using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Infrastructure.Caching;
using RealtimeMatches.Infrastructure.Channels;
using RealtimeMatches.Infrastructure.Messaging;
using RealtimeMatches.Infrastructure.Middleware;
using RealtimeMatches.Infrastructure.Monitoring;

public static IServiceCollection AddInfrastructure(this IServiceCollection services, IConfiguration configuration)
    {
        if (configuration.GetValue<bool>("UseInMemoryDatabase"))
        {
            services.AddDbContext<ApplicationDbContext>(options =>
                options.UseInMemoryDatabase("RealtimeMatchesDb"));
        }
        else
        {
            var migrationAssembly = typeof(ApplicationDbContext).GetTypeInfo().Assembly.GetName().Name;

            var connString = configuration.GetConnectionString("DefaultConnection");
            if (connString.Contains("mssqllocaldb"))
            {
                services.AddDbContext<ApplicationDbContext>(options =>
                options.UseSqlServer(
                    connString,
                    b => b.MigrationsAssembly(migrationAssembly)));
            }
            else
            {
                services.AddDbContext<ApplicationDbContext>(
                    o => o.UseMySql(connString, new MySqlServerVersion(new Version(8, 0)),
                        x => x.MigrationsAssembly(migrationAssembly)));
            }
        }

        if (configuration.GetValue<bool>("UseInMemoryCache"))
        {
            services.AddSingleton<ICacheService, InMemoryCacheService>();
        }
        else
        {
            services.AddRedis(configuration);
        }

        services.AddTransient<IApplicationContext>(provider => provider.GetService<ApplicationDbContext>());

        services.AddSingleton<CrawlerChannelQueue>();
        services.AddSingleton<ICrawlerPublishChannel, CrawlerPublishChannel>();
        services.AddSingleton<IRestApiPublishChannel, RestApiChannel>();
        services.AddSingleton<IXPathPublishChannel, XPathPublishChannel>();
        services.AddSingleton<HeartbeatService>();
        services.AddSingleton<IAlertService, TelegramBotService>();

        services.AddTransient<LoggingHttpRequestsHandler>();

        services.AddHttpClient<HttpClientService>()
            .AddHttpMessageHandler<LoggingHttpRequestsHandler>();

        if (configuration.GetValue<bool>("UseLocalBrowser", false))
        {
            services.AddSingleton<LocalWebBrowserService>();
        }

        services.AddScoped<BrowserInstancesService>();

        return services;
    }

