            var totalSize = 0;

            try
            {
                while (current_same_height < max_same_height)
                {
                    var isAtBottom = (bool)driver.ExecuteScript("return $(window).scrollTop() + $(window).height() == $(document).height()");
                    driver.ExecuteScript($"window.scrollBy(0, {_scrolSize})");

                    totalSize += _scrolSize;

                    if (isAtBottom)
                    {
                        current_same_height++;
                    }
                    else
