using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using OpenQA.Selenium;
using OpenQA.Selenium.Firefox;
using OpenQA.Selenium.Remote;
using System;
using System.Collections.Concurrent;
using System.Diagnostics;
using System.Threading;

public Task<string> RequestHtmlAsync(string url, string model, bool throwExceptions = false)
        {
            return Task.Run<string>(async () =>
            {
                var added = _queue.TryAdd(model, url);
                if (!added)
                {
                    _logger.LogInformation($"Model {model} is already in queue. Ignoring...");
                    return null;
                }

                string html = null;
                Interlocked.Increment(ref _queueCount);

                try
                {
                    var queueSw = Stopwatch.StartNew();

                    _logger.LogInformation($"{model} waiting to crawler {url}. {Interlocked.Read(ref _queueCount)} size");
                    await _semaphore.WaitAsync(5 * 60 * 1000);

                    queueSw.Stop();

                    _logger.LogInformation($"{model} crawling {url}. Queue Time: {queueSw.Elapsed.TotalSeconds}");

                    if (_driver?.SessionId == null)
                        StartSession();

                    var sw = Stopwatch.StartNew();

                    _navigation.GoToUrl(url);

                    ScrollToBottom(_driver);

                    html = _driver.PageSource;

                    if (Interlocked.Read(ref _queueCount) - 1 == 0)
                        FinishSession();

                    sw.Stop();
                    _logger.LogInformation($"{model} finished to crawler {url} in {sw.Elapsed.TotalSeconds} seconds");
                }
                catch (OpenQA.Selenium.WebDriverException ex)
                {
                    if (ex.Message == "Could not start a new session. Response code 500")
                    {
                        _logger.LogError(ex, $" {ex.Message} .buscar html de {url}");
                        await _browserInstancesService.Restart();
                    }
                    else
                    {
                        _logger.LogError(ex, $"Timeout ao buscar html de {url}");
                    }
                    _driver = null;


                    html = null;
                }
                catch (JsonReaderException ex)
                {
                    _logger.LogError(ex, $"Erro de json? ao buscar {url}");
                    html = null;
                }
                catch (Exception ex)
                {
                    _driver = null;
                    _logger.LogError(ex, $"Erro ao buscar html de {url}");

                    html = null;
                }
                finally
                {
                    _queue.TryRemove(model, out _);
                    Interlocked.Decrement(ref _queueCount);
                    _semaphore.Release();
                }

                return html;
            });
        }

