using MassTransit;

public static IServiceCollection AddBus(this IServiceCollection services, IConfiguration configuration, params Type[] consumersType)
    {
        var busConfig = configuration.GetSection("BusConfig").Get<BusConfig>();
        var scopePrefix = busConfig.Scope ?? throw new NullReferenceException("BusConfig.Scope cannot be null");

        services.AddMassTransit(x =>
        {
            consumersType?.ToList().ForEach(c => x.AddConsumer(c));

            if (busConfig.UseRabbitMq)
            {
                var rabbit = busConfig.RabbitMq ?? new Configs.RabbitMqConfig();

                x.UsingRabbitMq((context, cfg) =>
                {
                    cfg.Host(rabbit.Host, rabbit.VirtualHost, h =>
                    {
                        h.Username(rabbit.User);
                        h.Password(rabbit.Password);
                    });

                    cfg.ConfigureEndpoints(context, new DefaultEndpointNameFormatter($"{ENDPOINT}-{scopePrefix}-", false));
                });
            }
            else
            {
                x.UsingAmazonSqs((context, cfg) =>
                {
                    cfg.Host(busConfig.AmazonSqs.Region, h =>
                    {
                        h.AccessKey(busConfig.AmazonSqs.AccessKey);
                        h.SecretKey(busConfig.AmazonSqs.SecretKey);

                        h.Scope(scopePrefix);
                        h.EnableScopedTopics();
                    });

                    cfg.ConfigureEndpoints(context, new DefaultEndpointNameFormatter($"{ENDPOINT}-{scopePrefix}-", false));
                });
            }
        });

        return services;
    }

