[Test]
        public async Task ParallelTest()
        {
#pragma warning disable CS0618 // Type or member is obsolete
            var browser = GetService<WebBrowserService>();
#pragma warning restore CS0618 // Type or member is obsolete

            var partidaId = Guid.Parse("92172db1-488f-c419-ef4d-60ee9df57ab9");
            var providerId = typeof(GloboesporteWebProvider).Name.ToGuid();
            var globoesporteProvider = GetProvider(providerId) as GloboesporteWebProvider;

            var tasks = new List<Task<string>>();

            for (int i = 0; i < 3; i++)
            {
                var t = browser.RequestHtmlAsync("https://ge.globo.com/rs/futebol/brasileirao-serie-a/jogo/12-09-2021/gremio-ceara.ghtml?beta-test-refused=true", partidaId.ToString(), true);
                tasks.Add(Task.Run(() => t));
            }

            var r = await Task.WhenAll(tasks);

            Assert.IsTrue(r.Any(html => !string.IsNullOrEmpty(html)));

            var html = await browser.RequestHtmlAsync("https://ge.globo.com/rs/futebol/brasileirao-serie-a/jogo/12-09-2021/gremio-ceara.ghtml?beta-test-refused=true", partidaId.ToString(), true);
            Assert.IsNotNull(html);
        }

