[Test]
        public async Task BrowserInstanceStopStartTest()
        {
            var browserInstances = GetService<BrowserInstancesService>();
            var status = await browserInstances.GetStatus();
            Console.WriteLine(status);

            if (status == "running")
            {
                var stopped = await browserInstances.Stop();
                Assert.IsTrue(stopped);
            }

            while(status != "stopped")
            {
                status = await browserInstances.GetStatus();
                Assert.IsNotNull(status);

                Console.WriteLine(status);
                await Task.Delay(1000);
            }

            var started = await browserInstances.Start();
            Assert.IsTrue(started);

            while (status != "running")
            {
                status = await browserInstances.GetStatus();
                Assert.IsNotNull(status);

                Console.WriteLine(status);
                await Task.Delay(1000);
            }
        }

