using MediatR;
using Microsoft.EntityFrameworkCore;
using NUnit.Framework;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Partidas.Commands;
using RealtimeMatches.Application.Providers.Globoesporte;
using RealtimeMatches.Application.Providers.Sources.RapidApiFootball;
using RealtimeMatches.Domain.Entities;
using System;
using System.Linq;

[Test]
        public async Task CoberturaPartida_Tests()
        {
            var mediator = GetService<IMediator>();
            var context = GetService<IApplicationContext>();

            var date = new DateTime(2022, 02, 13, 18, 50, 00);

            const string RAPID_LINK = "rapidlink";

            var globoesporteProviderId = new GloboesporteWebProvider().Id;

            var rapidProviderId = new RapidApiFootballPartidasProvider().Id;

            var campeonato = new Campeonato("C", Guid.Empty);

            var status = PartidaStatus.AoVivo;
            var mandante = new Time("M", String.Empty);
            var visitante = new Time("V", String.Empty);

            var createRapidCommand = new CreateOrUpdatePartidaCommand.Contract(
                status,
                mandante,
                visitante,
                campeonato,
                date,
                rapidProviderId)
            {
                UrlTransmissao = RAPID_LINK
            };

            var createGeCommand = new CreateOrUpdatePartidaCommand.Contract(
                status,
                mandante,
                visitante,
                campeonato,
                date,
                globoesporteProviderId);

            var partidaRapid = await mediator.Send(createRapidCommand);
            var partidaGe = await mediator.Send(createGeCommand);

            Assert.AreEqual(partidaGe.Value.UniqueKey, partidaRapid.Value.UniqueKey);

            var partidaUniqueKey = partidaGe.Value.UniqueKey;

            var agenda = await context.Agendas.FirstOrDefaultAsync(a => a.PartidaUniqueKey == partidaUniqueKey);

            Assert.AreEqual(partidaGe.Value.Id, agenda.PartidaId);

            partidaRapid = await mediator.Send(createRapidCommand);
            partidaGe = await mediator.Send(createGeCommand);

            var coberturaGe = await context.Partidas.Include(x => x.Cobertura).AsNoTracking().Where(p => p.Id == partidaGe.Value.Id).Select(p => p.Cobertura).FirstOrDefaultAsync();

            Assert.AreEqual(RAPID_LINK, coberturaGe.Link);

            var channelRequests = await context.ChannelRequests.Where(c=>c.Status != ChannelRequestStatus.Finished).ToListAsync();

            Assert.AreEqual(1, channelRequests.Count);

            var request = channelRequests[0];

            Assert.AreEqual(partidaGe.Value.Id.ToString(), request.Model);
            Assert.AreEqual(rapidProviderId, request.ProviderId);

            var partidaAgendada = await context
                .Agendas
                .Include(x => x.Partida)
                .Where(x => x.PartidaUniqueKey == partidaUniqueKey)
                .Select(x => x.Partida)
                .FirstOrDefaultAsync();

            createGeCommand.UrlTransmissao = "gelink";

            partidaGe = await mediator.Send(createGeCommand);
            partidaRapid = await mediator.Send(createRapidCommand);

            channelRequests = await context.ChannelRequests.Where(x => x.Status != ChannelRequestStatus.Finished).ToListAsync();

            Assert.AreEqual(1, channelRequests.Count);

            request = channelRequests[0];

            Assert.AreEqual(partidaGe.Value.Id.ToString(), request.Model);
            Assert.AreEqual(globoesporteProviderId, request.ProviderId);
        }

