using RealtimeMatches.Application.Providers.Globoesporte;
using RealtimeMatches.Application.Providers.Sources.Globoesporte.Builders;

public async Task CrawlerChannelResponseHandlerTest(string html, int lancesMatch)
        {
            var mediator = GetService<IMediator>();
            var context = GetService<IApplicationContext>();
            var cache = GetService<IPartidaCacheService>();

            var geId = "GloboesporteWebProvider".ToGuid();

            var mandante = new Time("M", string.Empty);
            var visitante = new Time("V", string.Empty);
            var camp = new Campeonato("Fake", geId, true);
            var date = DateTime.UtcNow.AddDays(-1);

            var partida = new Partida(geId, date, camp, mandante, visitante, string.Empty, PartidaStatus.AoVivo, 0, 0);

            if (!context.Partidas.Any(x => x.Id == partida.Id))
            {
                context.Partidas.Add(partida);
                await context.SaveChangesAsync();
            }

            var channelRequest = new ChannelRequest(new GloboesporteWebProvider(), partida.Id.ToString(), ProviderMessageType.PartidaDetalhe, null);

            var message = new ChannelMessage(channelRequest);
            message.SetResponse(html);

            var notification = new CrawlerChannelResponseHandler.Contract(message);
            var res = await mediator.Send(notification);

            context.Partidas.Remove(partida);
            foreach (var atualizacao in partida.Atualizacoes)
            {
                context.PartidaAtualizacoes.Remove(atualizacao);
            }

            context.Times.Remove(mandante);
            context.Times.Remove(visitante);
            context.Campeonatos.Remove(camp);

            await context.SaveChangesAsync();

            var lanceCache = await cache.GetLancesPartida(partida.Id, date);
            Assert.AreEqual(lanceCache.Count(), lancesMatch);

            var partidaRequest = new GetPartidaByIdAndDate.Contract
            {
                PartidaId = partida.Id,
                PartidaData = date,
                FichaCompleta = true
            };

            var partidaResult = await mediator.Send(partidaRequest);

            Assert.IsTrue(partidaResult.IsSuccess);
            Assert.AreEqual(partidaResult.Value.Lances.Count(), lancesMatch);
        }

