using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Events;
using RealtimeMatches.IntegrationTests.Mocks;

public class SkyTests : TestBase
    {
        [Test]
        public async Task Transmissoes_Test()
        {
            var mediator = GetService<IMediator>();
            var context = GetService<IApplicationContext>();

            var partida = PartidaMock.Create(Guid.NewGuid(), "Banfield", "Santos", date: new DateTime(2022, 04, 05, 20, 30, 0));

            context.Partidas.Add(partida);
            await context.SaveChangesAsync();

            var json = await File.ReadAllTextAsync("Jsons/SkyProvider_05-04-2022_611.json", Encoding.GetEncoding("iso-8859-1"));

            var skyProvider = new SkyProvider();

            var request = new ChannelRequest(
                skyProvider,
                "SkyProvider_05-04-2022_611",
                ProviderMessageType.Transmissao,
                null);
            var message = new ChannelMessage(request);

            var eventsResult = skyProvider.HandleResponseAndGetEvents(json, new Dictionary<string, string>(), 200, message);

            Assert.IsTrue(eventsResult.IsSuccess);

            var events = eventsResult.Value;

            Assert.AreEqual(1, events.Count);

            var programacaoEvent = events[0] as ProgramacaoOperadoraObtidaEvent;

            Assert.AreEqual(new DateTime(2022, 04, 05).Date, programacaoEvent.ProgramacaoData.Date);

            var addTransmissoesCommand = new AddTransmissoesPartidasCommand.Contract
            {
                ProviderId = skyProvider.Id,
                Operadora = programacaoEvent.Operadora,
                Canais = programacaoEvent.Programacao,
                ProgramacaoData = programacaoEvent.ProgramacaoData
            };

            var result = await mediator.Send(addTransmissoesCommand);
        }
    }

