using System.IO;
using FluentAssertions;
using NUnit.Framework;
using RealtimeMatches.Application.Providers.Sources.Futnatv;

public class FutnatvSourceParserTests
    {
        [Test]
        public void Parse_Should_Parse_Third_Line_As_Expected()
        {
            // Arrange
            var fileName = Path.Combine(TestContext.CurrentContext.TestDirectory, "MockedFiles", "futnatv-18janeiro2026.html");

            string html = null;
            if (File.Exists(fileName))
                html = File.ReadAllText(fileName);
            else
                Assert.Fail($"futnatv-18janeiro2026-table.html not found at {fileName}");

            TestContext.WriteLine($"Read html length: {html.Length}");
            TestContext.WriteLine($"Contains '<table>'? {html.Contains("<table")}");

            var parser = new FutnatvSourceParser();

            // Act
            var matches = parser.Parse(html);

            TestContext.WriteLine($"Parser returned matches count: {matches.Count}");
            for (int i = 0; i < matches.Count; i++)
            {
                TestContext.WriteLine($"Match {i}: {matches[i].Horario} | {matches[i].Campeonato} | {matches[i].Mandante} | {matches[i].Visitante} | {string.Join(",", matches[i].Canais)}");
            }

            // Assert
            matches.Should().HaveCountGreaterOrEqualTo(3, "there should be at least 3 rows parsed");

            var third = matches[2]; // terceira linha (índice 2) deve ser 08h30
            third.Should().NotBeNull();
            // horario pode ser 8h30, 08h30, 8:30
            third.Horario.Should().Match(h => h != null && (h.Contains("8h30") || h.Contains("08h30") || h.Contains("8:30")));
            third.Campeonato.Should().NotBeNull();
            (third.Campeonato.Contains("Italiano") || third.Campeonato.Contains("Ital")).Should().BeTrue();
            third.Mandante.Should().Be("Parma");
            third.Visitante.Should().Be("Genoa");
            third.Canais.Should().Contain(c => c.Contains("Disney"));
        }
    }

