using MassTransit;
using Microsoft.Extensions.DependencyInjection;
using Moq;
using NUnit.Framework;
using Providers.Clients.Messaging;
using Providers.Clients.Messaging.Interfaces;
using Providers.Clients.Services.Base;
using Providers.Domain.Enums;
using Providers.Domain.Models.Resources;
using Providers.Shared.Requests.Messaging;

public class ResourceRequestConsumerTests
{
    private Mock<IServiceScopeFactory> _serviceScopeFactory;
    private Mock<IApmService> _apmService = new();

    [Test]
    public void Consume_GivenResourceAsyncRequestMessage_ShouldPublishResourceType()
    {
        var resourceId = "100";
        var mappingId = Guid.NewGuid();

        var resourceRequest = new ResourceAsyncRequestMessage(
            nameof(BaseProvider).Replace("Provider", string.Empty),
            mappingId,
            resourceId,
            ResourceType.Jogador);

        var provider = new Mock<BaseProvider>().As<IResourceRequestHandler<JogadorResource>>();
        provider
            .Setup(x => x.Handler(It.Is<ResourceRequest<JogadorResource>>(x => x.ResourceId == resourceId && x.MappingId == mappingId)))
            .ReturnsAsync(new JogadorResource());

        MockServiceScopeFactoryWithProvider(provider.Object);

        var consumer = new ResourceRequestConsumer(_serviceScopeFactory.Object, _apmService.Object);

        var context = new Mock<ConsumeContext<ResourceAsyncRequestMessage>>();
        context
            .Setup(x => x.Message)
            .Returns(resourceRequest);

        consumer.Consume(context.Object).Wait();

        context.Verify(x => x.Publish<IResourceReplied>(It.IsAny<ResourceReply>(), default), Times.Once);
    }

    private void MockServiceScopeFactoryWithProvider(object providerObj)
    {
        var provider = providerObj as BaseProvider;

        var serviceProvider = new Mock<IServiceProvider>();
