using System;

public class FootballApiProviderTests
{
    private readonly Mock<IFootballApiClient> _client;
    private readonly Fixture _fixture = new();

    public FootballApiProviderTests()
    {
        _client = new Mock<IFootballApiClient>();
    }

    [Test]
    public void HandlerJogadorResource_GivenResourceRequest_ShouldBeAsExpected()
    {
        var message = _fixture.Build<ResourceRequest<JogadorResource>>()
            .With(x => x.ResourceId, "100")
            .Create();

        var playerDto = _fixture.Build<FootballApiPlayerDTO>()
            .With(x => x.Height, "184 cm")
            .With(x => x.Weight, "87 kg")
            .Create();

        _client
            .Setup(x => x.GetPlayer(It.Is<long>(id => id == long.Parse(message.ResourceId)), It.Is<int>(season => season == DateTime.Now.Year)))
            .Returns(Task.FromResult(playerDto));

        var provider = new FootballApiProvider(_client.Object);

        var expectedResource = new JogadorResource
        {
            ResourceId = playerDto.Id.ToString(),
            ResourceLanguage = ResourceLanguage.EN,
            NomeCompleto = playerDto.Name,
            Apelido = playerDto.Firstname,
            FotoUri = playerDto.Photo.ToString(),
