// Namespace: RealtimeMatchrs.IntegrationTests.ChannelRequests
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Threading;
using System.Threading.Tasks;

public class CreateChannelRequestCommand
    {
        public class Contract : IRequest<Result>
        {
            public Guid ProviderId { get; set; }
            public string Model { get; set; }

            public ChannelRequestStatus Status { get; set; }
            public string Response { get; set; }

            public Contract(Guid providerId, string model)
            {
                ProviderId = providerId;
                Model = model;
            }
        }

        public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IApplicationContext _applicationContext;

            public Handler(IApplicationContext applicationContext)
            {
                _applicationContext = applicationContext;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var channelRequest = await _applicationContext
                    .ChannelRequests
                    .FirstOrDefaultAsync(x => x.ProviderId == request.ProviderId && x.Model == request.Model);

                channelRequest.Status = request.Status;

                if (!string.IsNullOrEmpty(request.Response))
                    channelRequest.Response = request.Response;

                await _applicationContext.SaveChangesAsync(cancellationToken);

                return Result.Success();
            }
        }
    }

