public async Task RapidApiUpdateTest()
    {
        var channelPublish = GetService<ChannelPublishMediator>();
        var context = GetService<IApplicationContext>();
        var providersFactory = GetService<ProvidersFactory>();
        var rapidApiProvider = providersFactory.GetPartidaProvider(new RapidApiFootballPartidasProvider().Id) as RapidApiFootballPartidasProvider;
        var httpClient = GetService<HttpClientService>();
        var providerEventsService = GetService<ProviderEventsHandler>();
        var mediator = GetService<IMediator>();

        var partida = await context
            .Partidas
            .FirstOrDefaultAsync(p => p.Id == Guid.Parse("5960d650-b0b3-0a9f-e6af-e1f6c648e08a"));

        var channelRequest = rapidApiProvider.GetPartidaDetalheRequest(partida, partida.Cobertura);

        var response = await httpClient.SendRequest(channelRequest);

        var eventsResult = rapidApiProvider.HandleResponseAndGetEvents(response.Item1, null, (int)response.Item2, new ChannelMessage(channelRequest));

        var lanceEvents = eventsResult.Value.FirstOrDefault(x => x is LancesAtualizadosProviderEvent) as LancesAtualizadosProviderEvent;

        var result = await providerEventsService.SendCommandEvents(new List<ProviderEvent> { lanceEvents }, default);

        var apiResponseCommand = new GetPartidaByIdAndDate.Contract
        {
            CacheOnly = true,
            FichaCompleta = true,
            PartidaData = partida.Data,
            PartidaId = partida.Id,
        };

        var partidaResult = await mediator.Send(apiResponseCommand);

        Assert.AreEqual(lanceEvents.Lances.Count + 1, partidaResult.Value.Lances?.Count());
    }

