using Amazon.Runtime.Internal.Util;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;

protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        await Task.Delay(1000 * 60 * 5);

        while (true)
        {
            try
            {
                var brDatetime = DateTime.UtcNow.AddHours(-3);

                var partidasNotUpdated = await _context
                    .Partidas
                    .Include(x => x.Mandante)
                    .Include(x => x.Visitante)
                    .Where(x => x.DeletedAt == null &&
                                x.Data >= brDatetime.Date &&
                                x.Data <= brDatetime.Date.AddDays(1) &&
                                x.UpdatedAt <= brDatetime.AddDays(-2))
                    .ToListAsync();

                foreach (var partida in partidasNotUpdated)
                {
                    partida.DeletedAt = brDatetime;

                    var agenda = await _context.Agendas.FirstOrDefaultAsync(x => x.PartidaId == partida.Id);
                    if (agenda != null)
                    {
                        _context.Agendas.Remove(agenda);
                    }

                    await _cacheService.DeletePartida(partida.Id, partida.Data);
                    await _cacheService.DelPartidaFromDate(partida.Id, partida.Data);

                    await _context.SaveChangesAsync(stoppingToken);
                    
                    await _alertService.SendAlert($"Removida Partida '{partida}' não atualizada nas últimas 48h.\nhttps://admin.realtimematches.tech.pedroccrl.com/Partidas/Edit?id={partida.Id}\nÚltima atualização: {partida.UpdatedAt}", true);
                }

                await Task.Delay(TimeSpan.FromDays(1), CancellationToken.None);
            }
            catch (Exception e)
            {
                _logger.LogError(e, "Erro rodar auditorias de partidas não atualizadas.");
                await Task.Delay(1000 * 60 * 5);
            }
        }
    }

