using Newtonsoft.Json;

public class CommandMessage
{
    private static readonly string _contractSufix = "+Contract";

    [JsonProperty]
    public DateTime PublishedAt { get; set; }

    [JsonProperty]
    public string CommandName { get; set; }

    [JsonProperty]
    public object CommandContract { get; set; }

    public static CommandMessage BuildCommandMessage(object contract)
    {
        var type = contract.GetType().FullName;
        if (!type.EndsWith(_contractSufix))
            throw new Exception("Cant build command from this type of contract.");

        var commandMessage = new CommandMessage
        {
            PublishedAt = DateTime.Now,
            CommandName = type.Replace(_contractSufix, string.Empty),
            CommandContract = contract
        };

        return commandMessage;
    }
}

