using System.Linq;
using System.Threading.Tasks;

public async Task<CrawlerItem> Dequeue()
        {
            var key = await _cacheService.ListLeftPopAsync<string>($"{Queuekey}:List");
            if (string.IsNullOrEmpty(key))
                return null;

            var item = await _cacheService.HashGetAsync<CrawlerItem>($"{Queuekey}:Set", key);
            if (item == null)
                return await Dequeue();

            await _cacheService.HashDelAsync($"{Queuekey}:Set", key);

            return item;
        }

