using System;
using System.Collections.Generic;
using System.Threading.Tasks;

public class CrawlerSubscriptionChannel
    {
        private readonly ILogger<CrawlerSubscriptionChannel> _logger;
        private readonly IServiceProvider _serviceProvider;
        private readonly CrawlerChannelQueue _crawlerChannelQueue;
        private readonly List<Task> _tasks;

        public CrawlerSubscriptionChannel(
            ILogger<CrawlerSubscriptionChannel> logger,
            IServiceProvider serviceProvider,
            CrawlerChannelQueue crawlerChannelQueue)
        {
            _logger = logger;
            _serviceProvider = serviceProvider;
            _crawlerChannelQueue = crawlerChannelQueue;

            _tasks = new List<Task>();
        }

        public async Task StartCrawlerListenner()
        {
            while (true)
            {
                var item = await _crawlerChannelQueue.DequeueProccessed();
                if (item == null)
                {
                    await Task.Delay(1000);
                    continue;
                }

                _logger.LogInformation($"Dequeued html {item.Model}");

                try
                {
                    var task = Task.Run(async () =>
                    {
                        using var scope = _serviceProvider.CreateScope();
                        var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

                        var result = await mediator.Send(new CrawlerChannelResponseHandler.Contract(item.ChannelMessage));
                        if (result.IsFailure)
                        {
                            _logger.LogError($"Erro ao manipular response de crawler. " + result.Error);
                        }
                    });

                    _tasks.Add(task);
                }
                catch (System.Exception e)
                {
                    _logger.LogError(e, $"Erro");
                    await Task.Delay(1000);
                }
            }
        }
    }

