using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Net.Http;
using System.Threading;
using System.Threading.Tasks;

public class LoggingHttpRequestsHandler : DelegatingHandler
{
    private readonly IApmService _apmService;

    public LoggingHttpRequestsHandler(IApmService apmService)
    {
        _apmService = apmService;
    }

    protected override async Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, CancellationToken cancellationToken)
    {
        var stopWatch = Stopwatch.StartNew();

        var response = await base.SendAsync(request, cancellationToken);

        stopWatch.Stop();

        RecordApmEvent(response, stopWatch.ElapsedMilliseconds);

        return response;
    }

    private void RecordApmEvent(HttpResponseMessage response, long elapsedMilliseconds)
    {
        var attributes = new Dictionary<string, object>
        {
            { "ExternalHost", response.RequestMessage.RequestUri.Host },
            { "ElapsedMilliseconds", (Single)elapsedMilliseconds },
            { "IsSuccessStatusCode", response.IsSuccessStatusCode },
            { "ReasonPhrase", response.ReasonPhrase },
            { "StatusCode", response.StatusCode },
            { "Method", response.RequestMessage.Method },
            { "RequestUri", response.RequestMessage.RequestUri },
            { "AbsolutePath", response.RequestMessage.RequestUri.AbsolutePath },
            { "PathAndQuery", response.RequestMessage.RequestUri.PathAndQuery }
        };

        _apmService.RecordCustomEvent("RequestToExternalService", attributes);
    }
}

