protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        ProviderMapConfig.BuilderProviders(modelBuilder);

        modelBuilder.Entity(CampeonatoMapConfig.ConfigureMap());
        modelBuilder.Entity(TimeMapConfig.ConfigureMap());
        modelBuilder.Entity(TimeMapConfig.ConfigurTimeProviderMap());
