        modelBuilder.Entity(ChannelRequestMapConfig.ConfigureMap());

        modelBuilder.Entity(AgendaMapConfig.ConfigureMap());
        modelBuilder.Entity(VideoMapConfig.ConfigureMap());

        modelBuilder.Entity(CoberturaMapConfig.ConfigureMap());

        modelBuilder.Entity(CrawlerMensagemMapConfig.ConfigureMap());

        modelBuilder.Entity<ProviderMapping>(entity =>
        {
            entity.HasIndex(x => x.EntityId);
            entity.HasIndex(x => x.Type);
