using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Design;
using Microsoft.Extensions.Configuration;
using System;
using System.IO;
using System.Reflection;

public class ApplicationDbContextFactory : IDesignTimeDbContextFactory<ApplicationDbContext>
{
    public ApplicationDbContext CreateDbContext(string[] args)
    {
        var configuration = new ConfigurationBuilder()
            .SetBasePath(Path.Combine(Directory.GetCurrentDirectory(), "..", "RealtimeMatches.Admin"))
            .AddJsonFile("appsettings.json", optional: false)
            .Build();

        var connString = configuration.GetConnectionString("DefaultConnection");
        var migrationAssembly = typeof(ApplicationDbContext).GetTypeInfo().Assembly.GetName().Name;

        var optionsBuilder = new DbContextOptionsBuilder<ApplicationDbContext>();
        optionsBuilder.UseMySql(connString, new MySqlServerVersion(new Version(8, 0)),
            x => x.MigrationsAssembly(migrationAssembly));

        return new ApplicationDbContext(optionsBuilder.Options, null, null);
    }
}

