using Microsoft.EntityFrameworkCore.Metadata.Builders;
using RealtimeMatches.Domain.Entities;
using System;

public class AgendaMapConfig
    {
        internal static Action<EntityTypeBuilder<Agenda>> ConfigureMap()
        {
            return entity =>
            {
                entity.HasKey(p => new { p.Dia, p.PartidaUniqueKey });

                entity.HasIndex(entity => entity.Dia);

                entity.Property(a => a.PartidaUniqueKey).IsRequired().HasMaxLength(255);
                entity.HasIndex(p => p.PartidaUniqueKey).IsUnique();

                entity
                    .HasOne(entity => entity.Partida)
                    .WithOne(x=>x.Agenda)
                    .HasForeignKey<Agenda>(x=> x.PartidaId)
                    .IsRequired(true);

                entity
                    .HasOne(a => a.Cobertura)
                    .WithOne(c => c.Agenda)
                    .HasForeignKey<Agenda>(a => a.CoberturaId);
            };
        }
    }

