                entity.HasKey(p => p.Id);

                entity.HasKey(p => p.Platform);

                entity.Property(x => x.EmergencyFixVersions)
                    .HasConversion(x => JsonConvert.SerializeObject(x, new JsonSerializerSettings { NullValueHandling = NullValueHandling.Ignore }),
