public class EstadioResourceResponseHandler : IResourceResponseHandler<EstadioResource>
{
    private readonly IApplicationContext _context;

    public EstadioResourceResponseHandler(IApplicationContext context)
    {
        _context = context;
    }

    public async Task Handle(ResourceReplyNotification<EstadioResource> notification, CancellationToken cancellationToken)
    {
        var mapping = await _context.ProviderMappings.FirstOrDefaultAsync(x => x.Id == notification.Message.MappingId);
        var resource = notification.Resource;

        var estadio = new Estadio
        {
            Nome = resource.Nome,
            Cidade = resource.Cidade,
            Capacidade = resource.Capacidade,
            Endereco = resource.Endereco,
            Imagem = resource.Imagem,
            Pais = resource.Pais
        };

        mapping.Update(estadio);
        mapping.IncludeMetadata(notification.Resource);

        await _context.SaveChangesAsync(cancellationToken);
    }
}

