// File: RealtimeMatches.Application.Integrations/EventHandlers/JogosFantasia/TimeFantasiaPontuacaoCollectionUpdatedEventHandler.cs
// Namespace: RealtimeMatches.Application.Integrations.EventHandlers.JogosFantasia
// Class: TimeFantasiaPontuacaoCollectionUpdatedEventHandler
using MediatR;
using Microsoft.EntityFrameworkCore;
using Providers.Shared.Events.JogosVirtuais;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Entities.Fantasia;

public async Task Handle(TimeFantasiaPontuacaoCollectionUpdated notification, CancellationToken cancellationToken)
    {
        var campeonato = await _mappingService.MapCampeonato(notification.Provider, notification.Campeonato.Nome, notification.Campeonato.ResourceId);

        var rodada = $"Rodada {notification.Rodada}";

        var times = new List<(Time, TimeFantasiaPontuacao)>();
        foreach (var timeFantasia in notification.Times)
        {
            var time = await _mappingService.MapTime(notification.Provider, timeFantasia.Time.Nome, timeFantasia.Time.Escudo, timeFantasia.Time.ResourceId);

            times.Add((time, timeFantasia));
        }

        var partidas = await _context.Partidas
            .Include(x => x.Campeonato)
            .Include(x => x.Mandante)
            .Include(x => x.Visitante)
            .Include(x => x.Fantasias)
            .Where(x => x.Campeonato.Id == campeonato.Id && x.Rodada == rodada)
            .AsNoTracking()
            .Select(x => new
            {
                x.Id,
                x.Data,
                x.Mandante,
                x.Visitante,
                x.Fantasias
            })
            .ToListAsync();

        foreach (var partida in partidas)
        {
            var ptsMandante = times.FirstOrDefault(x => x.Item1.Id == partida.Mandante.Id);
            var ptsVisitante = times.FirstOrDefault(x => x.Item1.Id == partida.Visitante.Id);

            if (ptsMandante.Item1 == null || ptsVisitante.Item1 == null)
            {
                continue;
            }

            var fantasia = default(PontuacaoPartidaFantasia);
            if (partida.Fantasias?.Count > 0)
            {
                fantasia = partida.Fantasias.FirstOrDefault(x => x.FantasyName == notification.Provider);
                if (fantasia != null)
                {
                    fantasia.PontosMandante = ptsMandante.Item2.Pontuacao;
                    fantasia.PontosVisitante = ptsVisitante.Item2.Pontuacao;

                    _context.PontuacaoPartidaFantasias.Update(fantasia);
                }
            }

            if (fantasia == null)
            {
                fantasia = new PontuacaoPartidaFantasia(notification.Provider, ptsMandante.Item2.Pontuacao, ptsVisitante.Item2.Pontuacao, partida.Id);
                _context.PontuacaoPartidaFantasias.Add(fantasia);
            }

            var atletasMandanteCache = ptsMandante.Item2.Atletas.OrderByDescending(x => x.Pontuacao).Select(atleta => new AtletaFantasiaPontuacaoCache
            {
                Nome = atleta.Nome,
                Foto = atleta.Foto,
                Pontuacao = atleta.Pontuacao,
                Posicao = atleta.Posicao,
            });

            var atletasVisitanteCache = ptsVisitante.Item2.Atletas.OrderByDescending(x => x.Pontuacao).Select(atleta => new AtletaFantasiaPontuacaoCache
            {
                Nome = atleta.Nome,
                Foto = atleta.Foto,
                Pontuacao = atleta.Pontuacao,
                Posicao = atleta.Posicao,
            });

            var pontuacaoCache = new PontuacaoFantasiaCache(fantasia, atletasMandanteCache, atletasVisitanteCache);
            await _partidaCacheService.SetPontuacaoFantasia(partida.Id, partida.Data, pontuacaoCache);
        }

        await _context.SaveChangesAsync();
    }

