public class VideoCollectionProducedEventHandler : INotificationHandler<VideoCollectionProduced>
{
    private readonly IMediator _mediator;

    public VideoCollectionProducedEventHandler(IMediator mediator)
    {
        _mediator = mediator;
    }

    public async Task Handle(VideoCollectionProduced notification, CancellationToken cancellationToken)
    {
        var videosContract = notification
                               .Videos
                               .Select(v => new UpdateVideoCollectionCommand.VideoContract(
                                   v.Titulo,
                                   v.VideoId,
                                   v.Thumbnail,
                                   v.Descricao,
                                   v.CanalId,
                                   v.CanalNome,
                                   v.Url,
                                   v.PublishedAt))
                               .ToList();

        var videoCommand = new UpdateVideoCollectionCommand.Contract
        {
            Provider = notification.Provider,
            Videos = videosContract
        };

        var result = await _mediator.Send(videoCommand, cancellationToken);
    }
}

