using RealtimeMatches.Api.Extensions;
using RealtimeMatches.Application.Campeonatos.Queries;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using System;
using System.Collections.Generic;
using System.Linq;

[Route("api/[controller]")]
[ApiController]
public class CampeonatosController : ControllerBase
{
    private readonly IMediator _mediator;
    private readonly CampeonatoCacheService _cacheService;

    public CampeonatosController(
        IMediator mediator,
        CampeonatoCacheService cacheService)
    {
        _mediator = mediator;
        _cacheService = cacheService;
    }

    [HttpGet]
    public Task<IActionResult> GetCampeonatos([FromQuery] ListarCampeonatos.Contract request) 
        => _mediator.HandleAndReturn(request);

    [HttpGet("{campeonatoId}")]
    public Task<IActionResult> GetCampeonato([FromRoute] GetCampeonatoCached.Contract request) 
        => _mediator.HandleAndReturn(request);

    [HttpPost("{campeonatoId}/tabela-fases")]
    public async Task<IActionResult> PostTabela(
        [FromRoute] Guid campeonatoId,
        [FromBody] AtualizarTabelaContract request)
    {
        var campeonato = await _cacheService.GetBaseCampeonato(campeonatoId);

        var fasesToAdd = new List<FaseCache>();
        foreach (var fase in request.Fases)
        {
            if (fase.Chaveamento == null || fase.Chaveamento.Count == 0)
            {
                break;
            }

            fasesToAdd.Add(fase);
        }

        campeonato.RodadaAtual = fasesToAdd.LastOrDefault()?.Nome;

        await _cacheService.SetBaseCampeonato(campeonato);

        var tabelaCache = new TabelaCache
        {
            Fases = fasesToAdd
        };

        await _cacheService.SetTabela(campeonatoId, tabelaCache);

        return Accepted();
    }
}

