        private readonly IApplicationContext _context;

        public PartidasController(IMediator mediator, IApplicationContext context)
        {
            _mediator = mediator;
            _context = context;
        }

        [HttpGet("{partidaId}")]
        public Task<IActionResult> GetPartida([FromRoute] GetPartidaByIdAndDate.Contract request)
            => _mediator.HandleAndReturn(request);

        [HttpGet("{partidaId}/{partidaData}")]
        public Task<IActionResult> GetPartidaData([FromRoute] GetPartidaByIdAndDate.Contract request)
            => _mediator.HandleAndReturn(request);

