        public Task<IActionResult> GetPartidaCache([FromQuery] GetPartidaPorTimesEData.Contract request)
            => _mediator.HandleAndReturn(request);

        [HttpPost("reagendar")]
        public async Task<IActionResult> ReagendarPartida([FromBody] List<Guid> partidasId)
        {
            var partidas = await _context
                .Partidas
                .IgnoreQueryFilters()
                .Where(x => partidasId.Contains(x.Id))
                .ToListAsync();

            foreach (var partida in partidas)
            {
                partida.DeletedAt = null;

                await _context.SaveChangesAsync();

                await _mediator.Send(new AgendarPartida.Contract(partida.Id, partida.UniqueKey));
            }

            return Accepted();
        }
    }

