using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.AspNetCore.Mvc;
using System.Threading.Tasks;

public static class MediatorRestResultExtension
    {
        public static async Task<IActionResult> HandleAndReturn<TResponse>(this IMediator mediator, IRequest<Result<TResponse>> contract)
        {
            var result = await mediator.Send(contract);

            if (result.IsFailure)
            {
                return new ObjectResult(new RestResultError(result.Error))
                {
                    StatusCode = 400
                };
            }
            else
            {
                return new ObjectResult(result.Value)
                {
                    StatusCode = 200
                };
            }
        }

        public static async Task<IActionResult> HandleAndReturn(this IMediator mediator, IRequest<Result> contract)
        {
            var result = await mediator.Send(contract);

            if (result.IsFailure)
            {
                return new ObjectResult(new RestResultError(result.Error))
                {
                    StatusCode = 400
                };
            }
            else
            {
                return new ObjectResult(new { })
                {
                    StatusCode = 200
                };
            }
        }
    }

