using System;
using System.Threading.Tasks;
using Amazon.SQS;
using Amazon.SQS.Model;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using RabbitMQ.Client;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Messaging;

// ------------------------------------------------------------------
    // SQS
    // ------------------------------------------------------------------

    private async Task<int> IngestFromSqsAsync()
    {
        var queueUrl = _config["CrawlerIngest:SqsQueueUrl"] ?? "";
        if (string.IsNullOrWhiteSpace(queueUrl))
        {
            _logger.LogWarning("CrawlerIngest:SqsQueueUrl is not configured.");
            return 0;
        }

        var sqsConfig = new AmazonSQSConfig
        {
            RegionEndpoint = Amazon.RegionEndpoint.GetBySystemName(_config["CrawlerIngest:AwsRegion"] ?? "us-east-1")
        };
        using var sqs = new AmazonSQSClient(
            _config["CrawlerIngest:AwsAccessKey"],
            _config["CrawlerIngest:AwsSecretKey"],
            sqsConfig);

        int saved = 0;

        // Pull up to 10 messages at a time (SQS max), non-blocking
        var response = await sqs.ReceiveMessageAsync(new ReceiveMessageRequest
        {
            QueueUrl = queueUrl,
            MaxNumberOfMessages = 10,
            WaitTimeSeconds = 0,
        });

        foreach (var msg in response.Messages)
        {
            var persisted = await PersistAsync(msg.Body);
            if (persisted)
            {
                saved++;
                await sqs.DeleteMessageAsync(queueUrl, msg.ReceiptHandle);
            }
        }

        return saved;
    }

