// Namespace: RealtimeMatches.Admin.Services
// Class: CrawlerMensagemIngestService
using System;
using System.Threading.Tasks;
using Amazon.SQS;
using Amazon.SQS.Model;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using RabbitMQ.Client;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Messaging;

// ------------------------------------------------------------------
    // RabbitMQ
    // ------------------------------------------------------------------

    private async Task<int> IngestFromRabbitMqAsync()
    {
        var host     = _config["CrawlerIngest:RabbitMq:Host"] ?? "localhost";
        var port     = _config.GetValue<int>("CrawlerIngest:RabbitMq:Port", 5672);
        var user     = _config["CrawlerIngest:RabbitMq:User"] ?? "guest";
        var password = _config["CrawlerIngest:RabbitMq:Password"] ?? "guest";
        var queue    = _config["CrawlerIngest:RabbitMq:Queue"] ?? "crawler-results";

        var factory = new ConnectionFactory { HostName = host, Port = port, UserName = user, Password = password };

        using var connection = factory.CreateConnection();
        using var channel = connection.CreateModel();
        channel.QueueDeclare(queue, durable: true, exclusive: false, autoDelete: false);

        int saved = 0;

        // Drain all available messages without blocking
        while (true)
        {
            var result = channel.BasicGet(queue, autoAck: false);
            if (result is null) break; // queue is empty

            var body = Encoding.UTF8.GetString(result.Body.ToArray());
            var persisted = await PersistAsync(body);

            if (persisted)
            {
                channel.BasicAck(result.DeliveryTag, multiple: false);
                saved++;
            }
            else
            {
                channel.BasicNack(result.DeliveryTag, multiple: false, requeue: false);
            }
        }

        return saved;
    }

// File: RealtimeMatches.Admin/Services/CrawlerMensagemIngestService.cs
// Namespace: RealtimeMatches.Admin.Services
// Class: CrawlerMensagemIngestService
using System;
using System.Threading.Tasks;
using Amazon.SQS;
using Amazon.SQS.Model;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using RabbitMQ.Client;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Messaging;

// ------------------------------------------------------------------
    // Shared persistence
    // ------------------------------------------------------------------

    private async Task<bool> PersistAsync(string body)
    {
        try
        {
            var msg = JsonSerializer.Deserialize<CrawlerResultMessage>(body,
                new JsonSerializerOptions { PropertyNameCaseInsensitive = true });

            if (msg is null || !DateOnly.TryParse(msg.Day, out var day))
            {
                _logger.LogWarning("CrawlerMensagemIngestService: invalid message body");
                return false;
            }

            var existingForDay = await _db.CrawlerMensagens
                .Where(x => x.Source == msg.Source && x.Day == day)
                .ToListAsync();

            if (existingForDay.Any(x => x.CrawledAt == msg.CrawledAt))
            {
                _logger.LogDebug("CrawlerMensagemIngestService: duplicate {Source}/{Day} — skipped", msg.Source, day);
                return true; // ack so it leaves the queue
            }

            var olderPending = existingForDay
                .Where(x => x.Status == CrawlerMensagemStatus.Pending && x.CrawledAt < msg.CrawledAt)
                .ToList();

            if (olderPending.Count > 0)
            {
                _db.CrawlerMensagens.RemoveRange(olderPending);
                _logger.LogInformation(
                    "CrawlerMensagemIngestService: hard-deleted {Count} older pending message(s) for {Source}/{Day}",
                    olderPending.Count, msg.Source, day);
            }

            _db.CrawlerMensagens.Add(new CrawlerMensagem
            {
                Id = Guid.NewGuid(),
                Source = msg.Source,
                Day = day,
                CrawledAt = msg.CrawledAt,
                Payload = body,
                Status = CrawlerMensagemStatus.Pending,
            });

            await _db.SaveChangesAsync();

            _logger.LogInformation("CrawlerMensagemIngestService: saved {Source}/{Day} ({Count} partidas)",
                msg.Source, day, msg.Matches.Count);

            return true;
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "CrawlerMensagemIngestService: error persisting message");
            return false;
        }
    }

