using Amazon;
using Amazon.S3;
using Amazon.S3.Transfer;
using Microsoft.Extensions.Configuration;
using System.IO;
using System.Threading.Tasks;

public class ImageUploadService
    {
        private readonly RegionEndpoint _bucketRegion;
        private readonly IConfiguration _configuration;
        private readonly string _bucketName;
        private IAmazonS3 _s3Client;

        public ImageUploadService(
            IConfiguration configuration)
        {
            _bucketRegion = RegionEndpoint.USEast1;
            _configuration = configuration;

            var awsSec = _configuration.GetSection("Aws");

            var accessKey = awsSec.GetValue<string>("AccessKey");
            var secretKey = awsSec.GetValue<string>("SecretKey");

            _bucketName = awsSec.GetValue<string>("BucketName");

            _s3Client = new AmazonS3Client(accessKey, secretKey, _bucketRegion);
        }

        public async Task<string> UploadFileAsync(Stream FileStream, string keyName)
        {
#if DEBUG
            keyName = $"debug/{keyName}";
#endif

            var fileTransferUtility = new TransferUtility(_s3Client);
            await fileTransferUtility.UploadAsync(FileStream, _bucketName, keyName);

            return $"https://{_bucketName}.s3.amazonaws.com/{keyName}";
        }
    }

