using System.Linq;
using System.Threading.Tasks;

private void CalculateDates(DateTime baseDate)
        {
            Dates = new List<DateTime>();
            var today = DateTime.UtcNow.AddHours(-3).Date;
            
            // Gera 7 dias: 3 antes, o dia base, e 3 depois
            for (int i = -3; i <= 3; i++)
            {
                Dates.Add(baseDate.Date.AddDays(i));
            }
            
            // Navegação para semanas anteriores/seguintes
            PreviousWeekDate = baseDate.Date.AddDays(-7);
            NextWeekDate = baseDate.Date.AddDays(7);
            
            // Verifica se hoje está no range visível
            IsNearToday = Dates.Any(d => d.Date == today);
        }

