public async Task OnGetAsync(DateTime? date)
        {
            var today = DateTime.UtcNow.AddHours(-3);
            date ??= today;

            Date = date;

            CalculateDates(date.Value);

            var result = await _mediator.Send(new BuscarPartidasPorDia.Contract 
            { 
                Date = Date.Value, 
                CacheOnly = true 
            });

            if (result.IsSuccess)
            {
                Partidas = result.Value.OrderBy(p => p.OrderKey).ToList();

                PartidasPorCampeonato = Partidas
                    .GroupBy(p => p.Campeonato.Nome)
                    .ToDictionary(g => g.Key, g => g.ToList());
            }
        }

