using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;

public async Task<IActionResult> OnPostAsync()
        {
            if (string.IsNullOrWhiteSpace(HtmlContent))
                return Page();

            try
            {
                Matches = _futnatvParser.Parse(HtmlContent);

                FutnatvMatchSearchResults = await _futnatvService.GetMatchesFromHtmlAsync(Matches);

                var canais = await _context.Canais.ToListAsync();
                Canais = canais;

                // build DTOs with candidate transmissões per partida
                foreach (var result in FutnatvMatchSearchResults)
                {
                    var partida = result.MatchedPartida;

                    var partidaTransmissoesDto = new FutnatvPartidaTransmissoesDto
                    {
                        Partida = partida,
                        Transmissoes = partida.Transmissoes.Select(x => new TransmissaoListingDto()
                        {
                            CanalId = x.CanalId,
                            CanalNome = x.Canal.Nome,
                            IsFromFutnatv = false,
                            IsSaved = true
                        }).ToList()
                    };

                    foreach (var parsedCanal in result.Parsed.Canais)
                    {
                        var canal = await _futnatvChannelMatcher.MatchAsync(parsedCanal);

                        if (canal != null)
                        {
                            var partidaTransmissao = partidaTransmissoesDto.Transmissoes.FirstOrDefault(t => t.CanalId == canal.Id);
                            if (partidaTransmissao != null)
                            {
                                partidaTransmissao.IsFromFutnatv = true;
                            }
                            else
                            {
                                partidaTransmissoesDto.Transmissoes.Add(new TransmissaoListingDto()
                                {
                                    CanalId = canal.Id,
                                    CanalNome = canal.Nome,
                                    IsFromFutnatv = true,
                                    IsSaved = false
                                });
                            }
                        }
                        else
                        {
                            partidaTransmissoesDto.Transmissoes.Add(new TransmissaoListingDto()
                            {
                                CanalNome = parsedCanal,
                                IsFromFutnatv = true,
                                IsSaved = false
                            });
                        }
                    }

                    PartidaTransmissoes.Add(partidaTransmissoesDto);
                }

                // Deduplica (pode haver partidas repetidas no retorno do parser/serviço)
                PartidaTransmissoes = PartidaTransmissoes
                    .Where(x => x.Partida != null)
                    .GroupBy(x => x.Partida.Id)
                    .Select(g =>
                    {
                        var first = g.First();

                        // consolida transmissões por CanalId quando existe, senão por nome
                        var merged = g
                            .SelectMany(x => x.Transmissoes ?? new List<TransmissaoListingDto>())
                            .GroupBy(t => t.CanalId != null
                                ? $"id:{t.CanalId.Value}" 
                                : $"name:{(t.CanalNome ?? string.Empty).Trim().ToLowerInvariant()}"
                            )
                            .Select(tg =>
                            {
                                var anySaved = tg.Any(x => x.IsSaved);
                                var anyFromFutnatv = tg.Any(x => x.IsFromFutnatv);

                                // preferir CanalId preenchido / nome preenchido
                                var baseItem = tg
                                    .OrderByDescending(x => x.CanalId != null)
                                    .ThenByDescending(x => !string.IsNullOrWhiteSpace(x.CanalNome))
                                    .First();

                                return new TransmissaoListingDto
                                {
                                    CanalId = baseItem.CanalId,
                                    CanalNome = baseItem.CanalNome,
                                    IsSaved = anySaved,
                                    IsFromFutnatv = anyFromFutnatv
                                };
                            })
                            .ToList();

                        first.Transmissoes = merged;
                        return first;
                    })
                    .ToList();

                // Ordena as partidas por data/hora (ascendente)
                PartidaTransmissoes = PartidaTransmissoes
                    .OrderBy(x => x.Partida.Data)
                    .ToList();

                // Disponibiliza lista de dias (Date) presentes nas partidas encontradas
                AvailableMatchDates = PartidaTransmissoes
                    .Where(x => x.Partida != null)
                    .Select(x => x.Partida.Data.Date)
                    .Distinct()
                    .OrderBy(x => x)
                    .ToList();

                // Default: seleciona o primeiro dia disponível (se não veio nada do post)
                if (SelectedMatchDate == null && AvailableMatchDates.Count > 0)
                {
                    SelectedMatchDate = AvailableMatchDates[0];
                }
            }
            catch (Exception ex)
            {
                ModelState.AddModelError(string.Empty, "Erro ao processar HTML: " + ex.Message);
            }

            return Page();
        }

