/// <summary>
        /// Confirma transmissões via JSON.
        /// Espera payload: { selectedDate: "yyyy-MM-dd", items: [{ partidaId: "guid", canais: ["guid", ...] }, ...] }
        /// </summary>
        public async Task<IActionResult> OnPostConfirmJsonAsync([FromBody] ConfirmTransmissoesRequest request)
        {
            try
            {
                if (request?.Items == null || request.Items.Count == 0)
                {
                    return new JsonResult(new ConfirmTransmissoesResponse(false, "Nenhuma partida encontrada no payload.", 0, 0));
                }

                if (request.SelectedDate == null)
                {
                    return new JsonResult(new ConfirmTransmissoesResponse(false, "Selecione um dia para confirmar.", 0, 0));
                }

                // Confirmamos apenas a data (Date) selecionada
                var selectedDate = request.SelectedDate.Value.Date;

                var selections = request.Items;

                var canais = await _context.Canais
                    .ToListAsync();

                var selectedPartidaIds = selections.Select(s => s.PartidaId).ToList();

                // Busca as partidas do payload, mas apenas do dia selecionado (otimiza e evita confirmar dia errado)
                var partidas = await _context.Partidas
                    .Where(x => selectedPartidaIds.Contains(x.Id) && x.Data.Date == selectedDate)
                    .AsNoTracking()
                    .ToListAsync();

                // Se vier partidaId de outro dia, ignoramos
                var validPartidaIds = partidas.Select(p => p.Id).ToHashSet();

                var transmissoesPartidas = await _context.Transmissoes
                    .Where(x => validPartidaIds.Contains(x.PartidaId))
                    .ToListAsync();

                _context.Transmissoes.RemoveRange(transmissoesPartidas);

                var updatePartidaCacheTasks = new List<Task>();

                foreach (var confirmPartidaTransmissoesSelection in selections)
                {
                    if (!validPartidaIds.Contains(confirmPartidaTransmissoesSelection.PartidaId))
                        continue;

                    var partida = partidas.First(p => p.Id == confirmPartidaTransmissoesSelection.PartidaId);

                    var transmissoesCache = new List<TransmissaoCache>();

                    foreach (var canalId in confirmPartidaTransmissoesSelection.Canais)
                    {
                        var canal = canais.First(c => c.Id == canalId);

                        var transmissaoPartidaToAdd = new Transmissao(canalId, partida.Id, ManualProvider.Id)
                        {
                            Canal = canal
                        };

                        _context.Transmissoes.Add(transmissaoPartidaToAdd);
                        transmissoesCache.Add(new TransmissaoCache(transmissaoPartidaToAdd));
                    }

                    var partidaId = partida.Id;
                    var partidaData = partida.Data;
                    var transmissoesCacheSnapshot = transmissoesCache.ToList();

                    updatePartidaCacheTasks.Add(Task.Run(() => UpdatePartidaCacheAsync(partidaId, partidaData, transmissoesCacheSnapshot)));
                }

                await _context.SaveChangesAsync();

                await Task.WhenAll(updatePartidaCacheTasks);

                return new JsonResult(new ConfirmTransmissoesResponse(true, "OK", selections.Sum(x => x.Canais.Count), transmissoesPartidas.Count));
            }
            catch (Exception ex)
            {
                Response.StatusCode = 500;
                return new JsonResult(new ConfirmTransmissoesResponse(false, ex.Message, 0, 0));
            }
        }

