private async Task UpdatePartidaCacheAsync(Guid partidaId, DateTime partidaData, IReadOnlyList<TransmissaoCache> transmissoesCache)
        {
            await _cacheSemaphore.WaitAsync();
            try
            {
                // references in `transmissoesCache` are kept alive by the task until this finishes
                await _partidaCacheService.SetTransmicoesPartida(partidaId, partidaData, transmissoesCache.ToList());
            }
            finally
            {
                _cacheSemaphore.Release();
            }
        }

