public async Task<IActionResult> OnGetAsync(Guid id)
    {
        var mensagem = await _db(id);
        if (mensagem is null) return NotFound();
        if (mensagem.Status != CrawlerMensagemStatus.Pending)
        {
            TempData["Status"] = $"Esta mensagem já foi {mensagem.Status.ToString().ToLower()}.";
            return RedirectToPage("./Index");
        }

        Mensagem = mensagem;
        SelectedMatchDate = mensagem.Day.ToDateTime(TimeOnly.MinValue);

        await BuildTransmissoesAsync(mensagem);
        Canais = await _context.Canais.ToListAsync();

        return Page();
    }

