using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;

public async Task<IActionResult> OnPostConfirmJsonAsync(Guid id, [FromBody] CampeonatoCanaisPage.ConfirmTransmissoesRequest request)
    {
        try
        {
            if (request?.Items == null || request.Items.Count == 0)
                return new JsonResult(new CampeonatoCanaisPage.ConfirmTransmissoesResponse(false, "Nenhuma partida encontrada no payload.", 0, 0));

            if (request.SelectedDate == null)
                return new JsonResult(new CampeonatoCanaisPage.ConfirmTransmissoesResponse(false, "Selecione um dia para confirmar.", 0, 0));

            var mensagem = await _db(id);
            if (mensagem is null)
                return new JsonResult(new CampeonatoCanaisPage.ConfirmTransmissoesResponse(false, "Mensagem não encontrada.", 0, 0));

            var selectedDate = request.SelectedDate.Value.Date;
            var selectedPartidaIds = request.Items.Select(s => s.PartidaId).ToList();

            var partidas = await _context.Partidas
                .Where(x => selectedPartidaIds.Contains(x.Id) && x.Data.Date == selectedDate)
                .AsNoTracking()
                .ToListAsync();

            var validPartidaIds = partidas.Select(p => p.Id).ToHashSet();

            var transmissoesExistentes = await _context.Transmissoes
                .Where(x => validPartidaIds.Contains(x.PartidaId))
                .ToListAsync();

            _context.Transmissoes.RemoveRange(transmissoesExistentes);

            var canais = await _context.Canais.ToListAsync();
            var updateCacheTasks = new List<Task>();

            foreach (var sel in request.Items)
            {
                if (!validPartidaIds.Contains(sel.PartidaId)) continue;

                var partida = partidas.First(p => p.Id == sel.PartidaId);
                var transmissoesCache = new List<TransmissaoCache>();

                foreach (var canalId in sel.Canais)
                {
                    var canal = canais.First(c => c.Id == canalId);
                    var transmissao = new Transmissao(canalId, partida.Id, ManualProvider.Id) { Canal = canal };
                    _context.Transmissoes.Add(transmissao);
                    transmissoesCache.Add(new TransmissaoCache(transmissao));
                }

                var pId = partida.Id;
                var pData = partida.Data;
                var cacheSnap = transmissoesCache.ToList();
                updateCacheTasks.Add(Task.Run(() => UpdateCacheAsync(pId, pData, cacheSnap)));
            }

            mensagem.Status = CrawlerMensagemStatus.Approved;
            mensagem.ProcessedAt = DateTime.UtcNow;

            await _context.SaveChangesAsync();
            await Task.WhenAll(updateCacheTasks);

            return new JsonResult(new CampeonatoCanaisPage.ConfirmTransmissoesResponse(true, "OK",
                request.Items.Sum(x => x.Canais.Count),
                transmissoesExistentes.Count));
        }
        catch (Exception ex)
        {
            Response.StatusCode = 500;
            return new JsonResult(new CampeonatoCanaisPage.ConfirmTransmissoesResponse(false, ex.Message, 0, 0));
        }
    }

