using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;

// ------------------------------------------------------------------

    private async Task BuildTransmissoesAsync(CrawlerMensagem mensagem)
    {
        var msg = JsonSerializer.Deserialize<CrawlerResultMessage>(mensagem.Payload,
            new JsonSerializerOptions { PropertyNameCaseInsensitive = true });

        if (msg is null) return;

        var dtoList = msg.Matches.Select(m => new FutnatvMatchDto
        {
            Data = mensagem.Day.ToString("dd/MM/yyyy"),
            Horario = m.Horario,
            Campeonato = m.Campeonato,
            Mandante = m.Mandante,
            Visitante = m.Visitante,
            Canais = m.Canais,
            DataDate = mensagem.Day.ToDateTime(TimeOnly.MinValue),
        }).ToList();

        var searchResults = await _futnatvService.GetMatchesFromHtmlAsync(dtoList);

        foreach (var result in searchResults)
        {
            var partida = result.MatchedPartida;
            var dto = new FutnatvPartidaTransmissoesDto
            {
                Partida = partida,
                Transmissoes = partida.Transmissoes.Select(x => new TransmissaoListingDto
                {
                    CanalId = x.CanalId,
                    CanalNome = x.Canal.Nome,
                    IsFromFutnatv = false,
                    IsSaved = true,
                }).ToList(),
            };

            foreach (var canalNome in result.Parsed.Canais)
            {
                var canal = await _futnatvChannelMatcher.MatchAsync(canalNome);
                if (canal is not null)
                {
                    var existing = dto.Transmissoes.FirstOrDefault(t => t.CanalId == canal.Id);
                    if (existing is not null)
                        existing.IsFromFutnatv = true;
                    else
                        dto.Transmissoes.Add(new TransmissaoListingDto
                        {
                            CanalId = canal.Id,
                            CanalNome = canal.Nome,
                            IsFromFutnatv = true,
                            IsSaved = false,
                        });
                }
                else
                {
                    dto.Transmissoes.Add(new TransmissaoListingDto
                    {
                        CanalNome = canalNome,
                        IsFromFutnatv = true,
                        IsSaved = false,
                    });
                }
            }

            PartidaTransmissoes.Add(dto);
        }

        PartidaTransmissoes = PartidaTransmissoes
            .Where(x => x.Partida is not null)
            .GroupBy(x => x.Partida.Id)
            .Select(g =>
            {
                var first = g.First();
                first.Transmissoes = g.SelectMany(x => x.Transmissoes ?? new())
                    .GroupBy(t => t.CanalId.HasValue ? $"id:{t.CanalId}" : $"name:{t.CanalNome?.ToLower()}")
                    .Select(tg =>
                    {
                        var best = tg.OrderByDescending(x => x.CanalId.HasValue).First();
                        return new TransmissaoListingDto
                        {
                            CanalId = best.CanalId,
                            CanalNome = best.CanalNome,
                            IsSaved = tg.Any(x => x.IsSaved),
                            IsFromFutnatv = tg.Any(x => x.IsFromFutnatv),
                        };
                    }).ToList();
                return first;
            })
            .OrderBy(x => x.Partida.Data)
            .ToList();
    }

