using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Admin.Services;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;

public async Task OnGetAsync()
    {
        // Pull pending messages from the queue and persist before rendering the list
        NovasMensagens = await _ingest.IngestPendingAsync();

        var mensagens = await _db.CrawlerMensagens
            .Where(x => x.DeletedAt == null)
            .OrderByDescending(x => x.Day)
            .ThenByDescending(x => x.CrawledAt)
            .ToListAsync();

        Mensagens = mensagens.Select(m =>
        {
            int count = 0;
            try
            {
                var doc = JsonDocument.Parse(m.Payload);
                if (doc.RootElement.TryGetProperty("matches", out var matches))
                    count = matches.GetArrayLength();
            }
            catch { }

            return new CrawlerMensagemListItem
            {
                Id = m.Id,
                Source = m.Source,
                Day = m.Day,
                CrawledAt = m.CrawledAt,
                MatchCount = count,
                Status = m.Status,
            };
        }).ToList();
    }

