using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Admin;

// To protect from overposting attacks, enable the specific properties you want to bind to.
        // For more details, see https://aka.ms/RazorPagesCRUD.
        public async Task<IActionResult> OnPostAsync()
        {
            if (!ModelState.IsValid)
            {
                return Page();
            }

            if (ImageUploader.ImageFile != null)
            {
                using var memoryStream = new MemoryStream();
                await ImageUploader.ImageFile.CopyToAsync(memoryStream);

                // Upload the file if less than 2 MB
                if (memoryStream.Length < 2097152)
                {
                    var imageId = Guid.NewGuid();
                    var extensao = ImageUploader.ImageFile.FileName.Split(".").Last();
                    var path = $"realtimematches/images/estadios/{imageId}.{extensao}";

                    ImageUrl = await _imageUploadService.UploadFileAsync(memoryStream, path);
                    Estadio.Imagem = ImageUrl;
                }
                else
                {
                    ModelState.AddModelError("File", "The file is too large.");
                }
            }

            _context.Attach(Estadio).State = EntityState.Modified;

            try
            {
                await _context.SaveChangesAsync();
            }
            catch (DbUpdateConcurrencyException)
            {
                if (!EstadioExists(Estadio.Id))
                {
                    return NotFound();
                }
                else
                {
                    throw;
                }
            }

            return RedirectToPage("./Index");
        }

