        var mapping = await _context.ProviderMappings.FirstOrDefaultAsync(m => m.Id == ProviderMapping.Id);

        mapping.Update(ProviderMapping.Info1, ProviderMapping.Info2, ProviderMapping.Info3, ProviderMapping.Info4);

        if (ProviderMapping.EntityId.HasValue)
        {
            mapping.SetEntity(ProviderMapping.EntityId.Value);
        }

        try
        {
            await _context.SaveChangesAsync();
        }
        catch (DbUpdateConcurrencyException)
        {
            if (!ProviderMappingExists(ProviderMapping.Id))
            {
                return NotFound();
            }
            else
            {
                throw;
            }
        }

        return RedirectToPage("./Index");
    }

