public async Task OnPostUploadImageAsync()
    {
        if (ImageUploader.ImageFile != null)
        {
            using var memoryStream = new MemoryStream();
            await ImageUploader.ImageFile.CopyToAsync(memoryStream);

            // Upload the file if less than 2 MB
            if (memoryStream.Length < 2097152)
            {
                var imageId = Guid.NewGuid();
                var extensao = ImageUploader.ImageFile.FileName.Split(".").Last();
                var path = $"realtimematches/images/mappings/{ProviderMapping.Type}/{imageId}.{extensao}";

                ImageUrl = await _imageUploadService.UploadFileAsync(memoryStream, path);
            }
            else
            {
                ModelState.AddModelError("File", "The file is too large.");
            }
        }

        await OnGetAsync(ProviderMapping.Id);
    }

