using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Domain.Entities;
using System.Collections.Generic;
using System.Threading.Tasks;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using System.Reflection.Emit;

public class IndexModel : PageModel
{
    private readonly RealtimeMatches.Admin.Context _context;

    public IList<ProviderMapping> ProviderMappings { get; set; }

    [BindProperty(SupportsGet = true)]
    public string MappingType { get; set; }

    [BindProperty(SupportsGet = true)]
    public string Query { get; set; }

    public SelectList MappingTypeList { get; set; }

    public IndexModel(RealtimeMatches.Admin.Context context)
    {
        _context = context;

        var list = new List<string>
        {
            string.Empty,
            ProviderMapping.TIME_TYPE,
            ProviderMapping.JOGADOR_TYPE,
            ProviderMapping.ESTADIO_TYPE,
            ProviderMapping.CAMPEONATO_TYPE,
            ProviderMapping.IGNORE_TYPE,
        };

        MappingTypeList = new SelectList(list);
    }

    public async Task OnGetAsync()
    {
        var query = _context.ProviderMappings.AsQueryable();

        if (string.IsNullOrEmpty(MappingType))
        {
            query = query.Take(100);
        }
        else
        {
            query = query.Where(x => x.Type == MappingType.ToUpper());
        }

        if (!string.IsNullOrEmpty(Query))
        {
            query = query.Where(x => 
                x.Info1.Contains(Query) || 
                x.Info2.Contains(Query) ||
                x.Info3.Contains(Query) ||
                x.Info4.Contains(Query));
        }

        ProviderMappings = await query.ToListAsync();
    }
}

