public class DeleteModel : PageModel
{
    private readonly IApplicationContext _context;
    private readonly IMediator _mediator;

    public DeleteModel(
        IApplicationContext context,
        IMediator mediator)
    {
        _context = context;
        _mediator = mediator;
    }

    [BindProperty]
    public Partida Partida { get; set; }

    public async Task<IActionResult> OnGetAsync(Guid? id)
    {
        if (id == null)
        {
            return NotFound();
        }

        Partida = await _context.Partidas.IgnoreQueryFilters().FirstOrDefaultAsync(m => m.Id == id);

        if (Partida == null)
        {
            return NotFound();
        }
        return Page();
    }

    public async Task<IActionResult> OnPostAsync(Guid? id)
    {
        if (id == null)
        {
            return NotFound();
        }

        Partida = await _context
            .Partidas
            .IgnoreQueryFilters()
            .FirstOrDefaultAsync(x => x.Id == id);

        if (Partida != null)
        {
            if (Partida.DeletedAt is null)
            {
                await _mediator.Send(new RemoverPartida.Contract(Partida.Id));
            }
            else
            {
                Partida.DeletedAt = null;
                await _context.SaveChangesAsync();
            }
        }

        return RedirectToPage("./Index");
    }
}

