public async Task<IActionResult> OnGetAsync(Guid? id, string status = null)
        {
            if (id == null)
            {
                return NotFound();
            }

            Status ??= status;

            var canais = await _context
                .Canais
                .ToListAsync();

            CanaisList = new SelectList(_context.Canais.OrderBy(x=>x.Nome), "Id", "Nome");
            
            // Lista completa de canais para exibição com ícones
            Canais = await _context.Canais.OrderBy(x => x.Nome).ToListAsync();

            Partida = await _context
                .Partidas.IgnoreQueryFilters()
                .Include(p => p.Mandante)
                .Include(p => p.Visitante)
                .Include(p => p.Campeonato)
                .Include(p => p.Transmissoes)
                .FirstOrDefaultAsync(m => m.Id == id);

            if (Partida == null)
                return NotFound();

            CanaisId = Partida.Transmissoes.Where(t => t.DeletedAt == null).Select(t => t.CanalId).ToArray();

            OndeAssistirBuscaUrl = $"https://www.google.com.br/search?q={Partida.Mandante.Nome} {Partida.Visitante.Nome} onde assistir";

            var provider = _providersFactory.Resolve(Partida.ProviderId);
            ProviderId = provider.Id;

            ChannelRequest = await _context.ChannelRequests.Include(c=>c.Cobertura).FirstOrDefaultAsync(x => x.ProviderId == Partida.ProviderId && x.Model == Partida.Id.ToString());
            if (ChannelRequest != null)
            {
                RequestModel = ChannelRequest.Model;
            }

            return Page();
