            //if (!ModelState.IsValid)
            //{
            //    return Page();
            //}

            var transmissoesNew = CanaisId.Select(canalId => new Transmissao(canalId, Partida.Id, ManualProvider.Id)).ToList();

            var transmissoesOld = await _context
                .Transmissoes
                .Where(t => t.PartidaId == Partida.Id)
                .IgnoreQueryFilters()
                .AsNoTracking()
                .ToListAsync();

            foreach (var tOld in transmissoesOld)
            {
                _context.Transmissoes.Remove(tOld);
            }

            foreach (var tNew in transmissoesNew)
            {
                _context.Transmissoes.Add(tNew);
            }

            if (Partida.DeletedAt.HasValue)
                Partida.DeletedAt = null;

            var partida = await _context
                .Partidas
                .IgnoreQueryFilters()
                .Include(p => p.Campeonato)
                .Include(p => p.Mandante)
                .Include(p => p.Visitante)
                .Where(p => p.Id == Partida.Id)
                .FirstOrDefaultAsync();

            partida.Status = Partida.Status;
            partida.Rodada = Partida.Rodada;
            partida.TransmissoesFixadas = true;
            partida.PlacarMandante = Partida.PlacarMandante < 0 ? null : Partida.PlacarMandante;
            partida.PlacarVisitante = Partida.PlacarVisitante < 0 ? null : Partida.PlacarVisitante;

            var status = string.Empty;
            if (partida.Data != Partida.Data)
            {
                partida.Data = Partida.Data;

                var agendarResult = await _mediator.Send(new AgendarPartida.Contract(partida.Id, partida.UniqueKey));

                status = agendarResult.IsSuccess ? $"Partida reagendada para {partida.Data:yyyy-MM-dd HH:mm}." : agendarResult.Error;
            }

            if (partida.StatusFixado != Partida.StatusFixado)
            {
                partida.StatusFixado = Partida.StatusFixado;
                await _partidaCacheService.FixarStatusPartida(partida.Id, partida.Data, Partida.StatusFixado);
            }

            try
            {
                await _context.SaveChangesAsync();
            }
            catch (DbUpdateConcurrencyException)
            {
                if (!PartidaExists(Partida.Id))
                {
                    return NotFound();
                }
                else
                {
                    throw;
                }
            }

            var transmissoesCache = new List<TransmissaoCache>();
            foreach (var tranmissao in transmissoesNew)
            {
                var canal = await _context.Canais.AsNoTracking().FirstOrDefaultAsync(x => x.Id == tranmissao.CanalId);
                tranmissao.Canal = canal;

                transmissoesCache.Add(new TransmissaoCache(tranmissao));
            }

            await _partidaCacheService.SetTransmicoesPartida(Partida.Id, Partida.Data, transmissoesCache);

            return RedirectToPage("/Partidas/Edit", new { id = Partida.Id, status });
        }

