        public async Task<IActionResult> OnGetAsync(string id)
        {
            if (id == null)
            {
                return NotFound();
            }

            ApplicationUser = await _context.ApplicationUsers.FirstOrDefaultAsync(m => m.Username == id);

            if (ApplicationUser.Username != User.Claims.FirstOrDefault(x => x.Type == ClaimTypes.NameIdentifier)?.Value)
            {
                return Forbid();
            }

            if (ApplicationUser == null)
            {
                return NotFound();
            }
            return Page();
