            {
                return NotFound();
            }

            ApplicationUser = await _context.ApplicationUsers.FindAsync(id);

            if (ApplicationUser != null)
            {
                _context.ApplicationUsers.Remove(ApplicationUser);
                await _context.SaveChangesAsync();
            }

            return RedirectToPage("./Index");
        }
    }

