        {
            if (id == null)
            {
                return NotFound();
            }

            Video = await _context.Videos.FindAsync(id);

            if (Video != null)
            {
                Video.DeletedAt = DateTime.UtcNow.AddHours(-3);
                await _context.SaveChangesAsync();

                await _videoCacheService.DeleteVideo(Video.Id, Video.PublishedAt);
            }

            return RedirectToPage("./Index");
        }
    }

