public async Task OnPostWordAsync()
        {
            await OnGetAsync();

            NotAllowedWords = await _videoCacheService.GetNotAllowedKeywords();
            NotAllowedWord = NotAllowedWord?.RemoveAccents().ToLower();

            if (!string.IsNullOrWhiteSpace(NotAllowedWord) && !NotAllowedWords.Contains(NotAllowedWord))
            {
                NotAllowedWords.Add(NotAllowedWord);

                await _videoCacheService.SetNotAllowedKeywords(NotAllowedWords);

                foreach (var video in Videos)
                {
                    if (video.Titulo.RemoveAccents().ToLower().Contains(NotAllowedWord, StringComparison.OrdinalIgnoreCase))
                    {
                        video.DeletedAt = DateTime.UtcNow.AddHours(-3);
                        await _context.SaveChangesAsync();

                        await _videoCacheService.DeleteVideo(Video.Id, Video.PublishedAt);
                    }
                }
            }

            await OnGetAsync();
        }

