        public TimeProvider Time { get; private set; }

        public async Task OnGetAsync(Guid? id)
        {
            id ??= Id;

            Time = await _context
                .TimesProvider
                .Include(t => t.Provider)
                .Where(x => x.Id == id)
                .FirstOrDefaultAsync();

            Id = Time.Id;

