using MediatR;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Application.Partidas.Queries;

public async Task OnGetAsync()
        {
            if (SelectedDay == null)
                return;

            var partidasResult = await _mediator.Send(new BuscarPartidasPorDia.Contract { Date = SelectedDay.Value });
            if (partidasResult.IsFailure)
            {
                Status = partidasResult.Error;
                return;
            }

            var partidas = partidasResult.Value.ToList();

            if (partidas.Count == 0)
            {
                Status = "Nenhuma partida encontrada para esse dia.";
                return;
            }

            foreach (var partida in partidas)
            {
                var mandante = await _jogosDbContext.Times.FirstOrDefaultAsync(x => x.Id == partida.Mandante.Id);
                var visitante = await _jogosDbContext.Times.FirstOrDefaultAsync(x => x.Id == partida.Visitante.Id);
                var partidaDb = await _jogosDbContext
                    .Partidas
                    .Include(x => x.Transmissoes)
                        .ThenInclude(x => x.Canal)
                    .Include(x => x.Campeonato)
                    .FirstOrDefaultAsync(x => x.Id == partida.Id);

                partida.Mandante.Escudo = mandante.Escudo;
                partida.Mandante.NomeAbreviado = mandante.Abreviacao;
                partida.Mandante.Importancia = mandante.Importancia;

                partida.Visitante.Escudo = visitante.Escudo;
                partida.Visitante.NomeAbreviado = visitante.Abreviacao;
                partida.Visitante.Importancia = visitante.Importancia;

                partida.Campeonato.Importancia = partidaDb.Campeonato.Importancia;

                partida.Transmissoes = partidaDb.Transmissoes.Select(t => new TransmissaoCache(t)).ToList();

                await _partidaCacheService.SetPartidaBase(partida);
                await _partidaCacheService.SetTransmicoesPartida(partida);
            }

            Status = $"{partidas.Count} partidas atualizadas!";
        }

