using CrystalQuartz.AspNetCore;
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using NCrontab;
using NewRelic.Api.Agent;
using Providers.Clients.Common.Abstractions;
using Providers.Domain.Events;
using Quartz;
using Quartz.Impl.Triggers;
using System.Reflection;

public static WebApplication UseProvidersJobs(this WebApplication app)
    {
        var timezone = TimeZoneInfo.FindSystemTimeZoneById("Bahia Standard Time");
        var eventsAssembly = Assembly.Load("Providers.Shared.Events");

        using (var scope = app.Services.CreateScope())
        {
            var serviceProvider = scope.ServiceProvider;
            var scheduler = serviceProvider.GetService<ISchedulerFactory>().GetScheduler().Result;

            app.UseCrystalQuartz(() => scheduler);

            var eventTypes = eventsAssembly.GetTypes().Where(p => p.IsClass && p.IsSubclassOf(typeof(ProviderEvent)));
            foreach (var item in eventTypes)
            {
                var eventType = typeof(IEventProducerTask<>).MakeGenericType(item);

                var types = Assembly.GetAssembly(typeof(IEventProducerTask<>)).GetTypes().Where(t => t.IsClass && t.GetInterfaces().Contains(eventType));

                foreach (var producerType in types)
                {
                    var producer = serviceProvider.GetService(producerType);

                    var crons = (string[])producerType.GetProperty(nameof(IEventProducerTask<ProviderEvent>.Cron)).GetValue(producer);

                    var identifier = $"{producerType.Name}_{item.Name}";

                    var job = JobBuilder.Create<EventProducerJob>().StoreDurably().WithIdentity(identifier).Build();

                    var jobExists = scheduler.CheckExists(job.Key).Result;
                    if (jobExists)
                    {
                        continue;
                    }

                    scheduler.AddJob(job, true).Wait();

                    for (int i = 0; i < crons.Length; i++)
                    {
                        var triggerId = identifier + "_" + i;
                        var cron = crons[i];
                        var triggerIdentifier = identifier + "_" + i;

                        var trigger = TriggerBuilder.Create()
                            .WithIdentity(triggerIdentifier)
                            .StartNow()
                            .WithCronSchedule(cron, x => x.InTimeZone(timezone))
                            .ForJob(job)
                            .Build();

                        var cronTrigger = trigger as CronTriggerImpl;

                        scheduler.ScheduleJob(trigger).Wait();

                        NewRelic.Api.Agent.NewRelic.RecordCustomEvent("JobTriggerScheduled", new Dictionary<string, object>
                        {
                            { "Identity", triggerIdentifier },
                            { "Cron", cron },
                            { "JobKey", job.Key },
                            { "EventType", item.Name },
                            { "ProducerType", producerType.Name }
                        });
                    }
                }
            }
        }

        return app;
    }

