using MassTransit;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using Providers.Clients.Common.Abstractions;
using Providers.Domain.Events;
using Quartz;
using RealtimeMatches.Infrastructure.Bus.Messaging;
using RealtimeMatches.Infrastructure.Monitoring.Abstractions;
using System.Reflection;

public async Task Execute(IJobExecutionContext context)
    {
        var jobName = context.JobDetail.Key.Name;
        var providerName = jobName.Split('_')[0];
        var eventName = jobName.Split('_')[1];

        var assembly = Assembly.GetAssembly(typeof(IEventProducerTask<>));
        var type = assembly.GetTypes().FirstOrDefault(x => x.Name == providerName);

        try
        {
            using var scope = _scopeFactory.CreateScope();
            var producer = scope.ServiceProvider.GetService(type);

            var method = type.GetMethod(nameof(IEventProducerTask<ProviderEvent>.ProduceEventAsync));
            var task = (Task)method.Invoke(producer, null);

            await task.ConfigureAwait(false);

            var resultProperty = task.GetType().GetProperty("Result");
            var @event = resultProperty.GetValue(task) as ProviderEvent;
            if (@event == null)
            {
                _apmService.RecordCustomEvent("EventUnproduced", new Dictionary<string, object>
                {
                    { "ProviderName", providerName },
                    { "EventName", eventName },
                    { "JobKey", jobName }
                });

                return;
            }

            var eventMessage = EventMessage.BuildEventMessage(@event);

            await _publish.Publish(eventMessage);

            _apmService.RecordCustomEvent("EventProduced", new Dictionary<string, object>
            {
                { "ProviderName", providerName },
                { "EventName", eventName },
                { "JobKey", jobName },
                { "ProducedEventType", @event.GetType().Name }
            });

            var eventMetadata = JsonConvert.SerializeObject(@event);
            var eventType = @event.GetType().Name;

            _logger.LogInformation("EventProduced Type {eventType}: {eventMetadata}", eventType, eventMetadata);
        }
        catch (Exception e)
        {
            _apmService.RecordCustomEvent("EventProducedError", new Dictionary<string, object>
            {
                { "ProviderName", providerName },
                { "EventName", eventName },
                { "JobKey", jobName },
                { "Error", e.Message },
                { "Stacktrace", e.StackTrace }
            });
        }
    }

