using Microsoft.AspNetCore.Mvc;
using Quartz;
using Quartz.Spi;

[Route("api/[controller]")]
[ApiController]
public class JobsController : ControllerBase
{
    private readonly IJobFactory _jobFactory;
    private readonly ISchedulerFactory _schedulerFactory;

    public JobsController(IJobFactory jobFactory, ISchedulerFactory schedulerFactory)
    {
        _jobFactory = jobFactory;
        _schedulerFactory = schedulerFactory;
    }

    [HttpGet("schedule")]
    public async Task<IActionResult> ScheduleJob()
    {
        var scheduler = await _schedulerFactory.GetScheduler();

        var job = JobBuilder.Create<ScopedJob>().WithIdentity("Controller").Build();

        var trigger = TriggerBuilder.Create()
                .WithIdentity("trigger-controller")
                .StartNow()
                .WithSimpleSchedule(x => x
                    .WithIntervalInSeconds(1)
                    .WithRepeatCount(50)).EndAt(DateTime.Now.AddMinutes(1))
                .Build();

        var x = await scheduler.ScheduleJob(job, trigger);

        return Ok();
    }

    [HttpGet("stop")]
    public async Task<IActionResult> Stop()
    {
        var scheduler = await _schedulerFactory.GetScheduler();
        var schedulers = await _schedulerFactory.GetAllSchedulers();

        var ok = await scheduler.Interrupt("trigger-controller");

        return Ok();
    }
}

