{
    private readonly RedisService _redis;
    private readonly IConfiguration _configuration;

    public RedisConfigRepository(RedisService redis, IConfiguration configuration)
    {
        _redis = redis;
        _configuration = configuration;
    }

    public string ConfigKey => $"Providers:{typeof(TConfig).Name.Replace("Config", string.Empty)}:Config";

    public async Task<TConfig> GetConfig()
    {
        var config = await _redis.GetObjectAsync<TConfig>(ConfigKey);
        if (config != null)
        {
            return config;
        }

        config = _configuration.GetSection($"ProvidersConfigs:{typeof(TConfig).Name}").Get<TConfig>();

        await SaveConfig(config);

        return config;
    }

