using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;
using Providers.Clients.Repositories;
using Providers.Clients.Services.FootballApi.DTOs;
using RealtimeMatches.Application.Common.Abstractions;

private async Task<T> GetResponse<T>(string path, TimeSpan cacheTtl)
    {
        var cacheKey = $"{nameof(FootballApiClient)}:{path}";

        if (_config == null)
        {
            _config = await _configRepository.GetConfig();
        }

        var cachedObj = await _cacheService.GetObjectAsync<T>(cacheKey);
        if (cachedObj != null)
        {
            return cachedObj;
        }

        var url = $"{_config.BaseUrl}/{path}";

        var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.TryAddWithoutValidation("x-rapidapi-key", _config.ApiKey);

        var response = await _client.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();

        var obj = JsonConvert.DeserializeObject<T>(json, _jsonSerializerSettings);

        await _cacheService.SetObjectAsync(cacheKey, obj, cacheTtl);

        return obj;
    }

