using Newtonsoft.Json;
using Providers.Clients.Repositories;
using Providers.Clients.Youtube;
using Providers.Clients.Youtube.DTOs;

public class YoutubeClient : IYoutubeClient
{
    private readonly HttpClient _client;
    private readonly IConfigRepository<YoutubeConfig> _configRepository;
    private YoutubeConfig _config;

    public YoutubeClient(HttpClient client, IConfigRepository<YoutubeConfig> configRepository)
    {
        _client = client;
        _configRepository = configRepository;
    }

    public async Task<YoutubeSearchResponse> GetYoutubeSearchByChannelId(string channelId, DateTime publishedAfter)
    {
        var query = $"channelId={channelId}&publishedAfter={publishedAfter:O}";

        var searchResponse = await GetYoutubeSearchByQuery(query);

        return searchResponse;
    }

    public async Task<YoutubeSearchResponse> GetYoutubeSearchByQuery(string query, DateTime publishedAfter)
    {
        var queryParams = $"q={query}&publishedAfter={publishedAfter:O}";

        var searchResponse = await GetYoutubeSearchByQuery(queryParams);

        return searchResponse;
    }

    private async Task<YoutubeSearchResponse> GetYoutubeSearchByQuery(string query)
    {
        if (_config == null)
        {
            _config = await _configRepository.GetConfig();
        }

        var url = $"{_config.BaseUrl}" +
                $"?key={_config.Key}" +
                $"&part=snippet,id" +
                $"&maxResults=50" +
                $"&regionCode=BR" +
                $"&order=date&" +
                query;

        var message = new HttpRequestMessage(HttpMethod.Get, url);
        message.Headers.TryAddWithoutValidation("cache-control", "no-cache, no-store, must-revalidate");
        message.Headers.TryAddWithoutValidation("pragma", "no-cache");

        var response = await _client.SendAsync(message);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadAsStringAsync();

        var searchResponse = JsonConvert.DeserializeObject<YoutubeSearchResponse>(body);

        return searchResponse;
    }
}

