public async Task<APIGatewayProxyResponse> FunctionHandler(APIGatewayProxyRequest input, ILambdaContext context)
        {
            using var scope = _services.CreateScope();
            var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

            Guid partidaId = Guid.Empty;
            DateTime? partidaData = null;

            if (input?.PathParameters != null && input.PathParameters.ContainsKey("partidaId"))
            {
                if (Guid.TryParse(input.PathParameters["partidaId"], out var partidaGuid))
                    partidaId = partidaGuid;

                if (input.PathParameters.ContainsKey("partidaData")
                    && DateTime.TryParse(input.PathParameters["partidaData"], out var date))
                    partidaData = date;
            }
            else
            {
                return APIGatewayResponseBuilder.Failure("partidaId required.");
            }

            var response = await mediator.HandleAndReturn(new GetPartidaByIdAndDate.Contract
            {
                PartidaId = partidaId,
                PartidaData = partidaData,
                FichaCompleta = true,
                CacheOnly = true
            });

            if (response.StatusCode == 400)
            {
                var configuration = scope.ServiceProvider.GetRequiredService<IConfiguration>();
                var apiUrl = configuration.GetValue("ApiUrl", "http://ip-172-31-7-242.ec2.internal/api");

                try
                {
                    var http = new HttpClient();
                    var httpResponse = await http.GetAsync($"{apiUrl}/partidas/{partidaId}");

                    var json = await httpResponse.Content.ReadAsStringAsync();

                    if (httpResponse.IsSuccessStatusCode)
                        return APIGatewayResponseBuilder.Generic(json, 200);

                    return APIGatewayResponseBuilder.Generic(json, 400);
                }
                catch (Exception e)
                {
                    return APIGatewayResponseBuilder.Failure("error " + e.Message);
                }
            }

            return response;
        }

