using MediatR;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Api.Settings;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Channels;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Application.Common.Services;

public static IServiceCollection AddProviders(this IServiceCollection services)
        {
            services.AddSingleton<ProvidersFactory>(serviceProvider =>
            {
                using var scope = serviceProvider.CreateScope();

                var channelPublish = scope.ServiceProvider.GetRequiredService<ChannelPublishMediator>();
                var scopeFactory = scope.ServiceProvider.GetRequiredService<IServiceScopeFactory>();
                var logger = scope.ServiceProvider.GetRequiredService<ILogger<ProvidersFactory>>();
                var context = scope.ServiceProvider.GetRequiredService<IApplicationContext>();
                var configuration = scope.ServiceProvider.GetRequiredService<IConfiguration>();

                var factory = new ProvidersFactory(logger, scopeFactory, channelPublish);

                GloboesporteWebProvider.CampeonatosFilter = configuration.GetSection("GloboesporteWebProvider:CampeonatosFilter").Get<string[]>();

                logger.LogInformation("GloboesporteWebProvider.CampeonatosFilter " + string.Join(';', GloboesporteWebProvider.CampeonatosFilter));

                var mustHaveProviders = new List<Provider>
                {
                    new CampeonatoCanalProvider(),
                    new ManualProvider(),
                    new GloboesporteWebProvider(),
                    new SkyProvider(),
                    new EspnClassificacaoProvider(),
                    new GloboplayProvider(),
                    new RapidApiFootballPartidasProvider(),
                    new GloboesporteTabelaProvider()
                };

                foreach (var provider in mustHaveProviders)
                {
                    var providerDb = context.Providers.FirstOrDefault(x => x.Id == provider.Id);
                    if (providerDb == null)
                    {
                        context.Providers.Add(provider);
                    }

                    switch (providerDb)
                    {
                        case PartidasProvider partidasProvider:
                            (provider as PartidasProvider).PartidasUpdateInterval = partidasProvider.PartidasUpdateInterval;
                            break;
                        default:
                            break;
                    }

                    factory.Register(provider);
                }

                var _ = context.SaveChangesAsync().Result;

                return factory;
            });


            return services;
        }

