        public Campeonato(string nome, Guid providerId, bool ativo = false)
        {
            Id = nome.ToGuid();

            Nome = nome;
            Ativo = ativo;
            Categoria = CampeonatoCategoria.Principal;

            ProviderId = providerId;

            var isSub = nome.ToLower().Contains("sub-");
