using Newtonsoft.Json;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities.Providers;
using RealtimeMatches.Domain.Enums;
using System;
using System.Collections.Generic;

public ChannelRequest(
            Provider provider,
            string model,
            ProviderMessageType messageType,
            ChannelData data,
            DateTime? requestUntilDate = null,
            TimeSpan? recurringMillisecondsInterval = null)
        {
            ConfigForDate = DateTime.UtcNow.AddHours(-3).Date;

            Type = provider switch
            {
                IRestApiProvider => ProviderType.RestApi,
                IHtmlCrawlerProvider or IHtmlProvider => ProviderType.Crawler,
                IHtmlXPathProvider => ProviderType.XPath,
                IFakeProvider => ProviderType.Fake,
                _ => ProviderType.Desconhecido
            };

            ProviderId = provider.Id;
            Model = model;

            MessageType = messageType;
            Status = ChannelRequestStatus.Created;

            RecurringInterval = recurringMillisecondsInterval;
            RequestUntilDate = requestUntilDate;

            Data = data;
        }

