// Class: ChannelRequest
using Newtonsoft.Json;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities.Providers;
using RealtimeMatches.Domain.Enums;
using System;
using System.Collections.Generic;

public bool CanRun(int timeoutMinutes = 3)
        {
            var now = DateTime.UtcNow.AddHours(-3);

            if (!RecurringInterval.HasValue)
            {
                // Onetime run
                if (LastSuccessRun.HasValue)
                    return false;
                else
                {
                    Status = ChannelRequestStatus.Finished;
                    return true;
                }
            }
            else if (RequestUntilDate.HasValue && now > RequestUntilDate.Value)
            {
                Status = ChannelRequestStatus.Finished;
                return false;
            }
            else if (Status == ChannelRequestStatus.Created)
            {
                return true;
            }
            else if (Status == ChannelRequestStatus.Failed && BeginRun.HasValue && (now - BeginRun.Value).TotalMinutes < 5)
            {
                return false;
            }
            

            var lastrun = this.LastSuccessRun ?? DateTime.MinValue;

            var currentInterval = now - lastrun;

            var runningTime = now - this.BeginRun;
            var timeout = this.Status == ChannelRequestStatus.Running &&
                          runningTime.HasValue &&
                          runningTime.Value.TotalMinutes > timeoutMinutes;

            if (timeout ||
                (currentInterval > this.RecurringInterval.Value && this.Status != ChannelRequestStatus.Running))
            {
                if (MessageType == ProviderMessageType.PartidaDetalhe &&
                        (
                            Cobertura.Agenda == null || 
                            !Cobertura.Agenda.Exibir || 
                            Cobertura.Agenda.Partida?.Status == PartidaStatus.Encerrada
                        )
                   )
                {
                    return false;
                }

                return true;
            }

            return false;
        }

