// Class: Lance
using CSharpFunctionalExtensions;
using Newtonsoft.Json;
using System;

public static Result<Lance> CriarLance(
            Guid partidaId,
            Time time,
            LanceIndicador indicador,
            string minuto,
            string titulo,
            string descricao,
            string periodo,
            JogadorLance jogador1 = null,
            JogadorLance jogador2 = null)
        {
            var lance = new Lance
            {
                Id = Guid.NewGuid(),
                PartidaId = partidaId,
                Tipo = new TipoLance(indicador),
                Minuto = minuto,
                Periodo = periodo,
                Substituicao = new SubstituicaoLance()
            };

            switch (indicador)
            {
                case LanceIndicador.Gol:
                case LanceIndicador.CartaoAmarelo:
                case LanceIndicador.CartaoVermelho:
                case LanceIndicador.GolAnulado:
                case LanceIndicador.GolContra:
                case LanceIndicador.PenaltiPerdido:
                case LanceIndicador.VarPenalti:
                    if (jogador1 == null)
                        return Result.Failure<Lance>("Jogador1 deve ser especificado.");

                    lance.Jogador = jogador1;

                    lance.Jogador.Time = time.Nome;
                    lance.Jogador.Escudo = time.Escudo;

                    break;
                case LanceIndicador.Substituicao:
                    if (jogador1 == null ||
                        jogador2 == null)
                        return Result.Failure<Lance>("Jogadores devem ser especificados.");

                    jogador1.Time = jogador2.Time = time.Nome;
                    jogador1.Escudo = jogador2.Escudo = time.Escudo;

                    lance.Substituicao = new SubstituicaoLance
                    {
                        JogadorEntra = jogador2,
                        JogadorSai = jogador1
                    };

                    break;
            }

            lance.Titulo = indicador switch
            {
                LanceIndicador.InicioDeJogo => "Início de jogo",
                LanceIndicador.FimDeJogo => "Fim de jogo!",
                LanceIndicador.Gol => "GOOOL!!",
                LanceIndicador.Substituicao => $"Substituição no {time.Nome}",
                LanceIndicador.CartaoAmarelo => "Cartão amarelo!",
                LanceIndicador.CartaoVermelho => "EXPULSO!",
                LanceIndicador.GolContra => "GOL CONTRA!",
                LanceIndicador.PenaltiPerdido => "Pênalti perdido!",
                _ => titulo
            };

            var jogador1Pos = string.Empty;
            if (jogador1?.PosicaoAbv is not null)
                jogador1Pos = $" ({jogador1.PosicaoAbv})";

            var jogador2Pos = string.Empty;
            if (jogador2?.PosicaoAbv is not null)
                jogador2Pos = $" ({jogador2.PosicaoAbv})";

            lance.Descricao = indicador switch
            {
                LanceIndicador.Gol => $"{jogador1.Nome}{jogador1Pos} marca para o {time.Nome}!",
                LanceIndicador.Substituicao => $"Entra {jogador2.Nome}{jogador2Pos}, Sai {jogador1.Nome}{jogador1Pos}",
                LanceIndicador.CartaoAmarelo => $"{jogador1.Nome}{jogador1Pos} recebe cartão amarelo.",
                LanceIndicador.CartaoVermelho => $"{jogador1.Nome}{jogador1Pos} está expulso!",
                LanceIndicador.GolContra => $"{jogador1.Nome}{jogador1Pos} marca contra!",
                _ => descricao
            };

            return Result.Success(lance);
        }

