public Partida AtualizarPlacar(int? mandante, int? visitante, int? penaltiMandante, int? penaltiVisitante, string destaqueMandante = null, string destaqueVisitante = null)
    {
        if (Status != PartidaStatus.NaoComecou)
        {
            if (mandante > PlacarMandante)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Placar, $"GOOL do {Mandante.Nome}!!!")
                {
                    Descricao = $"{Mandante.Nome} [{mandante}] x {visitante} {Visitante.Nome}"
                });
            }

            if (visitante > PlacarVisitante)
            {
                Events.Add(new PartidaEvent(this, PartidaEventType.Placar, $"GOOL do {Visitante.Nome}!!!")
                {
                    Descricao = $"{Mandante.Nome} {mandante} x [{visitante}] {Visitante.Nome}"
                });
            }
        }

        if (mandante.HasValue)
            PlacarMandante = mandante;

        if (visitante.HasValue)
            PlacarVisitante = visitante;

        DestaqueMandante = destaqueMandante;
        DestaqueVisitante = destaqueVisitante;

        PenaltiMandante = penaltiMandante;
        PenaltiVisitante = penaltiVisitante;

        return this;
    }

