public record Estatisticas
{
    public int? Chutes { get; set; }
    public int? ChutesGol { get; set; }
    public int? ChutesPraFora
    {
        get
        {
            if (!Chutes.HasValue || !ChutesGol.HasValue)
            {
                return null;
            }

            return Chutes - ChutesGol;
        }
    }
    public int? Faltas { get; set; }
    public int? Escanteios { get; set; }
    public int? Impedimentos { get; set; }
    /// <summary>
    /// Porcentagem de 0 a 100%.
    /// </summary>
    public string Posse => PossePorcentagem.HasValue ? PossePorcentagem.Value + "%" : null;
    public int? PossePorcentagem { get; set; }
    public int? CartoesAmarelos { get; set; }
    public int? CartoesVermelhos { get; set; }
    public int? Defesas { get; set; }
    public int? Passes { get; set; }
    public int? PassesCertos { get; set; }
    public int? PassesErrados
    {
        get
        {
            if (!Passes.HasValue || !PassesCertos.HasValue)
            {
                return null;
            }

            return Passes - PassesCertos;
        }
    }

    public string PrecisaoPasses
    {
        get
        {
            if (!Passes.HasValue || !PassesCertos.HasValue)
            {
                return null;
            }

            var razaoPasses = ((decimal)PassesCertos.Value) / Passes.Value;
            var porcentagem = razaoPasses.ToString("0.##").Replace("0,", string.Empty).Replace("0.", string.Empty) + "%";

            return porcentagem;
        }
    }

    public int? PrecisaoPassesPorcetagem => string.IsNullOrEmpty(PrecisaoPasses) ? null : int.Parse(PrecisaoPasses.Replace("%", string.Empty));
}

