// File: Domain/RealtimeMatches.Commands/Channels/ChannelPublishMediator.cs
// Namespace: RealtimeMatches.Application.Channels
// Class: ChannelPublishMediator
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Requests.Commands;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Threading.Tasks;

public async Task<Result> Publish(ChannelRequest channelRequest)
        {
            var invalidDataError = $"Invalid message type {channelRequest.Type} for provider {channelRequest.ProviderId}.";
            var error = false;

            if (channelRequest.Data == null)
            {
                _logger.LogError(invalidDataError + ". DATA IS NULL");
                return Result.Failure(invalidDataError + ". DATA IS NULL");
            }

            using var scope = _scopeFactory.CreateScope();

            var crawlerPublish = scope.ServiceProvider.GetRequiredService<ICrawlerPublishChannel>();
            var restApiPublish = scope.ServiceProvider.GetRequiredService<IRestApiPublishChannel>();
            var xPathPublish = scope.ServiceProvider.GetRequiredService<IXPathPublishChannel>();
            var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

            var result = await mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
            {
                Status = ChannelRequestStatus.Running
            });

            switch (channelRequest.Type)
            {
                case ProviderType.RestApi:
                    if (channelRequest.Data.Type != ProviderType.RestApi)
                    {
                        error = true;
                        break;
                    }

                    await restApiPublish.PublishRequest(channelRequest);

                    _logger.LogInformation($"Enqueued RestApiChannelData {channelRequest.Model} {channelRequest.Data.Url}");

                    break;

                case ProviderType.Crawler:
                    if (channelRequest.Data.Type != ProviderType.Crawler)
                    {
                        error = true;
                        break;
                    }

                    await crawlerPublish.PublishRequest(channelRequest);

                    _logger.LogInformation($"Enqueued CrawlerChannelData {channelRequest.Model} {channelRequest.Data.Url}");

                    break;

                case ProviderType.Fake:
                    _logger.LogInformation($"Handling FakeChannel {channelRequest.Model}");
                    using (var fakeScope = _scopeFactory.CreateScope())
                    {
                        var mediatorFakeScope = fakeScope.ServiceProvider.GetRequiredService<IMediator>();

                        var fakeChannelRequest = new FakeChannelHandler.Contract(channelRequest);

                        var channelResult = await mediatorFakeScope.Send(fakeChannelRequest);
                    }
                    break;

                case ProviderType.XPath:
                    if (channelRequest.Data.Type != ProviderType.XPath)
                    {
                        error = true;
                        break;
                    }

                    await xPathPublish.PublishRequest(channelRequest);

                    _logger.LogInformation($"Enqueued XPathChannelData {channelRequest.Model} {channelRequest.Data.Url}");

                    break;
                default:
                    throw new NotImplementedException();
            }

            if (error)
            {
                _logger.LogError(invalidDataError);
                return Result.Failure(invalidDataError);
            }

            return Result.Success();
        }

