// Class: CrawlerChannelResponseHandler.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Requests.Commands;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Application.Providers;
using RealtimeMatches.Domain.Entities;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                _logger.LogInformation($"Handling CrawlerHtmlNotification Type {request.Type} for Provider {request.ProviderId}");

                var channelRequest = request.ChannelMessage.Request;
                try
                {

                    Result<List<ProviderEvent>> providerEventsResult;
                    if (_providerProxy.Resolve(request.ProviderId) is IHtmlXPathProvider htmlXPathProvider)
                    {
                        providerEventsResult = htmlXPathProvider.HandleHtmlAndGetEvents(request.Model, request.Html, request.Type);
                    }
                    else if (_providerProxy.Resolve(request.ProviderId) is IHtmlProvider htmlProvider)
                    {
                        providerEventsResult = htmlProvider.GetHtmlEvents(request.Type, request.Model, request.ChannelMessage.Request.HtmlProviderData);
                    }
                    else
                    {
                        _logger.LogError("Erro ao processar ProviderCommandEvents, {providerId}, {model}, {messageType}. Error: {error}", request.ProviderId, request.Model, request.Type, "ProviderType desconhecido.");

                        return Result.Failure("Erro ao processar ProviderCommandEvents: ProviderType desconhecido.");
                    }

                    if (providerEventsResult.IsFailure)
                    {
                        // ToDo: Voltar a retornar response pra HTML
                        await _mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
                        {
                            Status = ChannelRequestStatus.Failed,
                            Response = null,
                            Error = providerEventsResult.Error
                        });

                        _logger.LogError(providerEventsResult.Error);
                        return Result.Failure(providerEventsResult.Error);
                    }

                    try
                    {
                        using var scope = _scopeFactory.CreateScope();
                        var providerEventService = scope.ServiceProvider.GetService<ProviderEventsHandler>();

                        var providerEvents = providerEventsResult.Value;
                        await providerEventService.SendCommandEvents(providerEvents, cancellationToken);
                    }
                    catch (Exception e)
                    {
                        _logger.LogError(e, "Erro ao processar ProviderCommandEvents, {providerId}, {model}, {messageType}. Error: {error}", request.ProviderId, request.Model, request.Type, e.Message);

                        return Result.Failure("Erro ao processar ProviderCommandEvents: " + e.Message);
                    }

                    var result = await _mediator.Send(new UpdateChannelRequestCommand.Contract(channelRequest)
                    {
                        Status = ChannelRequestStatus.Success,
                        Response = null
                    });
                }
                catch (Exception e)
                {
                    var msg = $"Erro ao manipular {request.Type} response html do provider: {request.ProviderId}. Html is null? {request.Html is null}. {e.Message}";

                    _logger.LogError(e, msg);

                    if (request.Html is not null)
                        await _cacheService.SetObjectAsync($"ErroHtml:{request.Model}", request.Html, TimeSpan.FromDays(1));

                    return Result.Failure(msg);
                }



                return Result.Success();
            }

