using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
        {
            var filteredVideos = new List<VideoContract>();

            var notAllowedKeywords = await _videoCacheService.GetNotAllowedKeywords();

            foreach (var video in request.Videos)
            {
                if (!_allowedChannels.Contains(video.CanalId))
                {
                    continue;
                }

                var notAllowed = false;
                foreach (var notAllowedWord in notAllowedKeywords)
                {
                    if (video.Titulo.RemoveAccents().ToLower().Contains(notAllowedWord, StringComparison.OrdinalIgnoreCase))
                    {
                        _logger.LogInformation("UpdateVideoCollectionCommandHandler: Video nao permitido. {titulo} {videoId} {url}", video.Titulo, video.VideoId, video.Url);

                        notAllowed = true;
                    }
                }

                if (notAllowed)
                    continue;

                _logger.LogInformation("UpdateVideoCollectionCommandHandler: Video permitido. {titulo} {videoId} {url}", video.Titulo, video.VideoId, video.Url);

                filteredVideos.Add(video);
            }

            var videos = new List<Video>();

            foreach (var video in filteredVideos)
            {
                var exists = await _applicationContext
                    .Videos
                    .IgnoreQueryFilters()
                    .AnyAsync(x => x.VideoId == video.VideoId, cancellationToken: cancellationToken);

                if (exists)
                    continue;

                var videoDb = new Video(
                    video.Titulo,
                    video.VideoId,
                    video.Thumbnail,
                    video.Descricao,
                    video.CanalId,
                    video.CanalNome,
                    video.Url,
                    video.PublishedAt);

                videos.Add(videoDb);
            }

            _applicationContext.Videos.AddRange(videos);
            await _applicationContext.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }

