using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Providers.Sources.RapidApiFootball;
using RealtimeMatches.Domain.Entities;
using System;
using System.Threading;
using System.Threading.Tasks;

public async Task<Result<Time>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var timeProvider = await _applicationContext
                    .TimesProvider
                    .Include(t => t.Time)
                    .FirstOrDefaultAsync(t => t.ProviderId == request.ProviderId && t.IdProvider == request.TimeProviderDTO.IdProvider);

                // ToDo: Criar providers preferenciais 
                var preferencialProviderId = new RapidApiFootballPartidasProvider().Id;

                if (timeProvider == null)
                {
                    timeProvider = new TimeProvider(request.ProviderId, request.TimeProviderDTO.Nome, request.TimeProviderDTO.IdProvider, request.Pais);

                    var timeRequest = new Time(request.TimeProviderDTO.Nome, request.TimeProviderDTO.Escudo);
                    var time = await _applicationContext
                        .Times
                        .FirstOrDefaultAsync(t => t.Id == timeRequest.Id, cancellationToken: cancellationToken);

                    if (time != null)
                    {
                        timeProvider.TimeId = time.Id;
                        time.Pais ??= timeProvider.Pais;
                    }
                    else if (request.ProviderId == preferencialProviderId && !request.TimeProviderDTO.Nome.Contains("U20"))
                    {
                        time = timeRequest;

                        _applicationContext.Times.Add(time);
                        timeProvider.TimeId = time.Id;
                    }

                    _applicationContext.TimesProvider.Add(timeProvider);
                    await _applicationContext.SaveChangesAsync(cancellationToken);

                    if (time == null)
                    {
                        return Result.Failure<Time>($"Time {timeProvider.Nome} nao encontrado/associado.");
                    }

                    return Result.Success(time);
                }
                else
                {
                    if (timeProvider.Time == null)
                    {
                        if (request.ProviderId == preferencialProviderId)
                        {
                            var time = new Time(request.TimeProviderDTO.Nome, request.TimeProviderDTO.Escudo);

                            if (!await _applicationContext.Times.AnyAsync(x => x.Id == time.Id))
                            {
                                _applicationContext.Times.Add(time);
                            }
                            
                            timeProvider.TimeId = time.Id;

                            await _applicationContext.SaveChangesAsync(cancellationToken);

                            _logger.LogInformation("Criando time {time} pelo provider preferencial.", time.Nome);

                            return Result.Success(time);
                        }
                        else
                        {
                            return Result.Failure<Time>($"TimeProvider {timeProvider.Nome} nao associado.");
                        }
                    }
                    else
                    {
                        return Result.Success(timeProvider.Time);
                    }
                }
            }

