using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Domain.Entities;
using System;
using System.Threading;

public async Task<Result<ChannelRequest>> Handle(Contract contract, CancellationToken cancellationToken)
            {
                var scope = _scopeFactory.CreateScope();
                var context = scope.ServiceProvider.GetRequiredService<IApplicationContext>();
                var mediator = scope.ServiceProvider.GetRequiredService<IMediator>();

                var providerId = contract.Request.ProviderId;
                var model = contract.Request.Model;
                var request = contract.Request;

                try
                {
                    var dbRequest = await context
                    .ChannelRequests
                    .AsNoTracking()
                    .FirstOrDefaultAsync(x => x.ProviderId == providerId && x.Model == model, cancellationToken);

                    if (dbRequest == null)
                    {
                        context.ChannelRequests.Add(request);

                        await context.SaveChangesAsync(cancellationToken);
                        return Result.Success(request);
                    }

                    var update = false;

                    // ToDo: Trocar para reference date
                    if (DateTime.UtcNow.AddHours(-3).Date > dbRequest.ConfigForDate.Date)
                    {
                        dbRequest.RecurringInterval = request.RecurringInterval;
                        dbRequest.RequestUntilDate = request.RequestUntilDate;
                        dbRequest.ConfigForDate = request.ConfigForDate.Date;

                        update = true;
                    }

                    if (dbRequest.Status != request.Status)
                    {
                        dbRequest.Status = request.Status;

                        if (dbRequest.Status == ChannelRequestStatus.Finished)
                            dbRequest.RequestUntilDate = DateTime.UtcNow.AddHours(-3);

                        update = true;
                    }

                    if (update)
                    {
                        context.ChannelRequests.Update(dbRequest);
                        await context.SaveChangesAsync(cancellationToken);
                    }

                    return Result.Success(dbRequest);
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro ao atualizar ChannelRequest {model} {providerId}", request.Model, request.ProviderId);

                    return Result.Failure<ChannelRequest>("Erro ao atualizar ChannelRequest");
                }
            }

