public class RemoveAllRequestsModel
    {
        public class Contract : ILockedRequest<int>
        {
            public string Model { get; set; }

            public string LockKey => $"{Model}";

            public int TimeoutSeconds => 120;
        }

        public class Handler : IRequestHandler<Contract, int>
        {
            private readonly IApplicationContext _context;

            public Handler(IApplicationContext context)
            {
                _context = context;
            }

            public async Task<int> Handle(Contract request, CancellationToken cancellationToken)
            {
                var requests = await _context.ChannelRequests.Where(x => x.Model == request.Model).ToListAsync(cancellationToken);
                foreach (var req in requests)
                {
                    req.Status = ChannelRequestStatus.Finished;
                    req.RequestUntilDate = DateTime.UtcNow;
                    req.Error = "Removed.";
                }

                await _context.SaveChangesAsync(cancellationToken);

                return requests.Count;
            }
        }
    }

