                };

                foreach (var classDto in classificacao)
                {
                    var classTimeEvent = new ClassificacaoObtidaProviderEvent.ClassificacaoTimeEvent(
                        classDto.Posicao,
                        classDto.Time,
                        classDto.Jogos,
                        classDto.Vitorias,
                        classDto.Derrotas,
                        classDto.Empates,
                        classDto.Pontos,
                        classDto.GolsPro,
                        classDto.GolsContra);

                    classEvent.Classificacao.Add(classTimeEvent);
                }

                return Result.Success(new List<ProviderEvent> { classEvent });
            }

            throw new NotImplementedException();
        }

