using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;

public async Task<Canal> MatchAsync(string parsedChannelName)
        {
            if (string.IsNullOrWhiteSpace(parsedChannelName))
                return null;

            // Carrega canais do banco (cache em memória por requisição)
            if (_canaisCache == null)
            {
                _canaisCache = await _context.Canais.ToListAsync();
            }

            var normalized = parsedChannelName.Trim();

            // 1. Tenta match exato (case-insensitive)
            var exactMatch = _canaisCache.FirstOrDefault(c =>
                string.Equals(c.Nome.Trim(), normalized, StringComparison.OrdinalIgnoreCase));

            if (exactMatch != null)
                return exactMatch;

            // 2. Tenta usar os mapeamentos de-para
            foreach (var mapping in Mappings)
            {
                if (mapping.Matches(normalized))
                {
                    var canal = _canaisCache.FirstOrDefault(c =>
                        string.Equals(c.Nome.Trim(), mapping.TargetChannelName, StringComparison.OrdinalIgnoreCase));

                    if (canal != null)
                        return canal;
                }
            }

            // 3. Tenta match parcial (contains) com os canais do banco
            var containsMatch = _canaisCache.FirstOrDefault(c =>
                normalized.ToLowerInvariant().Contains(c.Nome.Trim().ToLowerInvariant()) ||
                c.Nome.Trim().ToLowerInvariant().Contains(normalized.ToLowerInvariant()));

            return containsMatch;
        }

