using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;

private class ChannelMapping
        {
            public string TargetChannelName { get; }
            private readonly List<Regex> _regexPatterns;
            private readonly List<string> _containsPatterns;

            public ChannelMapping(string targetChannelName, params string[] patterns)
            {
                TargetChannelName = targetChannelName;
                _regexPatterns = new List<Regex>();
                _containsPatterns = new List<string>();

                foreach (var pattern in patterns)
                {
                    // Se começa com ^ ou contém caracteres de regex, trata como regex
                    if (pattern.StartsWith("^") || pattern.StartsWith(@"\b") || 
                        pattern.Contains(@"\s") || pattern.Contains("(") && pattern.Contains(")") && pattern.Contains(@"\"))
                    {
                        try
                        {
                            _regexPatterns.Add(new Regex(pattern, RegexOptions.IgnoreCase | RegexOptions.Compiled));
                        }
                        catch
                        {
                            // Se falhar ao compilar regex, trata como contains
                            _containsPatterns.Add(pattern.ToLowerInvariant());
                        }
                    }
                    else
                    {
                        _containsPatterns.Add(pattern.ToLowerInvariant());
                    }
                }
            }

            public bool Matches(string input)
            {
                var lowerInput = input.ToLowerInvariant();

                // Tenta regex primeiro
                foreach (var regex in _regexPatterns)
                {
                    if (regex.IsMatch(input))
                        return true;
                }

                // Depois tenta contains
                foreach (var pattern in _containsPatterns)
                {
                    if (lowerInput.Contains(pattern))
                        return true;
                }

                return false;
            }
        }

