using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using HtmlAgilityPack;

public List<FutnatvMatchDto> Parse(string html)
        {
            var results = new List<FutnatvMatchDto>();
            if (string.IsNullOrWhiteSpace(html))
                return results;

            var doc = new HtmlDocument();
            doc.LoadHtml(html);

            var table = doc.DocumentNode.SelectSingleNode("//table");
            if (table == null)
                return results;

            // find day title
            string dayTitle = null;
            

            var rows = table.SelectNodes(".//tr");
            if (rows == null) return results;

            // Detect an optional leading numeric index column present in many rows (e.g., '1', '2', '3')
            int offset = 0;
            try
            {
                var headerPatternSample = new Regex(@"\b(hora|horário|horario|campeonato|competicao|competição|mandante|visitante|canal|teams)\b", RegexOptions.IgnoreCase);
                var dataRows = rows.Where(r =>
                {
                    var tcs = r.SelectNodes("./th|./td");
                    if (tcs == null || tcs.Count == 0) return false;
                    var headerMatches = tcs.Count(c => headerPatternSample.IsMatch((c.InnerText ?? string.Empty).Trim()));
                    return headerMatches < Math.Max(1, tcs.Count / 2);
                }).Take(20).ToList();

                if (dataRows.Count > 0)
                {
                    int numericFirstCount = 0;
                    int sample = Math.Min(10, dataRows.Count);
                    for (int i = 0; i < sample; i++)
                    {
                        var cells = dataRows[i].SelectNodes("./th|./td");
                        if (cells != null && cells.Count > 0)
                        {
                            var first = (cells[0].InnerText ?? string.Empty).Trim();
                            // considera como numérico se encontrar um grupo de dígitos
                            var m = System.Text.RegularExpressions.Regex.Match(first, "(\\d+)");
                            if (m.Success && m.Groups[1].Value.Length <= 4) numericFirstCount++;
                        }
                    }

                    if (numericFirstCount >= (sample + 1) / 2)
                    {
                        offset = 1;
                    }
                }
            }
            catch
            {
                offset = 0;
            }
            
            var brCulture = new System.Globalization.CultureInfo("pt-BR");
            var currentMonthBr = brCulture.DateTimeFormat.GetMonthName(DateTime.Now.Month).ToUpperInvariant();
            var currentYearStr = DateTime.Now.Year.ToString();

            foreach (var tr in rows)
            {
                var cells = tr.SelectNodes("./th|./td");
                if (cells == null || cells.Count == 0) continue;

                if (tr.InnerText.EndsWith($"{currentMonthBr} DE {currentYearStr}"))
                {
                    var inner = tr.InnerText.Trim();
                    
                    dayTitle = inner.Split(",")[1].Trim();
                }

                // Nova detecção robusta de cabeçalho: conta quantas células correspondem às palavras-chave de header
                var headerPattern = new Regex(@"\b(hora|horário|horario|campeonato|competicao|competição|mandante|visitante|canal|teams)\b", RegexOptions.IgnoreCase);
                var headerMatches = cells.Count(c => headerPattern.IsMatch((c.InnerText ?? string.Empty).Trim()));
                // se pelo menos metade das células parecem header, considera como linha de cabeçalho e pula
                if (headerMatches >= Math.Max(1, cells.Count / 2))
                    continue;

                // Mapeamento com offset detectado
                string horario = GetCell(cells, 0 + offset);
                string campeonato = GetCell(cells, 1 + offset);
                string mandante = GetCell(cells, 2 + offset);
                string visitante = GetCell(cells, 4 + offset);
                string canalRaw = GetCell(cells, cells.Count - 1);

                // Se os índices iniciais estiverem fora do range (por ex. tabela com menos colunas), tenta heurísticas
                if (horario == null && cells.Count >= 2)
                    horario = GetCell(cells, 0);
                if (mandante == null && cells.Count >= 3)
                    mandante = GetCell(cells, Math.Min(2, cells.Count - 1));
                if (visitante == null && cells.Count >= 4)
                    visitante = GetCell(cells, Math.Min(4, cells.Count - 1));

                horario = NormalizeHorario(horario);
                campeonato = SafeTrim(campeonato);
                mandante = SafeTrim(mandante);
                visitante = SafeTrim(visitante);
                canalRaw = SafeTrim(canalRaw);

                var canais = ParseCanais(canalRaw);

                if (!string.IsNullOrWhiteSpace(mandante) || !string.IsNullOrWhiteSpace(visitante))
                {
                    results.Add(new FutnatvMatchDto
                    {
                        Data = dayTitle,
                        Horario = horario,
                        Campeonato = campeonato,
                        Mandante = mandante,
                        Visitante = visitante,
                        Canais = canais,
                        DataDate = TryParseDayAndTime(dayTitle, horario)
                    });
                }
            }

            return results;
        }

