private static string NormalizeHorario(string raw)
        {
            if (string.IsNullOrWhiteSpace(raw)) return null;
            var m = Regex.Match(raw, "(\\d{1,2}h\\d{2})");
            if (m.Success) return m.Groups[1].Value;
            m = Regex.Match(raw, "(\\d{1,2}:\\d{2})");
            if (m.Success) return m.Groups[1].Value;
            return raw.Trim();
        }

