using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using HtmlAgilityPack;

private static List<string> ParseCanais(string raw)
        {
            var list = new List<string>();
            if (string.IsNullOrWhiteSpace(raw)) return list;
            var paren = new System.Collections.Generic.Dictionary<string, string>();
            var temp = Regex.Replace(raw, "\\(([^)]*)\\)", match =>
            {
                var key = System.Guid.NewGuid().ToString();
                paren[key] = match.Value;
                return key;
            });
            temp = Regex.Replace(temp, "\\s+e\\s+", ", ", RegexOptions.IgnoreCase);
            var parts = temp.Split(new[] { ',' }, StringSplitOptions.RemoveEmptyEntries).Select(p => p.Trim()).Where(p => p.Length > 0).ToList();
            for (int i = 0; i < parts.Count; i++)
            {
                foreach (var kv in paren)
                {
                    if (parts[i].Contains(kv.Key)) parts[i] = parts[i].Replace(kv.Key, kv.Value);
                }
            }
            foreach (var p in parts)
            {
                var cleaned = Regex.Replace(p, "\\s+", " ").Trim();
                if (!string.IsNullOrWhiteSpace(cleaned) && !list.Contains(cleaned)) list.Add(cleaned);
            }
            return list;
        }

