using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using HtmlAgilityPack;

private static DateTime? TryParseDayAndTime(string dayTitle, string horario)
        {
            if (string.IsNullOrWhiteSpace(dayTitle)) return null;

            // normalize and remove weekday if present
            var parts = dayTitle.Split(',');
            var candidate = parts.Length > 1 ? parts[1].Trim() : parts[0].Trim();
            candidate = Regex.Replace(candidate, "\\s+DE\\s+", " ", RegexOptions.IgnoreCase).Trim();

            var ci = new System.Globalization.CultureInfo("pt-BR");
            DateTime day;
            var patterns = new[] { "d MMMM yyyy", "d MMM yyyy", "d/MM/yyyy", "yyyy-MM-dd" };
            foreach (var p in patterns)
            {
                if (DateTime.TryParseExact(candidate, p, ci, System.Globalization.DateTimeStyles.None, out day))
                {
                    var ts = ParseHorarioToTimeSpan(horario);
                    if (ts.HasValue) return day.Date.Add(ts.Value);
                    return day.Date;
                }
            }

            if (DateTime.TryParse(candidate, ci, System.Globalization.DateTimeStyles.AssumeLocal, out day))
            {
                var ts = ParseHorarioToTimeSpan(horario);
