private static TimeSpan? ParseHorarioToTimeSpan(string horario)
        {
            if (string.IsNullOrWhiteSpace(horario)) return null;
            var h = horario.Trim().Replace("h", ":").Replace("H", ":");
            if (TimeSpan.TryParse(h, out var ts)) return ts;
            var m = System.Text.RegularExpressions.Regex.Match(h, "(\\d{1,2}):(\\d{2})");
            if (m.Success)
            {
                int hh = int.Parse(m.Groups[1].Value);
                int mm = int.Parse(m.Groups[2].Value);
                return new TimeSpan(hh, mm, 0);
            }
            var m2 = System.Text.RegularExpressions.Regex.Match(horario, "(\\d{1,2})h(\\d{2})", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
            if (m2.Success)
            {
                int hh = int.Parse(m2.Groups[1].Value);
                int mm = int.Parse(m2.Groups[2].Value);
                return new TimeSpan(hh, mm, 0);
            }
            return null;
        }

