using System;
using System.Collections.Generic;
using System.Globalization;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;

public async Task<List<FutnatvMatchSearchResult>> GetMatchesFromHtmlAsync(List<FutnatvMatchDto> matches)
        {
            // Group parsed entries by parsed date string to optimize DB queries
            var byDate = matches
                .Where(x => x.DataDate.HasValue)
                .GroupBy(p => p.DataDate.Value);
            
            var results = new List<FutnatvMatchSearchResult>();

            foreach (var group in byDate)
            {
                // Prepare a query that limits Partidas to the day (if parsedDay available) or whole set otherwise
                IQueryable<Partida> query = _context.Partidas
                    .Include(p => p.Mandante)
                    .Include(p => p.Visitante)
                    .Include(p => p.Campeonato)
                    .Include(x => x.Transmissoes)
                        .ThenInclude(t => t.Canal);

                query = query.Where(p => p.Data.Date  == group.Key.Date);

                // materialize once per date-group
                var partidasOnDay = await query.ToListAsync();

                foreach (var dto in group)
                {
                    Partida matched = null;

                    // try to find exact match by both team names (case-insensitive)
                    if (partidasOnDay.Count > 0)
                    {
                        matched = partidasOnDay.FirstOrDefault(p =>
                            string.Equals(p.Mandante?.Nome?.Trim(), dto.Mandante?.Trim(), StringComparison.OrdinalIgnoreCase)
                            && string.Equals(p.Visitante?.Nome?.Trim(), dto.Visitante?.Trim(), StringComparison.OrdinalIgnoreCase)
                        );

                        // if not found try looser matching (one side only or by time)
                        if (matched == null)
                        {
                            matched = partidasOnDay.FirstOrDefault(p =>
                                (string.Equals(p.Mandante?.Nome?.Trim(), dto.Mandante?.Trim(), StringComparison.OrdinalIgnoreCase)
                                    || string.Equals(p.Visitante?.Nome?.Trim(), dto.Visitante?.Trim(), StringComparison.OrdinalIgnoreCase))
                            );
                        }

                        if (matched == null)
                        {
                            // fallback: match by single team name
                            matched = partidasOnDay.FirstOrDefault(p =>
                                string.Equals(p.Mandante?.Nome?.Trim(), dto.Mandante?.Trim(), StringComparison.OrdinalIgnoreCase)
                                || string.Equals(p.Visitante?.Nome?.Trim(), dto.Visitante?.Trim(), StringComparison.OrdinalIgnoreCase)
                            );
                        }
                    }

                    if (matched == null)
                    {
                        continue;
                    }

                    results.Add(new FutnatvMatchSearchResult
                    {
                        Parsed = dto,
                        MatchedPartida = matched
                    });
                }
            }

            return results;
        }

