// Backward-compatible helper: tries to return a DateTime based on parsed fields
        public DateTime GetDate()
        {
            if (DataDate.HasValue) return DataDate.Value;

            // try to parse Data (string like "DOMINGO, 18 DE JANEIRO DE 2026") and Horario ("08h30")
            try
            {
                if (string.IsNullOrWhiteSpace(Data)) return DateTime.UtcNow;

                var parts = Data.Split(',');
                var candidate = parts.Length > 1 ? parts[1].Trim() : parts[0].Trim();
                candidate = System.Text.RegularExpressions.Regex.Replace(candidate, "\\s+DE\\s+", " ", System.Text.RegularExpressions.RegexOptions.IgnoreCase);

                var ci = new System.Globalization.CultureInfo("pt-BR");
                DateTime day;
                var patterns = new[] { "d MMMM yyyy", "d MMM yyyy", "d/MM/yyyy", "yyyy-MM-dd" };
                foreach (var p in patterns)
                {
                    if (DateTime.TryParseExact(candidate, p, ci, System.Globalization.DateTimeStyles.None, out day))
                    {
                        // parse horario
                        var timeSpan = ParseHorario(Horario);
                        if (timeSpan.HasValue)
                            return day.Date.Add(timeSpan.Value);

                        return day.Date;
                    }
                }

                if (DateTime.TryParse(candidate, ci, System.Globalization.DateTimeStyles.AssumeLocal, out day))
                {
                    var timeSpan = ParseHorario(Horario);
                    if (timeSpan.HasValue)
                        return day.Date.Add(timeSpan.Value);

                    return day.Date;
                }

                // fallback
                return DateTime.UtcNow;
            }
            catch
            {
                return DateTime.UtcNow;
            }
        }

