using System.Linq;

public Result<List<ProviderEvent>> HandleHtmlAndGetEvents(string modelId, string html, ProviderMessageType messageProviderType)
    {
        var events = new List<ProviderEvent>();

        switch (messageProviderType)
        {
            case ProviderMessageType.Partidas:
                var agendaData = modelId.Replace($"{this.Nome}_", "");
                var dataJogo = DateTime.ParseExact(agendaData, "dd-MM-yyyy", null);

                var partidasDto = PartidasGeHtmlBuilder.PartidasFromHtml(html, dataJogo);
                if (partidasDto == null)
                    return Result.Failure<List<ProviderEvent>>($"Error ao parser html from {modelId}. parttidasDto null");

                var partidasDtoGrouped = partidasDto.GroupBy(p => new { p.Campeonato, p.Rodada });

                foreach (var partidasCampeonatoRodada in partidasDtoGrouped)
                {
                    if (CampeonatosFilter.Contains(partidasCampeonatoRodada.Key.Campeonato))
                    {
                        continue;
                    }

                    var partidasEvent = new PartidasObtidasProviderEvent(Id)
                    {
                        Campeonato = partidasCampeonatoRodada.Key.Campeonato,
                        Rodada = partidasCampeonatoRodada.Key.Rodada,
                        Partidas = partidasCampeonatoRodada.Select(partidaDto =>
                            new PartidasObtidasProviderEvent.PartidaCampeonatoEvent(
                                partidaDto.Data,
                                partidaDto.TimeMandante,
                                partidaDto.TimeMandantePlacar,
                                partidaDto.TimeMandantePenalti,
                                partidaDto.TimeVisitante,
                                partidaDto.TimeVisitantePlacar,
                                partidaDto.TimeVisitantePenalti,
                                partidaDto.UrlTransmissao,
                                partidaDto.Status,
                                partidasCampeonatoRodada.Key.Rodada,
                                partidaDto.TemHorario,
                                null)
                            ).ToList()
                    };

                    events.Add(partidasEvent);
                }

                break;
            case ProviderMessageType.PartidaDetalhe:
                var partidaId = Guid.Parse(modelId);

                var lances = LanceGeHtmlBuilder.LancesFromHtml(html, partidaId);
                if (lances == null)
                {
                    return Result.Failure<List<ProviderEvent>>("Não foi possível obter lances. Null");
                }

                var placarResult = LancePlacarGeHtmlBuilder.PlacarFromHtml(html);
                var placar = placarResult.Value;

                var momento = string.Empty;
                var lastLance = lances.FirstOrDefault();
                if (lastLance != null)
                {
                    momento = $"{lastLance.Periodo} {lastLance.Minuto}".Trim();
                }

                (var escalacaoMandante, var escalacaoVisitante, var estadio) = FichaGeHtmlBuilder.FichaFromHtml(html);

                var status = PartidaStatus.AoVivo;

                if (lances.Any(l => l.Indicador == LanceIndicador.FimDeJogo))
                {
                    momento = "Fim de Jogo";
                    status = PartidaStatus.Encerrada;
                }

                var partidaEvent = new PartidaAtualizadaProviderEvent(this.Id, partidaId)
                {
                    Estadio = new Domain.Entities.Dtos.EstadioDto
                    {
                        IdExterno = null,
                        Nome = estadio
                    },
                    Momento = momento,
                    DestaqueMandante = placar.DestaqueMandante,
                    DestaqueVisitante = placar.DestaqueVisitante,
                    PlacarMandante = placar.PlacarMandante.GetValueOrDefault(),
                    PenaltiMandante = placar.PenaltiMandante,
                    PlacarVisitante = placar.PlacarVisitante.GetValueOrDefault(),
                    PenaltiVisitante = placar.PenaltiVisitante,
                    Status = status,
                    Tempo = lastLance?.Periodo
                };

                var escalacaoEvent = new EscalacoesAtualizadaProviderEvent(this.Id, partidaId, escalacaoMandante, escalacaoVisitante);

                var lancesEvent = new LancesAtualizadosProviderEvent(this.Id, partidaId, lances);

                events = new List<ProviderEvent> { partidaEvent, lancesEvent, escalacaoEvent };

                break;
            default:
                break;
        }

        return Result.Success(events);
    }

