public override List<ChannelRequest> GetChannelRequests(DateTime referenceDate)
    {
        var dayAfter = referenceDate.AddDays(1);

        var jogosRequest = new ChannelRequest(
            this,
            GetJogosModel(referenceDate),
            ProviderMessageType.Partidas,
            new ChannelData(ProviderType.Crawler, $"{JOGOS_URL}{referenceDate:dd-MM-yyyy}", JOGOS_PATH_TO_CLICK),
            new DateTime(dayAfter.Year, dayAfter.Month, dayAfter.Day, 3, 0, 0),
            TimeSpan.FromSeconds(45));

        var requests = new List<ChannelRequest>
        {
            jogosRequest
        };

        if (DateTime.UtcNow.Date == new DateTime(2022, 11, 15))
        {
            return requests;
        }

        var diasHora = 3;
        for (int i = 1; i <= 5; i++)
        {
            var date = referenceDate.AddDays(i);
            var endDate = date.AddDays(1);
            var url = $"{JOGOS_URL}{date:dd-MM-yyyy}";

            jogosRequest = new ChannelRequest(
                this,
                GetJogosModel(date),
                ProviderMessageType.Partidas,
                new ChannelData(ProviderType.Crawler, url, JOGOS_PATH_TO_CLICK),
                new DateTime(endDate.Year, endDate.Month, endDate.Day, 3, 0, 0),
                TimeSpan.FromHours(i * diasHora));

            requests.Add(jogosRequest);
        }

        return new List<ChannelRequest>();
    }

