private string GetBody(DateTime date)
        {
            var query = @"
                {
                    broadcasts {
                        channel {
                            slug,
                            name,
                            logo,
                            id
                        },
                        epgByDate(date: {0}) {
                            entries {
                                name,
                                metadata,
                                liveBroadcast,
                                startTime,
                                endTime
                            }
                        }
                    }
                }
            ";

            query = query.Replace("{0}", $"\"{date:yyyy-MM-dd}\"");

            var graphql = new
            {
                query,
                variables = new { }
            };

            var body = JsonConvert.SerializeObject(graphql);

            return body;
        }

