using System.Linq;

public override List<CanalOperadora> GetCanaisPartida(Partida partida, List<CanalProgramas> canais)
        {
            var titulos = new List<string>();
            var canalOperadoras = new List<CanalOperadora>();

            foreach (var mandanteNome in partida.Mandante.NomesPossiveis)
            {
                foreach (var visitanteNome in partida.Visitante.NomesPossiveis)
                {
                    if ((mandanteNome + visitanteNome).Contains("-"))
                    {
                        var mandante = mandanteNome.Trim().Replace("-", "/");
                        var visitante = visitanteNome.Trim().Replace("-", "/");

                        var titulo = $"{mandante} x {visitante}".ToLower().RemoveAccents();

                        titulos.Add(titulo);
                        titulos.Add(titulo + " - ao vivo");
                    }

                    var partidaTitulo = $"{mandanteNome.Trim()} x {visitanteNome.Trim()}".ToLower().RemoveAccents();

                    titulos.Add(partidaTitulo);
                    titulos.Add(partidaTitulo + " - ao vivo");
                }
            }

            foreach (var canal in canais)
            {
                foreach (var programa in canal.Programas)
                {
                    foreach (var titulo in titulos)
                    {
                        if (programa.Titulo.ToLower().RemoveAccents().Contains(titulo))
                        {
                            if (canalOperadoras.Any(x => x.Nome == canal.Nome && x.Numero == canal.Numero))
                                continue;

                            canalOperadoras.Add(new CanalOperadora(canal.Nome, canal.Numero, OperadoraEnum.Globoplay)
                            {
                                Imagem = canal.Imagem
                            });

                            continue;
                        }
                    }
                }
            }

            return canalOperadoras;
        }

