public override ChannelRequest GetChannelRequest(DateTime date)
        {
            var untilDate = date.AddDays(1);
            var model = GetModelForDate(date);

            var data = new ChannelData(ProviderType.RestApi, _url)
            {
                CacheTime = TimeSpan.FromMinutes(30),
                CacheKey = model,
                Headers = new Dictionary<string, string>
                {
                    { "x-platform-id", "web" },
                    { "x-client-version", "1.40.0" },
                    { "x-device-id", "desktop" },
                    { "host", "globoplay.globo.com" },
                    { "cache-control", "no-cache" },
                    { "x-tenant-id", "globosat-play" }
                }
            };

            data.SetBody(GetBody(date), "POST");

            var request = new ChannelRequest(
                this,
                model,
                ProviderMessageType.Transmissao,
                data,
                untilDate,
                TimeSpan.FromHours(1));

            return request;
        }

