// File: Domain/RealtimeMatches.Commands/Providers/Sources/RapidApiFootball/RapidApiFootballPartidasProvider.cs
// Namespace: RealtimeMatches.Application.Providers.Sources.RapidApiFootball
// Class: RapidApiFootballPartidasProvider
using CSharpFunctionalExtensions;
using Newtonsoft.Json;
using RealtimeMatches.Application.Providers.Sources.RapidApiFootball.DTOs;
using RealtimeMatches.Application.Providers.Sources.RapidApiFootball.DTOs.Fixtures;
using RealtimeMatches.Domain.Abstractions;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Entities.Dtos;
using RealtimeMatches.Domain.Entities.Providers;
using RealtimeMatches.Domain.Enums;
using RealtimeMatches.Domain.Events;

public Result<List<ProviderEvent>> HandleResponseAndGetEvents(string body, Dictionary<string, string> headers, int statusCode, ChannelMessage channelMessage)
    {
        var events = new List<ProviderEvent>();

        if (statusCode != 200 && statusCode != 304)
            return Result.Failure<List<ProviderEvent>>("StatusCode nao é 200");

        var request = channelMessage.Request;
        if (request.MessageType != ProviderMessageType.Partidas &&
            request.MessageType != ProviderMessageType.PartidaDetalhe &&
            request.MessageType != ProviderMessageType.PartidaDetalheEscalacao &&
            request.MessageType != ProviderMessageType.PartidaDetalheCoverage)
        {
            throw new NotImplementedException();
        }

        if (request.MessageType == ProviderMessageType.Partidas)
        {
            var response = JsonConvert.DeserializeObject<FootballApiResponse<List<FixtureDto>>>(body);
            var fixturesLigas = response.Response.Where(x => Ligas.ContainsKey(x.League.Id)).GroupBy(x => new { x.League.Id, x.League.Round });
            foreach (var fixtLeague in fixturesLigas)
            {
                var league = fixtLeague.First().League;
                var campeonato = Ligas[league.Id];

                var partidasEvent = new PartidasObtidasProviderEvent(Id)
                {
                    Campeonato = campeonato,
                    Temporada = league.Season
                };

                foreach (var partidasCampeonatoRodada in fixtLeague)
                {
                    var rodada = string.Empty;
                    var leagueRound = partidasCampeonatoRodada.League.Round;

                    if (leagueRound.Contains("Group") ||
                        leagueRound.Contains("Regular Season -"))
                    {
                        if (leagueRound.Contains("group stage", StringComparison.OrdinalIgnoreCase))
                        {
                            rodada = leagueRound
                                .Replace("Group Stage -", "Rodada", StringComparison.OrdinalIgnoreCase);
                        }
                        else
                        {
                            rodada = leagueRound
                                .Replace("Group", "Grupo")
                                .Replace("Regular Season -", "Rodada");
                        }
                    }
                    else if (leagueRound.Contains("Taça Rio"))
                    {
                        rodada = leagueRound switch
                        {
                            "Taça Rio - Semi-finals" => "Taça Rio - Semifinal",
                            "Taça Rio - Finals" => "Taça Rio - Final",
                            "Taça Rio - Final" => leagueRound,
                            _ => null
                        };
                    }
                    else if (leagueRound.Contains("Taça Guanabara - "))
                    {
                        rodada = "Rodada " + leagueRound.Replace("Taça Guanabara - ", string.Empty);
                    }
                    else if (leagueRound.Contains("Friendlies") || leagueRound.Contains("Friendly"))
                    {
                        rodada = "Amistoso";
                    }
                    else if (leagueRound.Contains("League"))
                    {
                        var regex = Regex.Match(leagueRound, "League .* - (\\d+)");
                        if (regex.Groups.Count == 2)
                        {
                            rodada = $"Rodada {regex.Groups[1].Value}";
                        }
                    }
                    else if (leagueRound.Contains(" Round - "))
                    {
                        var match = Regex.Match(leagueRound, @".* Round - (\d+)");
                        if (match.Groups.Count == 2)
                        {
                            rodada = "Rodada " + match.Groups[1].Value;
                        }
                    }
                    else if (leagueRound.Contains("Championship - "))
                    {
                        if (int.TryParse(leagueRound.Replace("Championship - ", string.Empty), out var rodadaNumber))
                        {
                            rodada = "Rodada " + rodadaNumber;
                        }
                        else
                        {
                            rodada = leagueRound switch
                            {
                                "Championship - Semi-finals" => "Semifinal",
                                "Championship - Final" => "Final",
                                "Championship - Finals" => "Final",
                                _ => null
                            };
                        }
                    }
                    else if (leagueRound.Contains(" Round") 
                             && !leagueRound.Contains("Knockout")
                             && !leagueRound.Contains("Qualification"))
                    {
                        var match = Regex.Match(leagueRound, @"(\d+).*Round");
                        if (match.Groups.Count == 2)
                        {
                            rodada = "Rodada " + match.Groups[1].Value;
                        }
                    }
                    else if (leagueRound.Contains("Phase"))
                    {
                        if (leagueRound.StartsWith("1st"))
                        {
                            rodada = "Primeira fase - ";
                        }

                        if (leagueRound.StartsWith("2nd"))
                        {
                            rodada = "Segunda fase - ";
                        }

                        var match = Regex.Match(leagueRound, @".*- (\d+)");
                        if (match.Groups.Count == 2)
                        {
                            rodada += "rodada" + match.Groups[1].Value;
                        }
                    }
                    else
                    {
                        rodada = leagueRound.ToLower() switch
                        {
                            "round of 32" => "16 avos de final",
                            "round of 16" => "Oitavas de final",
                            "8th finals" => "Oitavas de final",
                            "round of 8" => "Quartas de final",
                            "quarter-finals" => "Quartas de final",
                            "round of 4" => "Semifinal",
                            "semi-finals" => "Semifinal",
                            "final" or
                            "finals" => "Final",
                            "1st round" => "Primeira fase",
                            "2nd round" => "Segunda fase",
                            "3rd round" => "Terceira fase",
                            "knockout round play-offs" => "Segunda fase",
                            "3rd place final" => "Disputa 3º lugar",
                            "qualification round 1" => "Primeira fase qualificatória",
                            "qualification round 2" => "Segunda fase qualificatória",
                            "qualification round 3" => "Terceira fase qualificatória",
                            _ => null
                        };
                        
                        if (string.IsNullOrEmpty(rodada) && partidasCampeonatoRodada.League.Id == 73) // Copa do Brasil
                        {
                            rodada = leagueRound switch
                            {
                                "1/256-finals" => "Primeira fase",
                                "1/128-finals" => "Segunda fase",
                                "Round of 128" => "Terceira fase",
                                "Round of 64"  => "Quarta fase",
                                _ => null
                            };
                        }
                    }

                    if (string.IsNullOrEmpty(rodada))
                        continue;

                    var partidaDto = partidasCampeonatoRodada.Fixture;

                    var date = partidaDto.Date;
                    if (partidaDto.Timezone == "UTC")
                        date = date.AddHours(-3);

                    var teams = partidasCampeonatoRodada.Teams;
                    var goals = partidasCampeonatoRodada.Goals;
                    var score = partidasCampeonatoRodada.Score;

                    var status = GetPartidaStatus(partidaDto.Status.Short);

                    if (partidaDto.Status.Long == "Match Finished")
                        status = PartidaStatus.Encerrada;

                    var timeMandante = new TimeProviderRaw(teams.Home.Id.ToString(), teams.Home.Name, teams.Home.Logo);
                    var timeVisitante = new TimeProviderRaw(teams.Away.Id.ToString(), teams.Away.Name, teams.Away.Logo);

                    var estadio = new EstadioDto
                    {
                        Nome = partidasCampeonatoRodada.Fixture.Venue?.Name,
                        IdExterno = partidasCampeonatoRodada.Fixture.Venue?.Id?.ToString()
                    };

                    var partida = new PartidasObtidasProviderEvent.PartidaCampeonatoEvent(
                        date.DateTime,
                        timeMandante,
                        goals.Home,
                        score.Penalty.Home,
                        timeVisitante,
                        goals.Away,
                        score.Penalty.Away,
                        $"{_baseUrl}/fixtures/events?fixture={partidaDto.Id}",
                        status,
                        rodada,
                        true,
                        estadio);

                    partidasEvent.Partidas.Add(partida);
                }

                events.Add(partidasEvent);
            }
        }

        if (request.MessageType == ProviderMessageType.PartidaDetalhe)
        {
            var lancesDto = JsonConvert.DeserializeObject<FootballApiResponse<List<EventFixtureDto>>>(body);
            var lances = new List<LanceDto>();
            var partidaId = Guid.Parse(channelMessage.Request.Model);

            var untrackedRequest = new ChannelRequest(
                this,
                request.Model,
                ProviderMessageType.PartidaDetalheCoverage,
                new ChannelData(ProviderType.RestApi, request.Data.Url.Replace("events?fixture", "?id"))
                {
                    Headers = _headers,
                    CacheTime = TimeSpan.FromMinutes(10)
                })
            {
                AggregateObject = new AggregateObject(request.MessageType, body)
            };

            PublishUntrackedRequest(untrackedRequest);

            var cobrancasPenalti = new List<CobrancaPenaltiDto>();

            foreach (var dto in lancesDto.Response)
            {
                var jogador1 = default(JogadorLanceDto);
                var jogador2 = default(JogadorLanceDto);
                var indicador = default(LanceIndicador?);

                var timeIdProvider = dto.Team.Id.ToString();
                var timeNome = dto.Team.Name;
                var minuto = dto.Time.Elapsed.ToString();
                if (dto.Time.Extra.HasValue)
                {
                    minuto += "+" + dto.Time.Extra.Value.ToString();
                }

                jogador1 = new JogadorLanceDto(dto.Player.Id?.ToString(), dto.Player.Name, string.Empty);

                switch (dto.Type.ToLower())
                {
                    case "goal":
                        indicador = LanceIndicador.Gol;

                        if (dto.Detail == "Own Goal")
                        {
                            indicador = LanceIndicador.GolContra;
                        }

                        if (dto.Detail == "Missed Penalty")
                        {
                            indicador = LanceIndicador.PenaltiPerdido;
                        }

                        break;
                    case "card":
                        if (dto.Detail.Contains("Yellow"))
                            indicador = LanceIndicador.CartaoAmarelo;
                        else if (dto.Detail.Contains("Red"))
                            indicador = LanceIndicador.CartaoVermelho;
                        else
                            throw new ArgumentException($"Tipo de Cartão '{dto.Detail}' não identificado.");

                        break;
                    case "subst":
                        indicador = LanceIndicador.Substituicao;

                        jogador2 = jogador1;
                        jogador1 = new JogadorLanceDto(dto.Assist.Id?.ToString(), dto.Assist.Name, string.Empty);

                        break;
                    case "var":
                        if (dto.Detail == "Goal cancelled")
                        {
                            indicador = LanceIndicador.GolAnulado;
                        }
                        else if (dto.Detail == "Penalty confirmed")
                        {
                            indicador = LanceIndicador.VarPenalti;
                        }
                        else
                        {
                            continue;
                        }

                        break;
                    default:
                        break;
                }

                var lanceDto = new LanceDto(minuto, indicador.Value, timeIdProvider)
                {
                    Jogador1 = jogador1,
                    Jogador2 = jogador2,
                };

                if (dto.Comments == "Penalty Shootout")
                {
                    cobrancasPenalti.Add(new CobrancaPenaltiDto
                    {
                        Time = new TimeProviderRaw(timeIdProvider, timeNome),
                        Cobranca = indicador == LanceIndicador.Gol ? PenaltiConversao.Converteu : PenaltiConversao.Errou
                    });

                    lanceDto.Periodo = "Cobrança de Pênaltis";
                }

                lances.Add(lanceDto);
            }

            lances.Reverse();

            var lancesEvent = new LancesAtualizadosProviderEvent(this.Id, partidaId, lances)
            {
                CobrancaPenaltis = cobrancasPenalti
            };

            events.Add(lancesEvent);
        }

        if (request.MessageType == ProviderMessageType.PartidaDetalheEscalacao)
        {
            var partidaId = Guid.Parse(channelMessage.Request.Model);

            var eventsDto = JsonConvert.DeserializeObject<FootballApiResponse<List<EventFixtureDto>>>(request.AggregateObject.Json).Response;
            var lineupDto = JsonConvert.DeserializeObject<FootballApiResponse<List<LineupFixtureDto>>>(body).Response;

            if (lineupDto.Count > 1)
            {
                var lineupHome = lineupDto.First();
                var lineupAway = lineupDto.Last();

                var escalacaoMandante = GetEscalacao(lineupHome, eventsDto);
                var escalacaoVisitante = GetEscalacao(lineupAway, eventsDto);

                var escalacaoEvent = new EscalacoesAtualizadaProviderEvent(this.Id, partidaId, escalacaoMandante, escalacaoVisitante);

                events.Add(escalacaoEvent);
            }
        }

        if (request.MessageType == ProviderMessageType.PartidaDetalheCoverage)
        {
            var partidaId = Guid.Parse(channelMessage.Request.Model);

            var eventsDto = JsonConvert.DeserializeObject<FootballApiResponse<List<EventFixtureDto>>>(request.AggregateObject.Json).Response;
            var fixtureResponse = JsonConvert.DeserializeObject<FootballApiResponse<FootballApiFixtureCompleteDto[]>>(body);

            var fixture = fixtureResponse.Response.FirstOrDefault();
            if (fixture != null)
            {
                var lineupDto = fixture.Lineups;
                var stats = fixture.Statistics;

                if (lineupDto.Count > 1)
                {
                    var lineupHome = lineupDto.First();
                    var lineupAway = lineupDto.Last();

                    var escalacaoMandante = GetEscalacao(lineupHome, eventsDto);
                    var escalacaoVisitante = GetEscalacao(lineupAway, eventsDto);

                    var escalacaoEvent = new EscalacoesAtualizadaProviderEvent(this.Id, partidaId, escalacaoMandante, escalacaoVisitante);

                    events.Add(escalacaoEvent);
                }

                if (stats?.Length > 0)
                {
                    var estatisticas = GetEstatisticasPartida(fixture.Teams, fixture.Statistics);

                    var estatisticasEvent = new EstatisticasPartidaAtualizadaProviderEvent(Id, partidaId, estatisticas);

                    events.Add(estatisticasEvent);
                }
            }
        }

        return events;
    }

