public override ChannelRequest GetChannelRequest(DateTime date)
    {
        var diffDaysToday = (date - DateTime.UtcNow).TotalDays;
        var interval = TimeSpan.FromSeconds(60);
        interval += (diffDaysToday < 0 ? 0 : Math.Ceiling(diffDaysToday)) * TimeSpan.FromHours(1);

        var endDate = date.AddDays(1);
        var untilDate = new DateTime(endDate.Year, endDate.Month, endDate.Day, 3, 0, 0);

        var url = $"{_baseUrl}/fixtures?date={date:yyyy-MM-dd}&timezone=America/Sao_Paulo";

        var request = new ChannelRequest(
            this,
            GetJogosModel(date),
            ProviderMessageType.Partidas,
            new ChannelData(ProviderType.RestApi, url) { Headers = _headers, CacheTime = TimeSpan.FromMinutes(1) },
            untilDate,
            interval);

        return request;
    }

