public override List<ChannelRequest> GetChannelRequests(DateTime referenceDate)
    {
        var jogosRequest = GetChannelRequest(referenceDate);

        var requests = new List<ChannelRequest>
        {
            GetChannelRequest(referenceDate.AddDays(-1)),
            jogosRequest
        };

        for (int i = 1; i <= 5; i++)
        {
            var date = referenceDate.AddDays(i);
            var request = GetChannelRequest(date);

            requests.Add(request);
        }

        return requests;
    }

