public static PartidaStatus GetPartidaStatus(string status)
    {
        return status switch
        {
            "1H" or
            "HT" or
            "2H" or
            "ET" or
            "BT" or
            "P" => PartidaStatus.AoVivo,
            "SUSP" or
            "INT" or
            "PST" or
            "CANC" or
            "TBD" or
