private static EstatisticasPartida GetEstatisticasPartida(Teams teams, StatsFixtureDto[] stats)
    {
        if (teams?.Home == null || teams?.Away == null || stats == null)
        {
            return null;
        }

        var homeStats = stats?.FirstOrDefault(x => x.Team.Id == teams.Home.Id);
        var awayStats = stats?.FirstOrDefault(x => x.Team.Id == teams.Away.Id);

        if (homeStats?.Statistics == null && awayStats.Statistics == null)
        {
            return null;
        }

        var estatisticas = new EstatisticasPartida
        {
            Mandante = GetEstatisticas(homeStats.Statistics),
            Visitante = GetEstatisticas(awayStats.Statistics)
        };

        return estatisticas;
    }

