private static Estatisticas GetEstatisticas(FootballApiStatsTypeDto[] stats)
    {
        if (stats == null)
        {
            return null;
        }

        var estatisticas = new Estatisticas
        {
            Chutes = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.TotalShots)?.ToInt(),
            ChutesGol = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.ShotsOnGoal)?.ToInt(),
            Faltas = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.Fouls)?.ToInt(),
            Escanteios = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.CornerKicks)?.ToInt(),
            Impedimentos = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.Offsides)?.ToInt(),
            PossePorcentagem = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.BallPossession)?.PercentageToInt(),
            CartoesAmarelos = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.YellowCards)?.ToInt(),
            CartoesVermelhos = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.RedCards)?.ToInt(),
            Defesas = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.GoalkeeperSaves)?.ToInt(),
            Passes = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.TotalPasses)?.ToInt(),
            PassesCertos = stats.FirstOrDefault(x => x.Type == FootballApiStatsTypeDto.PassesAccurate)?.ToInt()
        };

        return estatisticas;
    }

