public override List<ChannelRequest> GetChannelRequests(DateTime referenceDate)
        {
            var headers = new Dictionary<string, string>
            {
                { "X-Api-Key", _xApiKey }
            };

            var list = new List<ChannelRequest>();

            for (int i = 0; i <= 5; i++)
            {
                var date = referenceDate.AddDays(i);
                var dateD1 = date.AddDays(1);

                var minDate = new DateTime(date.Year, date.Month, date.Day, 4, 0, 0);
                var maxDate = new DateTime(dateD1.Year, dateD1.Month, dateD1.Day, 3, 59, 59);

                var path = $"dateIni={minDate:yyyyMMddHHmmss}&dateEnd={maxDate:yyyyMMddHHmmss}";

                foreach (var channelNumber in channelsNumberQuery)
                {
                    var url = $"{_apiGuideUrl}&{path}&channelNum={channelNumber}";

                    var data = new ChannelData(ProviderType.RestApi, url)
                    {
                        Headers = headers,
                        CacheTime = TimeSpan.FromMinutes(30)
                    };

                    var interval = TimeSpan.FromHours((i + 1) * 2);

                    var model = $"{this.Nome}_{date:dd-MM-yyyy}_{channelNumber}";
                    var request = new ChannelRequest(this, model, ProviderMessageType.Transmissao, data, maxDate, interval);
                    list.Add(request);
                }
            }

            return list;
        }

