public override List<CanalOperadora> GetCanaisPartida(Partida partida, List<CanalProgramas> canais)
        {
            var titulos = new List<string>();
            var canalOperadoras = new List<CanalOperadora>();

            foreach (var mandanteNome in partida.Mandante.NomesPossiveis.GroupBy(x => x).Select(x => x.Key))
            {
                foreach (var visitanteNome in partida.Visitante.NomesPossiveis.GroupBy(x => x).Select(x => x.Key))
                {
                    var partidaTitulo = $"{mandanteNome.Trim()} x {visitanteNome.Trim()}".ToLower().RemoveAccents();

                    titulos.Add(partidaTitulo);
                    titulos.Add(partidaTitulo + " - ao vivo");
                }
            }

            foreach (var canal in canais)
            {
                var canalPartida = canal.Programas.FirstOrDefault(x => titulos.Contains(x.Titulo.ToLower().RemoveAccents()));
                if (canalPartida != null)
                {
                    canalOperadoras.Add(new CanalOperadora(canal.Nome, canal.Numero, OperadoraEnum.Sky)
                    {
                        Imagem = canal.Imagem
                    });
                }
            }

            return canalOperadoras;
        }

