// Class: FichaGeHtmlBuilder
using HtmlAgilityPack;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;

private static List<JogadorEscalacao> GetJogadoresTime(HtmlNode escalacaoNode)
        {
            var jogadores = new List<JogadorEscalacao>();

            var jogadoresNode = escalacaoNode.SelectNodes(".//li[contains(@class, 'ficha-jogo__time__jogadores__lista__jogador')]");
            if (jogadoresNode == null)
                return new List<JogadorEscalacao>();

            var subTipo = SubstituicaoTipo.Nenhum;
            foreach (var jogadorNode in jogadoresNode)
            {
                var nome = jogadorNode.SelectSingleNode("strong").InnerText;
                var numero = jogadorNode.SelectSingleNode("abbr/i")?.InnerText;
                var posicao = jogadorNode.SelectSingleNode("abbr")?.InnerText;

                if (!string.IsNullOrEmpty(numero))
                    posicao = posicao?.Replace(numero, "");

                var jogador = new JogadorEscalacao
                {
                    Nome = nome,
                    Numero = numero,
                    Posicao = posicao
                };

                var subNode = jogadorNode.SelectSingleNode("div[@class='ficha-jogo__time__jogadores__lista__jogador__scouts-substituicao']");
                if (subNode.HasChildNodes)
                {
                    if (subTipo == SubstituicaoTipo.Sai)
                        subTipo = SubstituicaoTipo.Entra;
                    else if (subTipo == SubstituicaoTipo.Nenhum)
                        subTipo = SubstituicaoTipo.Sai;
                }
                else
                    subTipo = SubstituicaoTipo.Nenhum;

                var scouts = GetScouts(jogadorNode);

                jogador.SubstituicaoTipo = subTipo;
                jogador.Scouts = scouts;

                jogadores.Add(jogador);

                if (subTipo == SubstituicaoTipo.Entra)
                    subTipo = SubstituicaoTipo.Nenhum;
            }

            return jogadores;
        }

