// File: Domain/RealtimeMatches.Commands/Providers/Sources/Globoesporte/Builders/LancesGeHtmlBuilder.cs
// Namespace: RealtimeMatches.Application.Providers.Globoesporte
// Class: LanceGeHtmlBuilder
using Fizzler.Systems.HtmlAgilityPack;
using HtmlAgilityPack;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;
using System.Linq;

public static List<LanceDto> LancesFromHtml(string html, Guid partidaId, string mandante = null, string visitante = null)
        {
            var lances = new List<LanceDto>();
            var htmlDoc = new HtmlDocument();
            htmlDoc.LoadHtml(html);

            var lancesNode = htmlDoc.DocumentNode.SelectNodes("//li[contains(@class, 'lance__list__item')]");
            if (lancesNode == null)
                return null;

            for (int i = 0; i < lancesNode.Count; i++)
            {
                var lanceNode = lancesNode[i];

                //var isTwitter = lanceNode.InnerHtml.Contains("twitter-widget");
                //if (isTwitter)
                //    continue;

                var titulo = lanceNode.SelectSingleNode(".//strong[@class='lance__item__content__detalhe__titulo']")?.InnerText;
                var descricao = lanceNode.SelectSingleNode(".//span[@class='lance__item__content__detalhe__descricao']")?.InnerText;
                var periodo = lanceNode.SelectSingleNode(".//span[@class='lance__item__content__header--periodo']")?.InnerText;
                var minuto = lanceNode.SelectSingleNode(".//h1[@class='lance__item__content__header--minuto']")?.InnerText;

                var indicador = GetLanceIndicador(lanceNode);
                if (indicador == LanceIndicador.Normal || 
                    indicador == LanceIndicador.Desconhecido || 
                    indicador == LanceIndicador.Importante)
                    continue;

                var lanceId = lanceNode.SelectSingleNode(".//div[@class='backstage-component']")?.Attributes["id"]?.Value;

                if (lanceId == null &&
                    string.IsNullOrEmpty(minuto) &&
                    string.IsNullOrEmpty(periodo))
                    continue;

                if (periodo == "Intervalo")
                {
                    periodo = "2º tempo";
                    minuto = "00'";
                }

                if (FimDeJogo(minuto, periodo, titulo, descricao))
                {
                    indicador = LanceIndicador.FimDeJogo;

                    if (lances.Any(x => x.Indicador == LanceIndicador.FimDeJogo))
                        continue;
                }

                var timeIdProvider = string.Empty;

                var jogador1 = default(JogadorLanceDto);
                var jogador2 = default(JogadorLanceDto);

                if (indicador == LanceIndicador.Substituicao)
                {
                    var jogadorSaiNode = lanceNode.SelectSingleNode(".//div[@class='substituicao__jogador']/div");
                    var jogadorSai = GetJogadorLance(jogadorSaiNode);

                    var jogadorEntraNode = lanceNode.SelectSingleNode(".//div[@class='substituicao__jogador-reserva']/div");
                    var jogadorEntra = GetJogadorLance(jogadorEntraNode);

                    timeIdProvider = jogadorSai.Item2;

                    jogador1 = jogadorSai.Item1;
                    jogador2 = jogadorEntra.Item1;
                }
                else
                {
                    var jogadorNode = lanceNode.SelectSingleNode(".//div[@class='jogador']");
                    if (jogadorNode != null)
                    {
                        var jogadorLance = GetJogadorLance(jogadorNode);
                        var jogador = jogadorLance.Item1;
                        timeIdProvider = jogadorLance.Item2;

                        var jogadorNome = jogador.Nome;

                        if (string.IsNullOrEmpty(timeIdProvider))
                        {
                            if (jogadorNome == mandante)
                                timeIdProvider = mandante;

                            if (jogadorNome == visitante)
                                timeIdProvider = visitante;
                        }

                        jogador1 = jogador;
                    }
                }

                var lanceDto = new LanceDto(minuto, indicador, timeIdProvider, periodo)
                {
                    Jogador1 = jogador1,
                    Jogador2 = jogador2
                };

                lances.Add(lanceDto);
            }

            return lances;
        }

