public static bool FimDeJogo(string minuto, string periodo, string titulo, string descricao)
        {
            if (periodo.Contains("1º tempo") ||
                minuto.Contains("00'"))
                return false;

            var keywords = new List<string>
            {
                "fim de jogo",
                "final de jogo",
                "acaba o jogo",
                "apita o árbitro",
                "fim de papo",
                "apitou, terminou!"
            };

            titulo = titulo?.Trim().ToLower();
            descricao = descricao?.Trim().ToLower();
            periodo = periodo?.Trim().ToLower();

            foreach (var key in keywords)
            {
                if (!string.IsNullOrEmpty(titulo) && titulo.Contains(key))
                    return true;

                if (!string.IsNullOrEmpty(descricao) && descricao.Contains(key))
                    return true;

                if (!string.IsNullOrEmpty(periodo) && periodo.Contains(key))
                    return true;
            }

            return false;
        }

