public static LanceIndicador GetLanceIndicador(HtmlNode lanceNode)
        {
            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--default") != null)
                return LanceIndicador.Normal;

            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--gol") != null)
                return LanceIndicador.Gol;

            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--substituicao") != null)
                return LanceIndicador.Substituicao;

            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--cartao-amarelo") != null)
                return LanceIndicador.CartaoAmarelo;

            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--cartao-vermelho") != null)
                return LanceIndicador.CartaoVermelho;

            if (lanceNode.QuerySelector("i.lance__item__content__detalhe__indicador.lance__item__content__detalhe__indicador--importante") != null)
                return LanceIndicador.Importante;

            // lance__item__content__detalhe__indicador lance__item__content__detalhe__indicador--gol-contra

