using HtmlAgilityPack;
using RealtimeMatches.Application.Providers.DTO.Tabela;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;

private static FaseMataMata.FaseChave BuildChaveMataMata(HtmlNode chaveNode)
        {
            var chaveNome = chaveNode.SelectSingleNode("div[@class='separador']/div/span")?.InnerText.Trim();

            var jogosNodes = chaveNode.SelectNodes("div[@class='jogo theme']") 
                ?? chaveNode.SelectNodes("div[@class='jogo confronto']")
                ;

            if (jogosNodes == null)
                return null;

            var inicio = DateTime.MaxValue;
            var fim = DateTime.MinValue;

            var chave = new FaseMataMata.FaseChave(chaveNome);

            foreach (var jogoNode in jogosNodes)
            {
                var urlTransmissao = jogoNode.SelectSingleNode("a")?.Attributes["href"]?.Value;

                var jogoInfo = jogoNode.SelectSingleNode(".//div[@class='jogo__informacoes']");
                var jogoCard = jogoInfo.ParentNode;

                var diaTxt = jogoCard.SelectSingleNode("div/span[1]")?.InnerText.Trim();
                var localTxt = jogoCard.SelectSingleNode("div/span[2]")?.InnerText.Trim();
                var horaTxt = jogoCard.SelectSingleNode("div/span[3]")?.InnerText.Trim();

                var dataStr = string.IsNullOrWhiteSpace(diaTxt) ? string.Empty : diaTxt[4..];

                if (DateTime.TryParseExact($"{dataStr}_{horaTxt}", "dd/MM/yyyy_HH:mm", null, System.Globalization.DateTimeStyles.None, out var date))
                {
                    if (date < inicio)
                        inicio = date;

                    if (date > fim)
                        fim = date;
                }

                var mandante = jogoCard
                    .SelectSingleNode("div[2]/div[1]/span[2]")?.InnerText.Trim();
                var mandanteEscudo = jogoCard
                    .SelectSingleNode("div[2]/div[1]/img")?.Attributes["src"]?.Value.Trim();

                var visitante = jogoCard
                    .SelectSingleNode("div[2]/div[3]/span[2]")?.InnerText.Trim();
                var visitanteEscudo = jogoCard
                    .SelectSingleNode("div[2]/div[3]/img")?.Attributes["src"]?.Value.Trim();

                var placarMandante = jogoCard
                    .SelectSingleNode("div[2]/div[2]/span[1]")?.InnerText.Trim();
                var placarPenaltiMandante = jogoCard
                    .SelectSingleNode("div[2]/div[2]/span[2]")?.InnerText.Trim().Replace("( ", string.Empty);

                var placarVisitante = jogoCard
                    .SelectSingleNode("div[2]/div[2]/span[5]")?.InnerText.Trim();
                var placarPenaltiVisitante = jogoCard
                    .SelectSingleNode("div[2]/div[2]/span[4]")?.InnerText.Trim().Replace(" )", string.Empty);

                var rodada = chaveNome;
                if (jogosNodes.Count == 2)
                {
                    rodada += " - ";
                    rodada += chave.Partidas.Count == 0 ? "ida" : "volta";
                }

                var partida = new PartidaFaseDto
                {
                    Data = date,
                    TimeMandante = new TimeProviderRaw(mandante, mandante, mandanteEscudo),
                    TimeMandantePlacar = ParseIntOrDefault(placarMandante),
                    TimeMandantePenalti = ParseIntOrDefault(placarPenaltiMandante),
                    TimeVisitante = new TimeProviderRaw(visitante, visitante, visitanteEscudo),
                    TimeVisitantePlacar = ParseIntOrDefault(placarVisitante),
                    TimeVisitantePenalti = ParseIntOrDefault(placarPenaltiVisitante),
                    Estadio = localTxt,
                    TemHorario = date != default,
                    UrlTransmissao = urlTransmissao,
                    Rodada = rodada,
                };

                chave.Partidas.Add(partida);
            }

            return chave;
        }

