using RealtimeMatches.Domain.Entities;
using System;

public class ClassificacaoTimeDTO
    {
        public int Posicao { get; set; }
        public TimeProviderRaw Time { get; set; }
        public string TimeLink { get; set; }
        public string TimeId { get; set; }
        public int Jogos { get; set; }
        public int Variacao { get; set; }
        public int Vitorias { get; set; }
        public int Derrotas { get; set; }
        public int Empates { get; set; }
        public int Pontos { get; set; }
        public int GolsPro { get; set; }
        public int GolsContra { get; set; }
        public double Aproveitamento => Math.Round((Pontos / (Jogos * 3.0) * 100), 1);
        public int SaldoGols => GolsPro - GolsContra;

        public override string ToString()
            => $"{Posicao}o - {Time.Nome} / {Jogos}J {Vitorias}V {SaldoGols}SG";
    }

