// File: Domain/RealtimeMatches.Commands/Partidas/Commands/AddTransmissoesPartidaCommand.cs
// Namespace: RealtimeMatches.Application.Partidas.Commands
// Class: AddTransmissoesPartidasCommand.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.CanalOperadoras.Commands;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Application.Providers;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partidasQuery = _applicationContext
                    .Partidas
                    .Include(p => p.Transmissoes)
                        .ThenInclude(c => c.Canal)
                    .Include(p => p.Mandante)
                    .Include(p => p.Visitante)
                    .Include(p => p.Campeonato)
                        .ThenInclude(c => c.Canais)
                            .ThenInclude(c=>c.Canal)
                    .Where(p => p.Data.Date == request.ProgramacaoData.Date);

                var operadoraNome = request.Operadora.ToString();

                if (request.PartidasFilter != null && request.PartidasFilter.Count > 0)
                    partidasQuery = partidasQuery.Where(x => request.PartidasFilter.Contains(x.Id));

                var partidas = await partidasQuery.ToListAsync(cancellationToken);

                var partidasCampeonatos = partidas.GroupBy(p => p.Campeonato.Id);

                var provider = _providersFactory.GetTransmissaoProvider(request.ProviderId);

                foreach (var campeonatoPartidas in partidasCampeonatos)
                {
                    var campeonato = campeonatoPartidas.FirstOrDefault().Campeonato;

                    foreach (var partida in campeonatoPartidas)
                    {
                        if (partida.TransmissoesFixadas)
                        {
                            _logger.LogInformation("Transmissoes fixadas para partida {partida}", partida);

                            continue;
                        }

                        var transmissoesToCache = new List<Transmissao>();

                        foreach (var canal in campeonato.Canais)
                        {
                            var transCanal = partida.Transmissoes.FirstOrDefault(t => t.CanalId == canal.CanalId && t.ProviderId == CampeonatoCanalProvider.Id);
                            if (transCanal == null)
                            {
                                var transmissao = new Transmissao(canal.Canal, partida, new CampeonatoCanalProvider());
                                transmissoesToCache.Add(transmissao);

                                _applicationContext.Transmissoes.Add(new Transmissao(canal.CanalId, partida.Id, CampeonatoCanalProvider.Id));
                            }
                        }

                        var canaisPartida = provider?.GetCanaisPartida(partida, request.Canais);
                        if (canaisPartida?.Count > 0)
                        {
                            var transOperadora = partida.Transmissoes.Where(x => x.Operadora == request.Operadora.ToString()).ToList();
                            foreach (var tOp in transOperadora)
                            {
                                partida.Transmissoes.Remove(tOp);
                                _applicationContext.Transmissoes.Remove(tOp);
                            }

                            foreach (var canalOperadora in canaisPartida)
                            {
                                var canalOperadoraDb = await _mediator.Send(new GetOrAddCanalOperadora.Contract(canalOperadora));

                                var tExists = partida
                                    .Transmissoes
                                    .Any(t => t.CanalId == canalOperadoraDb.CanalId &&
                                              t.Operadora == canalOperadoraDb.OperadoraNome &&
                                              t.CanalOperadoraNome == canalOperadoraDb.Nome &&
                                              t.CanalOperadoraNumero == canalOperadoraDb.Numero);

                                if (canalOperadoraDb.Canal != null && !tExists)
                                {
                                    var transmissao = new Transmissao(canalOperadoraDb.Canal.Id, partida.Id, provider.Id, canalOperadoraDb.OperadoraNome, canalOperadoraDb.Numero, canalOperadoraDb.Nome);
                                    transmissoesToCache.Add(new Transmissao(canalOperadoraDb.Canal, partida, provider, canalOperadoraDb.OperadoraNome, canalOperadoraDb.Numero, canalOperadoraDb.Nome));

                                    _applicationContext.Transmissoes.Add(transmissao);
                                }
                            }
                        }

                        if (transmissoesToCache.Count > 0)
                        {
                            await _applicationContext.SaveChangesAsync(cancellationToken);

                            var transmissoesCache = new List<TransmissaoCache>();

                            transmissoesToCache.AddRange(partida.Transmissoes);
                            var transmissoesCanal = transmissoesToCache.GroupBy(x => x.CanalId);

                            foreach (var tCanal in transmissoesCanal)
                            {
                                var tCache = new TransmissaoCache(tCanal.FirstOrDefault());
                                foreach (var canalOperadora in tCanal)
                                {
                                    if (string.IsNullOrEmpty(canalOperadora.CanalOperadoraNome))
                                        continue;

                                    var exists = tCache
                                        .CanaisOperadoras
                                        .Any(x => x.Nome == canalOperadora.CanalOperadoraNome &&
                                                  x.Numero == canalOperadora.CanalOperadoraNumero &&
                                                  x.Operadora == canalOperadora.Operadora);
                                    if (exists)
                                        continue;

                                    tCache.CanaisOperadoras.Add(new CanalOperadoraCache(canalOperadora.Operadora, canalOperadora.CanalOperadoraNome, canalOperadora.CanalOperadoraNumero));
                                }

                                transmissoesCache.Add(tCache);
                            }

                            await _partidaCacheService.SetTransmicoesPartida(partida.Id, partida.Data, transmissoesCache);
                        }
                    }
                }

                return Result.Success();
            }

