using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.ValueObjects;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class AtualizarEstatisticasPartidaCommand
{
    public record Contract : IRequest<Result>
    {
        public Guid PartidaId { get; set; }
        public EstatisticasPartida Estatisticas { get; set; }

        public Contract(Guid partidaId, EstatisticasPartida estatisticas)
        {
            PartidaId = partidaId;
            Estatisticas = estatisticas;
        }
    }

    public class Handler : IRequestHandler<Contract, Result>
    {
        private readonly IApplicationContext _applicationContext;
        private readonly IPartidaCacheService _partidaCacheService;

        public Handler(
            IApplicationContext applicationContext,
            IPartidaCacheService partidaCacheService)
        {
            _applicationContext = applicationContext;
            _partidaCacheService = partidaCacheService;
        }

        public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
        {
            var partidaData = await _applicationContext
                .Partidas
                .Where(x => x.Id == request.PartidaId)
                .Select(x => new
                {
                    x.Id,
                    x.Data
                })
                .FirstOrDefaultAsync(cancellationToken);
            if (partidaData == null)
            {
                return Result.Failure("Partida não encontrada.");
            }

            await _partidaCacheService.SetEstatisticasPartida(partidaData.Id, partidaData.Data, request.Estatisticas);

            return Result.Success();
        }
    }
}

