// Namespace: RealtimeMatches.Application.Partidas.Commands
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using System;
using System.Threading;
using System.Threading.Tasks;

public class RemoverPartida
{
    public record Contract(Guid Id) : IRequest<Result>;

    public class Handler : IRequestHandler<Contract, Result>
    {
        private readonly IApplicationContext _context;
        private readonly IPartidaCacheService _cacheService;

        public Handler(
            IApplicationContext context,
            IPartidaCacheService cacheService)
        {
            _context = context;
            _cacheService = cacheService;
        }

        public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
        {
            var partida = await _context
                .Partidas
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            partida.DeletedAt = DateTime.UtcNow.AddHours(-3);

            await _context.SaveChangesAsync(cancellationToken);

            await _cacheService.DeletePartida(partida.Id, partida.Data);

            return Result.Success();
        }
    }
}

