public class GetDataPartida
    {
        public class Contract : IRequest<Result<DateTime>>
        {
            public Guid PartidaId { get; set; }

            public Contract(Guid partidaId)
            {
                PartidaId = partidaId;
            }
        }

        public class Handler : IRequestHandler<Contract, Result<DateTime>>
        {
            private readonly IPartidaCacheService _partidaCacheService;
            private readonly IApplicationContext _applicationContext;

            public Handler(
                IPartidaCacheService partidaCacheService,
                IApplicationContext applicationContext)
            {
                _partidaCacheService = partidaCacheService;
                _applicationContext = applicationContext;
            }

            public async Task<Result<DateTime>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partidaDataResult = await _partidaCacheService.GetPartidaDate(request.PartidaId);
                if (partidaDataResult.IsSuccess)
                {
                    Result.Success(partidaDataResult.Value);
                }

                var partidaData = await _applicationContext.Partidas
                    .AsNoTracking()
                    .Where(p => p.Id == request.PartidaId)
                    .Select(p => p.Data)
                    .FirstOrDefaultAsync(cancellationToken);

                if (partidaData == DateTime.MinValue)
                    return Result.Failure<DateTime>("Partida not found");

                await _partidaCacheService.SetPartidaDate(request.PartidaId, partidaData);

                return partidaData;
            }
        }
    }

