using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class GetPartidaPorTimesEData
{
    public class Contract : IRequest<Result<PartidaCache>>
    {
        public Guid MandanteId { get; set; }
        public Guid VisitanteId { get; set; }
        public DateTime Data { get; set; }
    }

    public class Handler : IRequestHandler<Contract, Result<PartidaCache>>
    {
        private readonly IApplicationContext _context;
        private readonly IMediator _mediator;

        public Handler(IApplicationContext context, IMediator mediator)
        {
            _context = context;
            _mediator = mediator;
        }

        public async Task<Result<PartidaCache>> Handle(Contract request, CancellationToken cancellationToken)
        {
            var partidaId = await _context
                .Partidas
                .Include(x => x.Mandante)
                .Include(x => x.Visitante)
                .Where(x => x.Mandante.Id == request.MandanteId && x.Visitante.Id == request.VisitanteId && x.Data.Date == request.Data.Date)
                .Select(x => x.Id)
                .FirstOrDefaultAsync(cancellationToken);
            if (partidaId == Guid.Empty)
            {
                return Result.Failure<PartidaCache>("Partida nao encontrada.");
            }

            var partida = await _mediator.Send(new GetPartidaByIdAndDate.Contract { PartidaId = partidaId, CacheOnly = true });
            return partida;
        }
    }
}

