using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Domain.Entities;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
        {
            if (request.Lances == null)
            {
                return Result.Failure("Lances nao pode ser null ou vazio.");
            }

            var partida = await _applicationContext
                .Partidas
                .AsNoTracking()
                .Include(x => x.Mandante)
                    .ThenInclude(x => x.TimeProviders)
                .Include(x => x.Visitante)
                    .ThenInclude(x => x.TimeProviders)
                .Where(p => p.Id == request.PartidaId)
                .FirstOrDefaultAsync(cancellationToken);

            if (partida == null)
                return Result.Failure("Partida não encontrada.");

            var mandante = partida.Mandante;
            var visitante = partida.Visitante;

            var novosLances = new List<Lance>();
            foreach (var dto in request.Lances)
            {
                var tipo = new TipoLance(dto.Indicador);
                var time = default(Time);

                if (dto.Side.HasValue)
                {
                    time = dto.Side == LanceSide.Mandante ?
                        partida.Mandante :
                        partida.Visitante;
                }
                else if (!string.IsNullOrEmpty(dto.TimeProviderId))
                {
                    var timeProvider =
                        partida.Mandante.TimeProviders.FirstOrDefault(x => x.IdProvider == dto.TimeProviderId) ??
                        partida.Visitante.TimeProviders.FirstOrDefault(x => x.IdProvider == dto.TimeProviderId);

                    time = timeProvider.Time;
                }

                var jogador1 = default(JogadorLance);
                var jogador2 = default(JogadorLance);

                if (dto.Jogador1 != null)
                {
                    var jogador = await AddOrGetJogadorMapped(request.ProviderId, dto.Jogador1);

                    jogador1 = new JogadorLance(jogador);
                }

                if (dto.Jogador2 != null)
                {
                    var jogador = await AddOrGetJogadorMapped(request.ProviderId, dto.Jogador2);

                    jogador2 = new JogadorLance(jogador);
                }

                var lanceResult = Lance.CriarLance(
                    partida.Id,
                    time,
                    dto.Indicador,
                    dto.Minuto,
                    dto.Titulo,
                    dto.Descricao,
                    dto.Periodo,
                    jogador1,
                    jogador2);

                if (lanceResult.IsFailure)
                    return Result.Failure(lanceResult.Error);

                novosLances.Add(lanceResult.Value);
            }

            if (!novosLances.Any(x => x.Indicador == LanceIndicador.InicioDeJogo))
            {
                novosLances.Add(Lance.Inicial(partida.Id));
            }

            var oldLances = await _applicationContext
                .Lances
                .Where(l => l.PartidaId == request.PartidaId)
                .ToListAsync(cancellationToken);

            if (partida.Status != PartidaStatus.NaoComecou &&
                novosLances != null &&
                novosLances.Count > 0 &&
                novosLances.Count >= (oldLances.Count - 2))
            {
                if (partida.Status == PartidaStatus.Encerrada && !novosLances.Any(x => x.Indicador == LanceIndicador.FimDeJogo))
                {
                    novosLances.Insert(0, Lance.FimDeJogo(partida.Id));
                }

                _applicationContext.Lances.RemoveRange(oldLances);
                _applicationContext.Lances.AddRange(novosLances);

                await _applicationContext.SaveChangesAsync(cancellationToken);

                var lancesCache = novosLances.Select(l => new LanceCache(l)).ToList();

                await _partidaCacheService.SetLancesPartida(partida.Id, partida.Data, lancesCache);
            }

            return Result.Success();
        }

