public async Task<Jogador> AddOrGetJogadorMapped(Guid providerId, JogadorLanceDto dto)
        {
            if (string.IsNullOrEmpty(dto.Id))
            {
                return dto.ToJogador();
            }

            var providerName = await _applicationContext.Providers.Where(x => x.Id == providerId).Select(x => x.IntegrationName).FirstOrDefaultAsync();

            var mapping = await _applicationContext.ProviderMappings.FirstOrDefaultAsync(x => x.Type == ProviderMapping.JOGADOR_TYPE && x.ProviderId == providerId && x.ExternalId == dto.Id);
            if (mapping == null)
            {
                mapping = ProviderMapping.CreateMapping<Jogador>(providerName, providerId, dto.Id, dto.Nome, dto.Foto, dto.Posicao, dto.PosicaoAbv);

                _applicationContext.ProviderMappings.Add(mapping);
                await _applicationContext.SaveChangesAsync();

                return dto.ToJogador();
            }

            var jogador = new Jogador
            {
                Apelido = mapping.Info1,
                Foto = mapping.Info2,
                Posicao = new Domain.ValueObjects.Posicao { Nome = mapping.Info3, Abreviado = mapping.Info4 }
            };

            if (mapping.EntityId.HasValue)
            {
                //jogador = await _applicationContext.Jogadores.FirstOrDefaultAsync(x => x.Id == mapping.EntityId.Value);
            }

            return jogador;
        }

