// Namespace: RealtimeMatches.Application.Common.Behaviours
using MediatR;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using System;
using System.Threading;
using System.Threading.Tasks;

public class LockedRequestBehaviour<TRequest, TResponse> : IPipelineBehavior<TRequest, TResponse>
    {
        private readonly ICacheService _cacheService;
        private readonly ILogger<LockedRequestBehaviour<TRequest, TResponse>> _logger;

        public LockedRequestBehaviour(
            ICacheService cacheService,
            ILogger<LockedRequestBehaviour<TRequest, TResponse>> logger)
        {
            _cacheService = cacheService;
            _logger = logger;
        }

        public async Task<TResponse> Handle(TRequest request, CancellationToken cancellationToken, RequestHandlerDelegate<TResponse> next)
        {
            if (request is not ILockedRequest<TResponse>)
                return await next();

            var lockedRequest = request as ILockedRequest<TResponse>;

            var prefixKey = "RealtimeMatches:LockedRequestBehaviour:";
            var lockKey = prefixKey + lockedRequest.LockKey;
            var timeout = lockedRequest.TimeoutSeconds;

            int seconds = 0;
            do
            {
                if (!await _cacheService.KeyExists(lockKey))
                    break;

                _logger.LogDebug($"Request Key {lockKey} waiting {seconds}/{timeout} seconds to proccess.");
                seconds++;
                await Task.Delay(1000);
            } while (seconds < timeout);

            _logger.LogDebug($"Locking Request Key {lockKey}.");
            await _cacheService.SetObjectAsync(lockKey, 1, TimeSpan.FromSeconds(timeout));

            var response = await next();

            await _cacheService.DeleteAsync(lockKey);
            _logger.LogDebug($"Releasing Request Key {lockKey}.");

            return response;
        }
    }

