// File: Domain/RealtimeMatches.Commands/Common/Services/ProviderEventService.cs
// Namespace: RealtimeMatches.Application.Common.Services
// Class: ProviderEventsHandler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Campeonatos.Commands;
using RealtimeMatches.Application.Classificacoes.Command;
using RealtimeMatches.Application.CobrancaPenalti.Commands;
using RealtimeMatches.Application.Escalacoes.Commands;
using RealtimeMatches.Application.Lances.Commands;
using RealtimeMatches.Application.Partidas.Commands;
using RealtimeMatches.Domain.Events;

public async Task<Result> SendCommandEvents(List<ProviderEvent> events, CancellationToken cancellationToken)
        {
            var result = default(Result);
            foreach (var @event in events)
            {
                var providerId = @event.ProviderId;

                try
                {
                    if (@event is TabelaAtualizadaProviderEvent tabelaAtualizada)
                    {
                        var atualizarTabela = new UpdateTabela.Contract
                        {
                            CampeonatoId = tabelaAtualizada.CampeonatoId,
                            ProviderId = providerId,
                            Tabela = tabelaAtualizada.Tabela
                        };

                        result = await _mediator.Send(atualizarTabela, cancellationToken);
                    }

                    if (@event is ProgramacaoOperadoraObtidaEvent transmissoesEvent)
                    {
                        var addTransmissoesCommand = new AddTransmissoesPartidasCommand.Contract
                        {
                            ProviderId = providerId,
                            Operadora = transmissoesEvent.Operadora,
                            Canais = transmissoesEvent.Programacao,
                            ProgramacaoData = transmissoesEvent.ProgramacaoData
                        };

                        result = await _mediator.Send(addTransmissoesCommand, cancellationToken);
                    }

                    if (@event is PartidasObtidasProviderEvent partidasEvent)
                    {
                        var command = new PartidaCollectionCommand.Contract
                        {
                            ProviderId = partidasEvent.ProviderId,
                            Campeonato = partidasEvent.Campeonato,
                            Temporada = partidasEvent.Temporada,
                            Rodada = partidasEvent.Rodada,
                            Partidas = partidasEvent.Partidas.Select(partidaDto => new PartidaCollectionCommand.PartidaContract
                            {
                                DataHorario = partidaDto.Data,
                                TimeMandante = partidaDto.TimeMandante,
                                TimeMandantePlacar = partidaDto.TimeMandantePlacar,
                                TimeMandantePenalti = partidaDto.TimeMandantePenalti,
                                TimeVisitante = partidaDto.TimeVisitante,
                                TimeVisitantePlacar = partidaDto.TimeVisitantePlacar,
                                TimeVisitantePenalti = partidaDto.TimeVisitantePenalti,
                                UrlTransmissao = partidaDto.UrlTransmissao,
                                Status = partidaDto.Status,
                                TemHorario = partidaDto.TemHorario,
                                Rodada = partidaDto.Rodada,
                                Estadio = partidaDto.Estadio
                            }).ToList()
                        };

                        result = await _mediator.Send(command, cancellationToken);
                    }

                    if (@event is PartidaAtualizadaProviderEvent partidaDetalheEvent)
                    {
                        try
                        {
                            var command = new CreateOrUpdatePartidaCommand.Contract(partidaDetalheEvent.PartidaId, partidaDetalheEvent.Status, partidaDetalheEvent.ProviderId)
                            {
                                Momento = partidaDetalheEvent.Momento,
                                Tempo = partidaDetalheEvent.Tempo,
                                PlacarMandante = partidaDetalheEvent.PlacarMandante,
                                PenaltiMandante = partidaDetalheEvent.PenaltiMandante,
                                PlacarVisitante = partidaDetalheEvent.PlacarVisitante,
                                PenaltiVisitante = partidaDetalheEvent.PenaltiVisitante,
                                DestaqueMandante = partidaDetalheEvent.DestaqueMandante,
                                DestaqueVisitante = partidaDetalheEvent.DestaqueVisitante,
                                Estadio = partidaDetalheEvent.Estadio
                            };

                            result = await _mediator.Send(command, cancellationToken);
                        }
                        catch (Exception e)
                        {
                            _logger.LogError(e, "Erro ao executar CreateOrUpdatePartidaCommand. Partida Id: {partidaId}", partidaDetalheEvent.PartidaId);

                            continue;
                        }
                    }

                    if (@event is ClassificacaoObtidaProviderEvent classificacaoEvent)
                    {
                        var updateClassificacaoCommand = new UpdateClassificacaoCampeonato.Contract(providerId, classificacaoEvent.Campeonato);

                        foreach (var c in classificacaoEvent.Classificacao)
                        {
                            var classContract = new UpdateClassificacaoCampeonato.ClassificacaoTimeContract(
                                c.Posicao,
                                c.Time,
                                c.Jogos,
                                c.Vitorias,
                                c.Derrotas,
                                c.Empates,
                                c.Pontos,
                                c.GolsPro,
                                c.GolsContra);

                            updateClassificacaoCommand.Classificacao.Add(classContract);
                        }

                        result = await _mediator.Send(updateClassificacaoCommand, cancellationToken);
                    }

                    if (@event is LancesAtualizadosProviderEvent lancesObtidos)
                    {
                        var lancesCommand = new UpdateLancesCommand.Contract(lancesObtidos.ProviderId, lancesObtidos.PartidaId, lancesObtidos.Lances);

                        result = await _mediator.Send(lancesCommand, cancellationToken);

                        if (lancesObtidos.CobrancaPenaltis?.Count > 0)
                        {
                            var cobrancasCommands = new UpdateCobrancaPenaltiCommand.Contract(lancesObtidos.ProviderId, lancesObtidos.PartidaId, lancesObtidos.CobrancaPenaltis);

                            result = await _mediator.Send(cobrancasCommands, cancellationToken);
                        }
                    }

                    if (@event is EscalacoesAtualizadaProviderEvent escalacoesAtualizada)
                    {
                        var escalacoesCommand = new UpdateEscalacaoCommand.Contract(
                            escalacoesAtualizada.PartidaId,
                            escalacoesAtualizada.Mandante,
                            escalacoesAtualizada.Visitante);

                        result = await _mediator.Send(escalacoesCommand, cancellationToken);
                    }

                    if (@event is EstatisticasPartidaAtualizadaProviderEvent estatisticasPartidaAtualizada)
                    {
                        var estatisticasCommand = new AtualizarEstatisticasPartidaCommand.Contract(estatisticasPartidaAtualizada.PartidaId, estatisticasPartidaAtualizada.Estatisticas);

                        result = await _mediator.Send(estatisticasCommand, cancellationToken);
                    }
                }
                catch (System.Exception e)
                {
                    _logger.LogError(e, $"Erro ao processar evento: {@event} do provider: {providerId}");
                }
            }

            return result;
        }

