using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

public async Task<Estadio> MapEstadio(Guid providerId, EstadioDto dto)
    {
        var idExterno = dto?.IdExterno;
        var nome = dto?.Nome;

        if (string.IsNullOrWhiteSpace(idExterno) && string.IsNullOrWhiteSpace(nome))
        {
            return null;
        }

        if (string.IsNullOrEmpty(idExterno))
        {
            return await _context.Estadios.Where(x => x.Nome == nome).FirstOrDefaultAsync() ?? new Estadio { Nome = nome };
        }

        var providerName = await GetProviderIntegrationName(providerId);
        var mapping = await GetMapping(providerId, idExterno, ProviderMapping.ESTADIO_TYPE);
        if (mapping == null)
        {
            mapping = ProviderMapping.CreateMapping<Estadio>(providerName, providerId, idExterno, nome);

            _context.ProviderMappings.Add(mapping);
            await _context.SaveChangesAsync();

            return new Estadio
            {
                Nome = nome,
            };
        }

        var estadio = new Estadio
        {
            Nome = mapping.Info1,
            Imagem = mapping.Info2,
            Cidade = mapping.Info4
        };

        if (!string.IsNullOrEmpty(mapping.Info3) && int.TryParse(mapping.Info3, out int capacidade))
        {
            estadio.Capacidade = capacidade;
        }

        return estadio;
    }

