        public int Posicao { get; set; }
        public int Jogos { get; set; }
        public int Vitorias { get; set; }
        public int Derrotas { get; set; }
        public int Empates { get; set; }
        public int Pontos { get; set; }
        public int GolsPro { get; set; }
        public int GolsContra { get; set; }
        public int SaldoGols => GolsPro - GolsContra;

        [JsonProperty]
        public double Aproveitamento { get; init; }

        [JsonConstructor]
        private PontuacaoTimeCache() { }

        public PontuacaoTimeCache(ClassificacaoTime classificacaoTime)
        {
            var time = classificacaoTime.Time;

            TimeId = time.Id;
            Time = time.Nome;
            Escudo = time.Escudo;

            Posicao = classificacaoTime.Posicao;
            Jogos = classificacaoTime.Jogos;
            Vitorias = classificacaoTime.Vitorias;
            Derrotas = classificacaoTime.Derrotas;
            Empates = classificacaoTime.Empates;
            Pontos = classificacaoTime.Pontos;
            GolsPro = classificacaoTime.GolsPro;
            GolsContra = classificacaoTime.GolsContra;

            if (Jogos > 0)
            {
                Aproveitamento = Math.Round((Pontos / (Jogos * 3.0) * 100), 1);
            }
            else
            {
                Aproveitamento = .0;
            }
        }
    }

