// Namespace: RealtimeMatches.Application.CobrancaPenalti.Commands
// Class: UpdateCobrancaPenaltiCommand.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Domain.Events;
using System;
using System.Collections.Generic;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                if (request.Cobrancas?.Count == 0)
                {
                    return Result.Failure("Cobrancas nao pode ser null ou vazio.");
                }

                try
                {
                    var partida = await _applicationContext
                    .Partidas
                    .AsNoTracking()
                    .Include(x => x.Mandante)
                        .ThenInclude(x => x.TimeProviders)
                    .Include(x => x.Visitante)
                        .ThenInclude(x => x.TimeProviders)
                    .Where(p => p.Id == request.PartidaId)
                    .FirstOrDefaultAsync(cancellationToken);

                    if (partida == null)
                        return Result.Failure("Partida nao encontrada.");

                    var cobrancaCache = new CobrancaPenaltisCache();

                    foreach (var cobranca in request.Cobrancas)
                    {
                        var cobrancaTimeIdProvider = cobranca.Time.IdProvider;

                        if (partida.Mandante.TimeProviders.Any(x => x.IdProvider == cobrancaTimeIdProvider))
                        {
                            cobrancaCache.Mandante.Add(cobranca.Cobranca);
                        }
                        else if (partida.Visitante.TimeProviders.Any(x => x.IdProvider == cobrancaTimeIdProvider))
                        {
                            cobrancaCache.Visitante.Add(cobranca.Cobranca);
                        }
                        else
                        {
                            _logger.LogError("TimeIdProvider {timeIdProvider} nao encontrado.", cobrancaTimeIdProvider);
                            return Result.Failure("TimeIdProvider nao encontrado.");
                        }
                    }

                    if (cobrancaCache.TemCobranca)
                    {
                        await _partidaCacheService.SetCobrancaPenalti(partida.Id, partida.Data, cobrancaCache);
                    }
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro ao atualizar cobranca da partida {partidaId}", request.PartidaId);
                }

                return Result.Success();
            }

