using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;
using System.Threading;
using System.Threading.Tasks;

public async Task<Result<Cobertura>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partida = await _context
                    .Partidas
                    .Include(p => p.Cobertura)
                    .FirstOrDefaultAsync(p => p.Id == request.PartidaId, cancellationToken);
                if (partida == null)
                    return Result.Failure<Cobertura>("Partida nao existe.");

                if (string.IsNullOrEmpty(request.Link))
                    return Result.Failure<Cobertura>("Link nao pode ser null.");

                if (partida.Cobertura != null)
                    return Result.Success(partida.Cobertura);

                try
                {
                    var cobertura = await _context
                        .Coberturas
                        .Include(c => c.Partida)
                        .FirstOrDefaultAsync(c => c.ProviderId == partida.ProviderId && c.PartidaUniqueKey == partida.UniqueKey);
                    if (cobertura != null)
                    {
                        cobertura.Partida.CoberturaId = null;

                        _logger.LogWarning("Atualizando cobertura ja criada.");

                        cobertura.UpdateLink(request.Link);
                    }
                    else
                    {
                        cobertura = new Cobertura(request.Link, partida.ProviderId, partida.Id, partida.UniqueKey);

                        _context.Coberturas.Add(cobertura);
                    }

                    partida.SetCobertura(cobertura);

                    var rowsAffected = await _context.SaveChangesAsync(cancellationToken);

                    return Result.Success(cobertura);
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Erro ao criar cobertura da partida {partida}", partida);

                    return Result.Failure<Cobertura>("Erro ao criar cobertura da partida: " + e.Message);
                }
            }

