using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Times.Commands;
using RealtimeMatches.Domain.Entities;
using System;
using System.Collections.Generic;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var campId = request.Campeonato.ToGuid();

                var campeonato = await _applicationContext
                    .Campeonatos
                    .Include(c => c.Classificacao)
                        .ThenInclude(c => c.Classificacao)
                    .FirstOrDefaultAsync(c => c.Id == campId);

                if (campeonato == null)
                {
                    var msg = $"Campeonato {request.Campeonato} nao existe e deve ser criado antes.";
                    _logger.LogError(msg);

                    return Result.Failure(msg);
                }                

                var maxJogos = request.Classificacao.Max(c => c.Jogos);
                campeonato.RodadaAtual = "Rodada " + maxJogos;

                var error = false;

                var classificacaoCamp = campeonato.Classificacao ?? new ClassificacaoCampeonato(request.ProviderId, campeonato); ;
                var classificacaoAtualizada = new List<ClassificacaoTime>();

                foreach (var classTimeReq in request.Classificacao)
                {
                    var timeResult = await _mediator.Send(new GetOrAddTimeCommand.Contract(request.ProviderId, classTimeReq.TimeProviderDTO));
                    if (timeResult.IsFailure ||
                        timeResult.Value == null)
                    {
                        _logger.LogError("Nao foi possivel gerar classificacao para o campeonato {campeonato}: {error}", request.Campeonato, timeResult.Error);
                        
                        error = true;
                        continue;
                    }

                    var time = timeResult.Value;

                    var classTime = new ClassificacaoTime(
                        time,
                        classificacaoCamp,
                        classTimeReq.Posicao,
                        classTimeReq.Jogos,
                        classTimeReq.Vitorias,
                        classTimeReq.Derrotas,
                        classTimeReq.Empates,
                        classTimeReq.Pontos,
                        classTimeReq.GolsPro,
                        classTimeReq.GolsContra);

                    classificacaoAtualizada.Add(classTime);
                }

                if (error)
                    return Result.Failure("Não foi possivel atualizar a classificacao do campeonato. Um ou mais erros foram encontrados.");

                if (campeonato.Classificacao != null)
                    campeonato.Classificacao.Classificacao.Clear();
                else
                    campeonato.Classificacao = classificacaoCamp;

                campeonato.Classificacao.Classificacao = classificacaoAtualizada;
                campeonato.ClassificacaoId = campeonato.Classificacao.Id;

                await _applicationContext.SaveChangesAsync();

                await _campeonatoCacheService.SetClassificacao(campeonato.Classificacao);

                return Result.Success();
            }

