using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Agendas.Queries;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Application.Providers.DTO.Tabela;

public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var campeonato = await _context
                    .Campeonatos
                    .AsNoTracking()
                    .FirstOrDefaultAsync(x => x.Id == request.CampeonatoId, cancellationToken: cancellationToken);

                if (campeonato == null)
                    throw new EntityNotFoundException<Campeonato>(request.CampeonatoId);

                if (request.Tabela.Type == TabelaType.Turnos)
                    throw new NotImplementedException("TabelaType.Turnos nao implementada.");

                if (request.Tabela is TabelaFases tabelaFases)
                {
                    var tabelaCache = new TabelaCache();

                    foreach (var fase in tabelaFases.Fases)
                    {
                        var faseCache = await GetFaseCacheAsync(request.ProviderId, campeonato, fase);

                        if (faseCache == null)
                        {
                            _logger.LogError("Stop building tabela {campeonato}. Fase {faseNome} apresentou erros.", campeonato.Nome, fase.Nome);
                            break;
                        }

                        if (faseCache.Chaveamento?.Count > 0)
                            tabelaCache.Fases.Add(faseCache);

                        if (faseCache.Grupos?.Count > 0)
                            tabelaCache.Fases.Add(faseCache);

                        if (faseCache.Classificacao?.Ranking?.Count > 0)
                            tabelaCache.Fases.Add(faseCache);
                    }

                    await _cacheService.SetTabela(campeonato.Id, tabelaCache);

                    return Result.Success();
                }

                throw new NotImplementedException($"{request.Tabela.GetType()} nao implementada.");
            }

