using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Agendas.Queries;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Application.Models.Caching;
using RealtimeMatches.Application.Providers.DTO.Tabela;

public async Task<FaseCache> GetFaseCacheAsync(Guid providerId, Campeonato campeonato, IFase fase)
            {
                var faseCache = new FaseCache(fase);

                switch (fase)
                {
                    case FaseMataMata mataMata:
                        faseCache.Chaveamento = new List<FaseChaveCache>();

                        foreach (var chave in mataMata.Chaveamento)
                        {
                            var faseChaveCache = new FaseChaveCache { Chave = chave.Chave };

                            foreach (var partidaDto in chave.Partidas)
                            {
                                var mandanteRes = await _mediator.Send(new GetOrAddTimeCommand.Contract(providerId, partidaDto.TimeMandante));

                                var visitanteRes = await _mediator.Send(new GetOrAddTimeCommand.Contract(providerId, partidaDto.TimeVisitante));

                                if (mandanteRes.IsFailure || visitanteRes.IsFailure)
                                {
                                    var error = string.Empty;

                                    error += mandanteRes.IsFailure ? mandanteRes.Error : string.Empty;
                                    error += visitanteRes.IsFailure ? visitanteRes.Error : string.Empty;

                                    _logger.LogError($"Erro ao criar Tabela do {campeonato.Nome}. " +
                                        $"{partidaDto.TimeMandante} x {partidaDto.TimeVisitante} " +
                                        $"{partidaDto.Data:yyyy-MM-dd HH:mm}: {error}");

                                    continue;
                                }

                                var mandante = mandanteRes.Value;
                                var visitante = visitanteRes.Value;

                                var partidaUniqueKey = Partida.GetUniqueKey(campeonato, partidaDto.Rodada, mandante, visitante, partidaDto.Data);

                                var partidaAgendada = await _mediator.Send(new GetPartidaAgendada.Contract(partidaUniqueKey));

                                var partidaCache = new BasePartidaCache(
                                    partidaAgendada?.Id,
                                    campeonato,
                                    partidaDto.Rodada,
                                    partidaDto.Data,
                                    mandante,
                                    partidaDto.TimeMandantePlacar,
                                    partidaDto.TimeMandantePenalti,
                                    visitante,
                                    partidaDto.TimeVisitantePlacar,
                                    partidaDto.TimeVisitantePenalti,
                                    partidaDto.Estadio);

                                faseChaveCache.Partidas.Add(partidaCache);
                            }

                            if (faseChaveCache.Partidas?.Count == 0)
                            {
                                continue;
                            }

                            faseCache.Chaveamento.Add(faseChaveCache);
                        }

                        if (faseCache.Chaveamento?.Count == 0)
                            return null;

                        break;

                    case FaseGrupos faseGrupos:
                        var faseGruposCache = new List<FaseGrupoCache>();

                        foreach (var grupo in faseGrupos.Grupos)
                        {
                            var grupoCache = new FaseGrupoCache { Nome = grupo.Nome };

                            var grupoClassificacaoTimes = await GetClassificacaoTimes(providerId, grupo.Classificacao);
                            if (grupoClassificacaoTimes == null)
                            {
                                _logger.LogError("Erro ao construir Grupo {grupo} do campeonato {campeonatoNome}", grupo.Nome, campeonato.Nome);

                                continue;
                            }

                            grupoCache.Classificacao = new ClassificacaoCache(grupoClassificacaoTimes);

                            faseGruposCache.Add(grupoCache);
                        }

                        if (faseGruposCache.Count == 0)
                            return null;

                        faseCache.Grupos = faseGruposCache;

                        break;

                    case FaseClassificatoria classificatoria:
                        var classificatoriaClassificacaoTimes = await GetClassificacaoTimes(providerId, classificatoria.Classificacao);
                        if (classificatoriaClassificacaoTimes == null)
                        {
                            _logger.LogError("Erro ao construir FaseClassificatoria {fase} do campeonato {campeonatoNome}", classificatoria.Nome, campeonato.Nome);

                            return null;
                        }

                        faseCache.Classificacao = new FaseClassificacaoCache(classificatoriaClassificacaoTimes);

                        break;

                    default:
                        return null;
                }

                return faseCache;
            }

