public async Task<List<ClassificacaoTime>> GetClassificacaoTimes(Guid providerId, List<ClassificacaoTimeDTO> dtos)
            {
                var classificacaoTimes = new List<ClassificacaoTime>();

                foreach (var classificacao in dtos)
                {
                    var timeRes = await _mediator.Send(new GetOrAddTimeCommand.Contract(providerId, classificacao.Time));
                    if (timeRes.IsFailure)
                    {
                        _logger.LogError("Erro ao obter time by provider {timeProviderId}", classificacao.Time.IdProvider);
                        return null;
