                    var classificacaoTimeCache = new ClassificacaoTime(timeRes.Value,
                                                                       null,
                                                                       classificacao.Posicao,
                                                                       classificacao.Jogos,
                                                                       classificacao.Vitorias,
                                                                       classificacao.Derrotas,
                                                                       classificacao.Empates,
                                                                       classificacao.Pontos,
                                                                       classificacao.GolsPro,
                                                                       classificacao.GolsContra);
                    classificacaoTimes.Add(classificacaoTimeCache);
                }

                return classificacaoTimes;
