        {
            public CanalOperadora CanalOperadora { get; set; }

            public string LockKey => $"GetOrAddCanalOperadora_{CanalOperadora.OperadoraId}_{CanalOperadora.Nome}_{CanalOperadora.Numero}";

            public int TimeoutSeconds => 15;

            public Contract(CanalOperadora canalOperadora)
