using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.Extensions.Logging;
using NewRelic.Api.Agent;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Services;
using System.Collections.Generic;
using System.Diagnostics;
using System.Threading;
using System.Threading.Tasks;

[Transaction]
            public async Task<Result<List<CampeonatoResponse>>> Handle(Contract request, CancellationToken cancellationToken)
            {
                
                var campeonatos = await _cacheService.GetObjectAsync<List<CampeonatoResponse>>("RealtimeMatches:ListarCampeonatos");
                
                if (campeonatos != null)
                {
                    var response = new List<CampeonatoResponse>();

                    foreach (var campResponse in campeonatos)
                    {
                        var watch = Stopwatch.StartNew();

                        var tabela = await _campeonatoCacheService.GetTabela(campResponse.Id);
                        if (tabela != null)
                            campResponse.Fases = tabela.Fases;

                        if (campResponse.Classificacao == null && campResponse.ClassificacaoId.HasValue)
                        {
                            campResponse.Classificacao = await _campeonatoCacheService.GetClassificacao(campResponse.Id);
                        }

                        response.Add(campResponse);

                        watch.Stop();

                        try
                        {
                            IAgent agent = NewRelic.Api.Agent.NewRelic.GetAgent();
                            ITransaction transaction = agent.CurrentTransaction;

                            transaction
                                .AddCustomAttribute("Campeonato", campResponse.Nome)
                                .AddCustomAttribute("CampeonatoId", campResponse.Id)
                                .AddCustomAttribute("TemTabela", tabela != null)
                                .AddCustomAttribute("TemClassificacao", campResponse.Classificacao != null)
                                .AddCustomAttribute("ElapsedMilliseconds", watch.ElapsedMilliseconds);

                            _logger.LogInformation("CampeonatoResponse: {Campeonato} {CampeonatoId} {TemTabela} {TemClassificacao} {ElapsedMilliseconds}",
                                campResponse.Nome, campResponse.Id, tabela != null, campResponse.Classificacao != null, watch.ElapsedMilliseconds);
                        }
                        catch (System.Exception e)
                        {
                            _logger.LogError(e, "Error recording custom event NewRelic");
                        }
                        
                    }

                    return Result.Success(response);
                }

                return Result.Failure<List<CampeonatoResponse>>("Sem campeonatos");
            }

