using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using RealtimeMatches.Api.Settings;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Models.Caching;
using RealtimeMatches.Application.Common.Services;
using RealtimeMatches.Domain.Entities;

public async Task<Result<List<CampeonatoResponse>>> Handle(Contract request, CancellationToken cancellationToken)
        {
            var campeonatos = await _cacheService.GetObjectAsync<List<CampeonatoResponse>>("RealtimeMatches:ListarCampeonatos");
            if (campeonatos != null)
            {
                return Result.Success(campeonatos);
            }

            var dateBefore = DateTime.UtcNow.AddHours(-3).AddDays(-1);
            var dateAfter = DateTime.UtcNow.AddHours(-3).AddDays(3);

            campeonatos = await _applicationContext
                .Campeonatos
                .Include(c => c.Partidas)
                .Include(x => x.Classificacao)
                .Where(c => c.Ativo &&
                            c.SempreMostrarTabela ||
                            (
                                c.Partidas
                                .Any(p =>
                                    p.Data > dateBefore &&
                                    p.Data < dateAfter
                                )
                            )
                )
                .OrderByDescending(x => x.OrderingKey)
                .ThenBy(x => x.Nome)
                .AsNoTracking()
                .Select(c => new CampeonatoResponse
                {
                    Id = c.Id,
                    Nome = c.Nome,
                    Logo = c.Logo,
                    Ano = c.Ano,
                    Pais = c.Pais,
                    RodadaAtual = c.RodadaAtual,
                    Importancia = c.Importancia,
                    OrderKey = c.OrderingKey,
                    Partidas = c.Partidas.Count(p =>
                                    p.Data > dateBefore &&
                                    p.Data < dateAfter
                                ),
                    ClassificacaoId = c.Classificacao == null ? null : c.Classificacao.Id
                })
                .ToListAsync(cancellationToken);

            foreach (var camp in campeonatos)
            {
                var tabelaEstrangulamento = _estrangulamentoSettings.Tabelas.FirstOrDefault(x => x.CampeonatoId == camp.Id);
                if (tabelaEstrangulamento != null)
                {
                    try
                    {
                        var fasesToAdd = new List<FaseCache>();

                        var http = new HttpClient();
                        var getUrl = $"{_estrangulamentoSettings.TabelaUrl}/{tabelaEstrangulamento.Path}/table";
                        var response = await http.GetAsync(getUrl);
                        if (response.IsSuccessStatusCode)
                        {
                            var responseJson = await response.Content.ReadAsStringAsync(cancellationToken);

                            var tabelaResponse = JsonConvert.DeserializeObject<TabelaCache>(responseJson);
                            
                            foreach (var fase in tabelaResponse.Fases)
                            {
                                if (fase.Grupos == null && 
                                    (fase.Chaveamento == null || fase.Chaveamento.Count == 0) &&
                                    fase.Classificacao == null)
                                {
                                    break;
                                }

                                fasesToAdd.Add(fase);
                            }

                            camp.RodadaAtual = fasesToAdd.LastOrDefault()?.Nome;
                        }

                        camp.Fases = fasesToAdd;
                        camp.Classificacao ??= fasesToAdd.LastOrDefault(x => x.Classificacao != null)?.Classificacao;
                    }
                    catch (Exception e)
                    {
                        _logger.LogError(e, "Error get Tabela from estrangulamento.");
                    }

                    continue;
                }

                if (!camp.ClassificacaoId.HasValue)
                    continue;

                try
                {
                    camp.Classificacao = await _campeonatoCacheService.GetClassificacao(camp.Id);
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Nao foi possivel obter classificacao para o campeonato {campeonatoNome} com id {campeonatoId}", camp.Nome, camp.Id);
                }

                try
                {
                    var tabela = await _campeonatoCacheService.GetTabela(camp.Id);
                    if (tabela != null)
                        camp.Fases = tabela.Fases;
                }
                catch (Exception e)
                {
                    _logger.LogError(e, "Nao foi possivel obter tabela para o campeonato {campeonatoNome} com id {campeonatoId}", camp.Nome, camp.Id);
                }
            }

            await _cacheService.SetObjectAsync("RealtimeMatches:ListarCampeonatos", campeonatos, TimeSpan.FromMinutes(5));

            return await Handle(request, cancellationToken);
        }

