// Class: AgendarPartida.Handler
using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Common.Behaviours;
using RealtimeMatches.Domain.Application.Providers;
using RealtimeMatches.Domain.Entities;
using System;

public async Task<Result<AgendaResponse>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partida = await _applicationContext
                    .Partidas
                    .FirstOrDefaultAsync(p => p.Id == request.PartidaId);

                if (partida == null)
                    return Result.Failure<AgendaResponse>("Partida nao pode ser null.");

                if (partida.UniqueKey == null)
                {
                    return Result.Failure<AgendaResponse>("Partida UniqueKey cannot be null");
                }

                try
                {
                    var agenda = await _applicationContext
                        .Agendas
                        .Include(x => x.Partida)
                        .IgnoreQueryFilters()
                        .FirstOrDefaultAsync(a => a.PartidaUniqueKey == partida.UniqueKey, cancellationToken);

                    var providerIdPreferencial = ProvidersFactory.PartidaProviderPreferencial();

                    if (agenda == null)
                    {
                        agenda = new Agenda(partida.Data, partida.Id, partida.UniqueKey);

                        _applicationContext.Agendas.Add(agenda);
                    }
                    else
                    {
                        if (agenda.PartidaId == partida.Id ||
                            agenda.PartidaUniqueKey == partida.UniqueKey)
                        {
                            if (agenda.Dia != partida.Data)
                            {
                                _applicationContext.Agendas.Remove(agenda);
                                await _applicationContext.SaveChangesAsync(cancellationToken);

                                var motivo = $"Transferida do dia {agenda.Dia:yyyy-MM-dd HH:mm} para {partida.Data:yyyy-MM-dd HH:mm}";
                                await _partidaCacheService.DelPartidaFromDate(partida.Id, agenda.Dia);

                                agenda.TrocarData(partida.Data, motivo);

                                _applicationContext.Agendas.Add(agenda);
                            }

                            await _partidaCacheService.AddPartidaToDate(partida.Id, partida.Data);
                            return Result.Success<AgendaResponse>(new AgendaResponse(true));
                        }
                        else
                        {
                            var partidaAgendadaProvider = await _applicationContext
                                .Partidas
                                .IgnoreQueryFilters()
                                .Where(p => p.Id == agenda.PartidaId)
                                .Select(p => p.ProviderId)
                                .FirstOrDefaultAsync(cancellationToken);

                            var partidaAgendada = agenda.Partida;

                            if (partidaAgendada.Status != PartidaStatus.NaoComecou &&
                                partidaAgendada.PlacarMandante == null &&
                                partida.PlacarMandante.HasValue)
                            {
                                await _partidaCacheService.DelPartidaFromDate(agenda.PartidaId, agenda.Dia);

                                agenda.TrocarPartida(partida.Id, "Partida reagendada por falta de placar.");

                                _logger.LogWarning($"Partida {partida.UniqueKey} reagendada por falta de placar.");
                            }
                            else if (partidaAgendada.Status == PartidaStatus.NaoComecou &&
                                     partidaAgendada.Data < DateTime.UtcNow.AddHours(-3) &&
                                     partidaAgendada.Data != partida.Data &&
                                     !(partida.Data.Hour == 0 && partida.Data.Minute == 0))
                            {
                                await _partidaCacheService.DelPartidaFromDate(agenda.PartidaId, agenda.Dia);

                                agenda.TrocarPartida(partida.Id, $"Partida agendada não iniciada. Provável adiamento. Antigo horario: {partidaAgendada.Data:dd/MM/yyyy HH:mm}");

                                _logger.LogWarning($"Partida {partida} reagendada por falta de placar.");
                            }
                            else if (partidaAgendadaProvider == providerIdPreferencial)
                            {
                                if (partida.Data == agenda.Dia &&
                                    agenda.Dia != partidaAgendada.Data)
                                {
                                    agenda.TrocarPartida(partida.Id, "Partida agendada com data diferente.");

                                    await _partidaCacheService.DelPartidaFromDate(partidaAgendada.Id, partidaAgendada.Data);
                                }
                                else
                                {
                                    _logger.LogDebug("Partida ja agendada pelo provider preferencial. Descartando novo agendamento.");
                                    return Result.Success(new AgendaResponse(false, "Partida ja agendada pelo provider preferencial. Descartando novo agendamento."));
                                }
                            }
                            else if (partida.ProviderId == providerIdPreferencial &&
                                     partida.PlacarMandante == null &&
                                     partidaAgendada.PlacarMandante != null)
                            {
                                _logger.LogInformation("Partida agendada pelo provider com cobertura. Descartando novo agendamento.");

                                return Result.Success(new AgendaResponse(false, "Partida agendada pelo provider com cobertura. Descartando novo agendamento."));
                            }
                            else
                            {
                                await _partidaCacheService.DelPartidaFromDate(agenda.PartidaId, agenda.Dia);

                                agenda.TrocarPartida(partida.Id, "Partida agendada pelo provider preferencial.");

                                _logger.LogWarning($"Partida {partida.UniqueKey} atualizada com outra partida.");
                            }
                        }
                    }

                    if (partida.DeletedAt.HasValue)
                    {
                        await _partidaCacheService.DelPartidaFromDate(partida.Id, partida.Data);

                        agenda.NaoExibir("Partida deletada.");
                    }
                    else
                    {
                        await _partidaCacheService.AddPartidaToDate(partida.Id, partida.Data);
                    }

                    await _applicationContext.SaveChangesAsync(cancellationToken);

                    return Result.Success(new AgendaResponse(true));
                }
                catch (Exception e)
                {
                    var msg = $"Erro ao agendar partida {partida}. " + e.Message;
                    _logger.LogError(e, msg);

                    return Result.Failure<AgendaResponse>(msg);
                }
            }

