using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Coberturas.Queries;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Application.Requests.Queries;
using RealtimeMatches.Domain.Application.Providers;
using RealtimeMatches.Domain.Entities;
using System.Threading;

public async Task<Result<ChannelRequest>> Handle(Contract request, CancellationToken cancellationToken)
            {
                var agenda = await _context
                    .Agendas
                    .Include(a => a.Cobertura)
                    .Include(a => a.Partida)
                        .ThenInclude(x => x.Cobertura)
                    .FirstOrDefaultAsync(x => x.PartidaUniqueKey == request.PartidaUniqueKey);

                if (agenda == null)
                {
                    _logger.LogError("Erro ao aplicar cobertura. Partida UniqueKey {partidaUniqueKey} não agendada como deveria.", request.PartidaUniqueKey);
                    return Result.Failure<ChannelRequest>("Partida não agendada.");
                }

                var coberturaAtiva = default(Cobertura);

                if (agenda.Cobertura == null || agenda.CoberturaStatus == CoberturaStatus.CoberturaNull)
                {
                    var coberturas = await _mediator.Send(new GetCoberturasPartida.Contract(request.PartidaUniqueKey));

                    foreach (var cobertura in coberturas)
                    {
                        if (cobertura.ProviderId == ProvidersFactory.PartidaProviderPreferencial())
                        {
                            agenda.SetCobertura(cobertura.Id, CoberturaStatus.ProviderPreferencial);
                            coberturaAtiva = cobertura;

                            break;
                        }
                        else
                        {
                            agenda.SetCobertura(cobertura.Id, CoberturaStatus.CoberturaNull);
                            coberturaAtiva = cobertura;

                            break;
                        }
                    }
                }
                else
                {
                    coberturaAtiva = agenda.Cobertura;
                }

                if (agenda.CoberturaId == null)
                    return Result.Failure<ChannelRequest>("Partida ainda sem cobertura.");

                await _context.SaveChangesAsync(cancellationToken);

                var coberturaProvider = _providersFactory.GetPartidaProvider(coberturaAtiva.ProviderId);
                var partidaDetalheRequest = coberturaProvider.GetPartidaDetalheRequest(agenda.Partida, agenda.Cobertura);
                if (partidaDetalheRequest != null)
                {
                    partidaDetalheRequest.SetCobertura(coberturaAtiva.Id);

                    var requestResult = await _mediator.Send(new AddOrGetUpdatedRequest.Contract(partidaDetalheRequest), cancellationToken);
                    if (requestResult.IsFailure)
                    {
                        _logger.LogError("Erro ao aplicar cobertura para {partidaUniqueKey}", request.PartidaUniqueKey);
                        return Result.Failure<ChannelRequest>($"Erro ao aplicar cobertura para {request.PartidaUniqueKey}");
                    }

                    return Result.Success(requestResult.Value);
                }

                return Result.Success(default(ChannelRequest)); 
            }

