using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using RealtimeMatches.Domain.Entities;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class FixarCoberturaPartida
    {
        public class Contract : IRequest<Result>
        {
            public string PartidaUniqueKey { get; set; }
            public Guid CoberturaId { get; set; }
        }

        public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IApplicationContext _context;

            public Handler(IApplicationContext context)
            {
                _context = context;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var agenda = await _context
                    .Agendas
                    .Include(x => x.Cobertura)
                    .Where(x => x.PartidaUniqueKey == request.PartidaUniqueKey)
                    .FirstOrDefaultAsync(cancellationToken);

                if (agenda == null)
                    return Result.Failure("Agenda nao encontrada.");

                var cobertura = await _context.Coberturas.FirstOrDefaultAsync(x => x.Id == request.CoberturaId);
                if (cobertura == null)
                    return Result.Failure("Cobertura nao encontrada.");

                agenda.SetCobertura(cobertura.Id, CoberturaStatus.Fixa);

                await _context.SaveChangesAsync(cancellationToken);

                return Result.Success();
            }
        }
    }

