using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using RealtimeMatches.Application.Abstractions;
using RealtimeMatches.Application.Common.Abstractions;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class Handler : IRequestHandler<Contract, Result>
        {
            private readonly IPartidaCacheService _partidaCacheService;
            private readonly IApplicationContext _applicationContext;
            private readonly IMediator _mediator;
            private readonly ILogger<RefazerAgendaDia> _logger;

            public Handler(
                IPartidaCacheService partidaCacheService,
                IApplicationContext applicationContext,
                IMediator mediator,
                ILogger<RefazerAgendaDia> logger)
            {
                _partidaCacheService = partidaCacheService;
                _applicationContext = applicationContext;
                _mediator = mediator;
                _logger = logger;
            }

            public async Task<Result> Handle(Contract request, CancellationToken cancellationToken)
            {
                var date = request.Date.Date;

                var partidasIdResult = await _partidaCacheService.ListPartidasDate(date);
                if (partidasIdResult.IsFailure)
                {
                    _logger.LogError($"Erro ao buscar partidas do dia {date}");
                    return Result.Failure($"Erro ao buscar partidas do dia {date}");
                }

                var partidasDia = await _applicationContext
                    .Partidas
                    .Include(p => p.Campeonato)
                    .Include(p => p.Mandante)
                    .Include(p => p.Visitante)
                    .AsNoTracking()
                    .IgnoreQueryFilters()
                    .Where(x => x.Data.Date == date)
                    .ToListAsync(cancellationToken);

                foreach (var partida in partidasDia)
                {
                    var agendarResult = await _mediator.Send(new AgendarPartida.Contract(partida.Id, partida.UniqueKey));
                    if (agendarResult.IsFailure)
                        _logger.LogError($"Erro ao reagendar partida {partida}. {agendarResult.Error}");
                }

                return Result.Success();
            }
        }

