public class GetPartidaAgendada
    {
        public class Contract : IRequest<Partida>
        {
            public string PartidaUniqueKey { get; set; }

            public Contract(string partidaUniqueKey)
            {
                this.PartidaUniqueKey = partidaUniqueKey;
            }
        }

        public class Handler : IRequestHandler<Contract, Partida>
        {
            private readonly IApplicationContext _context;

            public Handler(IApplicationContext context)
            {
                _context = context;
            }

            public async Task<Partida> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partida = await _context
                    .Agendas
                    .Where(x => x.PartidaUniqueKey == request.PartidaUniqueKey)
