using CSharpFunctionalExtensions;
using MediatR;
using Microsoft.EntityFrameworkCore;
using RealtimeMatches.Application.Common.Abstractions;
using System;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public class IsPartidaAgendada
    {
        public class Contract : IRequest<bool>
        {
            public Guid PartidaId { get; set; }

            public Contract(Guid partidaId)
            {
                PartidaId = partidaId;
            }
        }

        public class Handler : IRequestHandler<Contract, bool>
        {
            private readonly IApplicationContext _context;

            public Handler(IApplicationContext context)
            {
                _context = context;
            }

            public async Task<bool> Handle(Contract request, CancellationToken cancellationToken)
            {
                var partidaUniqueKey = await _context.Partidas.Where(x => x.Id == request.PartidaId).Select(x => x.UniqueKey).FirstOrDefaultAsync(cancellationToken);
                if (partidaUniqueKey != null)
                {
                    var partidaAgendada = await _context.Agendas.Where(x => x.PartidaUniqueKey == partidaUniqueKey).Select(x => x.PartidaId).FirstOrDefaultAsync(cancellationToken); ;
                    return partidaAgendada == request.PartidaId;
                }

                return false;
            }
        }
    }
